-- Poems batch 473
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-56','江行','吳融','唐','御定全唐诗','yuding','','[]','霞低水遠碧翻紅，一棹無邊落照中。',32,'御定全唐詩/json/685.json','["霞低水遠碧翻紅，一棹無邊落照中。", "說示北人應不愛，錦遮泥健馬追風。"]'),
('yuding-57','旅館梅花','吳融','唐','御定全唐诗','yuding','','[]','清香無以敵寒梅，可愛他鄉獨看來。',32,'御定全唐詩/json/685.json','["清香無以敵寒梅，可愛他鄉獨看來。", "為憶故溪千萬樹，幾年辜負雪中開。"]'),
('yuding-58','水鳥','吳融','唐','御定全唐诗','yuding','','[]','煙為行止水為家，兩兩三三睡暖沙。',32,'御定全唐詩/json/685.json','["煙為行止水為家，兩兩三三睡暖沙。", "為謝離鸞兼別鵠，如何禁得向天涯。"]'),
('yuding-59','楊花','吳融','唐','御定全唐诗','yuding','','[]','不鬥穠華不占紅，自飛晴野雪濛濛。',32,'御定全唐詩/json/685.json','["不鬥穠華不占紅，自飛晴野雪濛濛。", "百花長恨風吹落，唯有楊花獨愛風。"]'),
('yuding-60','水調','吳融','唐','御定全唐诗','yuding','','[]','鑿河千里走黃沙，沙殿西來動日華。',32,'御定全唐詩/json/685.json','["鑿河千里走黃沙，沙殿西來動日華。", "可道新聲是亡國，且貪惆悵後庭花。"]'),
('yuding-61','秋夕樓居','吳融','唐','御定全唐诗','yuding','','[]','月裏青山淡如畫，露中黃葉颯然秋。',32,'御定全唐詩/json/685.json','["月裏青山淡如畫，露中黃葉颯然秋。", "危欄倚遍都無寐，只恐星河墮入樓。"]'),
('yuding-62','經苻堅墓','吳融','唐','御定全唐诗','yuding','','[]','百里煙塵散杳冥，新平一隰草青青。',32,'御定全唐詩/json/685.json','["百里煙塵散杳冥，新平一隰草青青。", "八公山石君知否，休更中原作彗星。"]'),
('yuding-63','松江晚泊','吳融','唐','御定全唐诗','yuding','','[]','吳台越嶠兩分津，萬萬檣烏簇夜雲。',32,'御定全唐詩/json/685.json','["吳台越嶠兩分津，萬萬檣烏簇夜雲。", "吟盡長江一江月，更無人似謝將軍。"]'),
('yuding-64','送薛學士赴任峽州二首','吳融','唐','御定全唐诗','yuding','','[]','負譴雖安不敢安，疊猿聲裏獨之官。',64,'御定全唐詩/json/685.json','["負譴雖安不敢安，疊猿聲裏獨之官。", "莫將彩筆閑拋擲，更待淮王詔草看。", "片帆飛入峽雲深，帶雨兼風動楚吟。", "何似玉堂裁詔罷，月斜鳷鵲漏沉沉。"]'),
('yuding-65','送許校書','吳融','唐','御定全唐诗','yuding','','[]','故人言別倍依依，病裏班荊苦憶違。',32,'御定全唐詩/json/685.json','["故人言別倍依依，病裏班荊苦憶違。", "明日柳亭門外路，不知誰賦送將歸。"]'),
('yuding-66','蛺蝶','吳融','唐','御定全唐诗','yuding','','[]','兩兩自依依，南園煙露微。住時須並住，飛處要交飛。',48,'御定全唐詩/json/685.json','["兩兩自依依，南園煙露微。住時須並住，飛處要交飛。", "草淺憂驚吹，花殘惜晚暉。長交擷芳女，夜夢遠人歸。"]'),
('yuding-0','閿鄉寓居十首：阿對泉','吳融','唐','御定全唐诗','yuding','','[]','六載抽毫侍禁闈，可堪多病決然歸。',32,'御定全唐詩/json/686.json','["六載抽毫侍禁闈，可堪多病決然歸。", "五陵年少如相問，阿對泉頭一布衣。"]'),
('yuding-1','閿鄉寓居十首：蛙聲','吳融','唐','御定全唐诗','yuding','','[]','稚圭倫鑒未精通，只把蛙聲鼓吹同。',32,'御定全唐詩/json/686.json','["稚圭倫鑒未精通，只把蛙聲鼓吹同。", "君聽月明人靜夜，肯饒天籟與松風。"]'),
('yuding-2','閿鄉寓居十首：茆堂','吳融','唐','御定全唐诗','yuding','','[]','結得茆簷瞰碧溪，閑雲之外不同棲。',32,'御定全唐詩/json/686.json','["結得茆簷瞰碧溪，閑雲之外不同棲。", "猶嫌未遠函關道，正睡剛聞報曉雞。"]'),
('yuding-3','閿鄉寓居十首：清溪','吳融','唐','御定全唐诗','yuding','','[]','清溪見底露蒼苔，密竹垂藤鎖不開。',32,'御定全唐詩/json/686.json','["清溪見底露蒼苔，密竹垂藤鎖不開。", "應是仙家在深處，愛流花片引人來。"]'),
('yuding-4','閿鄉寓居十首：釣竿','吳融','唐','御定全唐诗','yuding','','[]','曾拋釣渚入秦關，今卻持竿傍碧灘。',32,'御定全唐詩/json/686.json','["曾拋釣渚入秦關，今卻持竿傍碧灘。", "認得舊溪兼舊意，恰如羊祜識金環。"]'),
('yuding-5','閿鄉寓居十首：山僧','吳融','唐','御定全唐诗','yuding','','[]','石臼山頭有一僧，朝無香積夜無燈。',32,'御定全唐詩/json/686.json','["石臼山頭有一僧，朝無香積夜無燈。", "近嫌俗客知蹤跡，擬向中方斷石層。"]'),
('yuding-6','閿鄉寓居十首：小徑','吳融','唐','御定全唐诗','yuding','','[]','礙竹妨花一徑幽，攀援可到玉峰頭。',32,'御定全唐詩/json/686.json','["礙竹妨花一徑幽，攀援可到玉峰頭。", "若教須作康莊好，更有高車駟馬憂。"]'),
('yuding-7','閿鄉寓居十首：聞提壺鳥','吳融','唐','御定全唐诗','yuding','','[]','早於批鵊巧於鶯，故國春林足此聲。',32,'御定全唐詩/json/686.json','["早於批鵊巧於鶯，故國春林足此聲。", "今在天涯別館裏，為君沽酒複何情。"]'),
('yuding-8','閿鄉寓居十首：木塔偶題','吳融','唐','御定全唐诗','yuding','','[]','西南古刹近芳林，偶得高秋試一吟。',32,'御定全唐詩/json/686.json','["西南古刹近芳林，偶得高秋試一吟。", "無限黃花襯黃葉，可須春月始傷心。"]'),
('yuding-9','閿鄉寓居十首：山禽','吳融','唐','御定全唐诗','yuding','','[]','碧嶂為家煙外棲，銜紅啄翠入芳蹊。',32,'御定全唐詩/json/686.json','["碧嶂為家煙外棲，銜紅啄翠入芳蹊。", "可能知我心無定，頻嫋花枝拂面啼。"]'),
('yuding-10','聞歌','吳融','唐','御定全唐诗','yuding','','[]','貫珠一夜奏累累，儘是荀家舊教詞。',32,'御定全唐詩/json/686.json','["貫珠一夜奏累累，儘是荀家舊教詞。", "落盡梁塵腸不斷，九原誰報小憐知。"]'),
('yuding-11','即席','吳融','唐','御定全唐诗','yuding','','[]','竹引絲隨嫋翠樓，滿筵驚動玉關秋。',32,'御定全唐詩/json/686.json','["竹引絲隨嫋翠樓，滿筵驚動玉關秋。", "何人借與丹青筆，畫取當時八字愁。"]'),
('yuding-12','便殿候對','吳融','唐','御定全唐诗','yuding','','[]','宣呼晝入蕊珠宮，玉女窗扉薄霧籠。',32,'御定全唐詩/json/686.json','["宣呼晝入蕊珠宮，玉女窗扉薄霧籠。", "待得華胥春夢覺，半竿斜日下廂風。"]'),
('yuding-13','南遷途中作七首：登七盤嶺二首','吳融','唐','御定全唐诗','yuding','','[]','才非賈傅亦遷官，五月驅羸上七盤。',64,'御定全唐詩/json/686.json','["才非賈傅亦遷官，五月驅羸上七盤。", "從此自知身計定，不能回首望長安。", "七盤嶺上一長號，將謂青天鑒郁陶。", "近日青天都不鑒，七盤應是未高高。"]'),
('yuding-14','南遷途中作七首：渡漢江初嘗鯿魚有作','吳融','唐','御定全唐诗','yuding','','[]','嘯父知機先憶魚，季鷹無事已思鱸。',32,'御定全唐詩/json/686.json','["嘯父知機先憶魚，季鷹無事已思鱸。", "自慚初識查頭味，正是棲棲哭阮塗。"]'),
('yuding-15','南遷途中作七首：溪翁','吳融','唐','御定全唐诗','yuding','','[]','飯稻羹菰曉複昏，碧灘聲裏長諸孫。',32,'御定全唐詩/json/686.json','["飯稻羹菰曉複昏，碧灘聲裏長諸孫。", "應嗟獨上涔陽客，排比椒漿奠楚魂。"]'),
('yuding-16','南遷途中作七首：寄友人','吳融','唐','御定全唐诗','yuding','','[]','驚魂往往坐疑飄，便好為文慰寂寥。',32,'御定全唐詩/json/686.json','["驚魂往往坐疑飄，便好為文慰寂寥。", "若待清湘葬魚了，縱然招得不堪招。"]'),
('yuding-17','南遷途中作七首：途中偶懷','吳融','唐','御定全唐诗','yuding','','[]','無路能酬國士恩，短亭寂寂到黃昏。',32,'御定全唐詩/json/686.json','["無路能酬國士恩，短亭寂寂到黃昏。", "回腸一寸危如線，賴得商山未有猿。"]'),
('yuding-18','南遷途中作七首：訪貫休上人','吳融','唐','御定全唐诗','yuding','','[]','休公為我設蘭湯，方便教人學洗腸。',32,'御定全唐詩/json/686.json','["休公為我設蘭湯，方便教人學洗腸。", "自覺塵纓頓瀟灑，南行不復問滄浪。"]'),
('yuding-19','鴛鴦','吳融','唐','御定全唐诗','yuding','','[]','翠翹紅頸覆金衣，灘上雙雙去又歸。',32,'御定全唐詩/json/686.json','["翠翹紅頸覆金衣，灘上雙雙去又歸。", "長短死生無兩處，可憐黃鵠愛分飛。"]'),
('yuding-20','野步','吳融','唐','御定全唐诗','yuding','','[]','一曲兩曲澗邊草，千枝萬枝村落花。',32,'御定全唐詩/json/686.json','["一曲兩曲澗邊草，千枝萬枝村落花。", "攜筇深去不知處，幾歎山阿隔酒家。"]'),
('yuding-21','酬僧','吳融','唐','御定全唐诗','yuding','','[]','玉堂全不限常朝，臥待重城宿霧銷。',32,'御定全唐詩/json/686.json','["玉堂全不限常朝，臥待重城宿霧銷。", "翻憶故山深雪裏，滿爐枯柏帶煙燒。"]'),
('yuding-22','買帶花櫻桃','吳融','唐','御定全唐诗','yuding','','[]','粉紅輕淺靚妝新，和露和煙別近鄰。',32,'御定全唐詩/json/686.json','["粉紅輕淺靚妝新，和露和煙別近鄰。", "萬一有情應有恨，一年榮落兩家春。"]'),
('yuding-23','海棠二首','吳融','唐','御定全唐诗','yuding','','[]','太尉園林兩樹春，年年奔走探花人。',64,'御定全唐詩/json/686.json','["太尉園林兩樹春，年年奔走探花人。", "今來獨倚荊山看，回首長安落戰塵。", "雲綻霞鋪錦水頭，占春顏色最風流。", "若教更近天街種，馬上多逢醉五侯。"]'),
('yuding-24','送僧上峽歸東蜀','吳融','唐','御定全唐诗','yuding','','[]','巴字江流一棹回，紫袈裟是禁中裁。',32,'御定全唐詩/json/686.json','["巴字江流一棹回，紫袈裟是禁中裁。", "如從十二峰前過，莫賦佳人殊未來。"]'),
('yuding-25','杏花','吳融','唐','御定全唐诗','yuding','','[]','春物競相妒，杏花應最嬌。紅輕欲愁殺，粉薄似啼銷。',36,'御定全唐詩/json/686.json','["春物競相妒，杏花應最嬌。紅輕欲愁殺，粉薄似啼銷。", "願作南華蝶，翩翩繞此條。"]'),
('yuding-26','草','吳融','唐','御定全唐诗','yuding','','[]','染亦不可成，畫亦不可得。萇弘未死時，應無此顏色。',24,'御定全唐詩/json/686.json','["染亦不可成，畫亦不可得。萇弘未死時，應無此顏色。"]'),
('yuding-27','和楊侍郎','吳融','唐','御定全唐诗','yuding','','[]','目極家山遠，身拘禁苑深。煙霄慚暮齒，麋鹿愧初心。',24,'御定全唐詩/json/686.json','["目極家山遠，身拘禁苑深。煙霄慚暮齒，麋鹿愧初心。"]'),
('yuding-28','山居喜友人相訪','吳融','唐','御定全唐诗','yuding','','[]','秋雨空山夜，非君不此來。高於剡溪雪，一棹到門回。',24,'御定全唐詩/json/686.json','["秋雨空山夜，非君不此來。高於剡溪雪，一棹到門回。"]'),
('yuding-29','遠山','吳融','唐','御定全唐诗','yuding','','[]','隱隱隔千里，巍巍知幾重。平時未能去，夢斷一聲鐘。',24,'御定全唐詩/json/686.json','["隱隱隔千里，巍巍知幾重。平時未能去，夢斷一聲鐘。"]'),
('yuding-30','江樹','吳融','唐','御定全唐诗','yuding','','[]','終日沖奔浪，何年墜亂風。謝公堪入詠，目極在雲中。',24,'御定全唐詩/json/686.json','["終日沖奔浪，何年墜亂風。謝公堪入詠，目極在雲中。"]'),
('yuding-31','薔薇','吳融','唐','御定全唐诗','yuding','','[]','萬卉春風度，繁花夏景長。館娃人盡醉，西子始新妝。',24,'御定全唐詩/json/686.json','["萬卉春風度，繁花夏景長。館娃人盡醉，西子始新妝。"]'),
('yuding-32','梅雨','吳融','唐','御定全唐诗','yuding','','[]','渾開又密望中迷，乳燕歸遲粉竹低。撲地暗來飛野馬，',40,'御定全唐詩/json/686.json','["渾開又密望中迷，乳燕歸遲粉竹低。撲地暗來飛野馬，", "少傍海邊飄泊處，中庭自有兩犁泥。"]'),
('yuding-33','登途懷友人','吳融','唐','御定全唐诗','yuding','','[]','日落野原秀，雨餘雲物閑。清時正愁絕，高處正躋攀。',48,'御定全唐詩/json/686.json','["日落野原秀，雨餘雲物閑。清時正愁絕，高處正躋攀。", "京洛遙天外，江河戰鼓間。孤懷欲誰寄，應望塞鴻還。"]'),
('yuding-34','聞蟬','吳融','唐','御定全唐诗','yuding','','[]','夏在先催過，秋賒已被迎。自應人不會，莫道物無情。',48,'御定全唐詩/json/686.json','["夏在先催過，秋賒已被迎。自應人不會，莫道物無情。", "木葉縱未落，鬢絲還易生。西風正相亂，休上夕陽城。"]'),
('yuding-35','秋色','吳融','唐','御定全唐诗','yuding','','[]','染不成幹畫未銷，霏霏拂拂又迢迢。',32,'御定全唐詩/json/686.json','["染不成幹畫未銷，霏霏拂拂又迢迢。", "曾從建業城邊路，蔓草寒煙鎖六朝。"]'),
('yuding-36','自諷','吳融','唐','御定全唐诗','yuding','','[]','本是滄洲把釣人，無端三署接清塵。',32,'御定全唐詩/json/686.json','["本是滄洲把釣人，無端三署接清塵。", "從來不解長流涕，也渡湘漓作逐臣。"]'),
('yuding-37','宿青雲驛','吳融','唐','御定全唐诗','yuding','','[]','蒼黃負譴走商顏，保得微躬出武關。',32,'御定全唐詩/json/686.json','["蒼黃負譴走商顏，保得微躬出武關。", "今夜青雲驛前月，伴吟應到落西山。"]'),
('yuding-38','秋聞子規','吳融','唐','御定全唐诗','yuding','','[]','年年春恨化冤魂，血染枝紅壓疊繁。',32,'御定全唐詩/json/686.json','["年年春恨化冤魂，血染枝紅壓疊繁。", "正是西風花落盡，不知何處認啼痕。"]'),
('yuding-39','荊南席上聞歌','吳融','唐','御定全唐诗','yuding','','[]','迎愁斂黛一聲分，吊屈江邊日暮聞。',32,'御定全唐詩/json/686.json','["迎愁斂黛一聲分，吊屈江邊日暮聞。", "何事遏雲翻不定，自緣蹤跡愛行雲。"]'),
('yuding-40','武關','吳融','唐','御定全唐诗','yuding','','[]','時來時去若迴圈，雙闔平雲謾鎖山。只地道教秦設險，',40,'御定全唐詩/json/686.json','["時來時去若迴圈，雙闔平雲謾鎖山。只地道教秦設險，", "爭得便如岩下水，從他興廢自潺潺。"]'),
('yuding-41','月夕追事','吳融','唐','御定全唐诗','yuding','','[]','曾聽豪家碧玉歌，雲床冰簟落秋河。月臨高閣簾無影，',40,'御定全唐詩/json/686.json','["曾聽豪家碧玉歌，雲床冰簟落秋河。月臨高閣簾無影，", "此時空見清涼影，來伴蛩聲咽砌莎。"]'),
('yuding-42','上陽宮辭','吳融','唐','御定全唐诗','yuding','','[]','苑路青青半是苔，翠華西去未知回。景陽春漏無人報，',40,'御定全唐詩/json/686.json','["苑路青青半是苔，翠華西去未知回。景陽春漏無人報，", "誰能賦得長門事，不惜千金奉酒杯。"]'),
('yuding-43','送于員外歸隱藍田','吳融','唐','御定全唐诗','yuding','','[]','曾吟工部兩峰寒，今日星郎得掛冠。吾道不行歸始是，',40,'御定全唐詩/json/686.json','["曾吟工部兩峰寒，今日星郎得掛冠。吾道不行歸始是，", "若遇秦時雪髯客，紫芝兼可備朝餐。"]'),
('yuding-44','廢宅','吳融','唐','御定全唐诗','yuding','','[]','風飄碧瓦雨摧垣，卻有鄰人與鎖門。幾樹好花閑白晝，',40,'御定全唐詩/json/686.json','["風飄碧瓦雨摧垣，卻有鄰人與鎖門。幾樹好花閑白晝，", "不獨淒涼眼前事，咸陽一火便成原。"]'),
('yuding-45','湖州晚望','吳融','唐','御定全唐诗','yuding','','[]','鼓角迎秋晚韻長，斷虹疏雨間微陽。兩條溪水分頭碧，',40,'御定全唐詩/json/686.json','["鼓角迎秋晚韻長，斷虹疏雨間微陽。兩條溪水分頭碧，", "他年若得壺中術，一簇汀洲盡貯將。"]'),
('yuding-46','宋玉宅','吳融','唐','御定全唐诗','yuding','','[]','草白煙寒半野陂，臨江舊宅指遺基。已懷湘浦招魂事，',40,'御定全唐詩/json/686.json','["草白煙寒半野陂，臨江舊宅指遺基。已懷湘浦招魂事，", "今朝送別還經此，吟斷當年幾許悲。"]'),
('yuding-47','春晚書懷','吳融','唐','御定全唐诗','yuding','','[]','落盡紅芳春意闌，綠蕪空鎖辟疆園。嫦娥斷影霜輪冷，',40,'御定全唐詩/json/686.json','["落盡紅芳春意闌，綠蕪空鎖辟疆園。嫦娥斷影霜輪冷，", "晚來雖共殘鶯約，爭奈風淒又雨昏。"]'),
('yuding-48','寄楊侍郎','吳融','唐','御定全唐诗','yuding','','[]','雲情鶴態莫誇慵，正上仙樓十二重。吟逸易沈鳷鵲月，',40,'御定全唐詩/json/686.json','["雲情鶴態莫誇慵，正上仙樓十二重。吟逸易沈鳷鵲月，", "何事春來待歸隱，探知溪畔有風松。"]'),
('yuding-49','杏花','吳融','唐','御定全唐诗','yuding','','[]','粉薄紅輕掩斂羞，花中占斷得風流。軟非因醉都無力，',40,'御定全唐詩/json/686.json','["粉薄紅輕掩斂羞，花中占斷得風流。軟非因醉都無力，", "裴回盡日難成別，更待黃昏對酒樓。"]'),
('yuding-50','憲丞裴公上洛退居有寄二首','吳融','唐','御定全唐诗','yuding','','[]','鴻在冥冥已自由，紫芝峰下更高秋。拋來簪紱都如夢，',80,'御定全唐詩/json/686.json','["鴻在冥冥已自由，紫芝峰下更高秋。拋來簪紱都如夢，", "自嗟不得從公去，共上仙家十二樓。", "瘦如仙鶴爽風篁，外卻塵囂興緒長。偶坐幾回沈皓月，", "目斷瓊林攀不得，一重丹水抵三湘。"]'),
('yuding-51','叢祠','吳融','唐','御定全唐诗','yuding','','[]','叢祠一炬照秦川，雨散雲飛二十年。長路未歸萍逐水，',40,'御定全唐詩/json/686.json','["叢祠一炬照秦川，雨散雲飛二十年。長路未歸萍逐水，", "何必向來曾識面，拂塵看字也淒然。"]'),
('yuding-52','分水嶺','吳融','唐','御定全唐诗','yuding','','[]','兩派潺湲不暫停，嶺頭長瀉別離情。南隨去馬通巴棧，',40,'御定全唐詩/json/686.json','["兩派潺湲不暫停，嶺頭長瀉別離情。南隨去馬通巴棧，", "紫溪舊隱還如此，清夜梁山月更明。"]'),
('yuding-53','赴職西川過便橋書懷寄同年','吳融','唐','御定全唐诗','yuding','','[]','平門橋下水東馳，萬里從軍一望時。鄉思旋生芳草見，',40,'御定全唐詩/json/686.json','["平門橋下水東馳，萬里從軍一望時。鄉思旋生芳草見，", "不是傷春愛回首，杏壇恩重馬遲遲。"]'),
('yuding-54','太保中書令軍前新樓','吳融','唐','御定全唐诗','yuding','','[]','十二闌幹壓錦城，半空人語落灘聲。風流近接平津閣，',40,'御定全唐詩/json/686.json','["十二闌幹壓錦城，半空人語落灘聲。風流近接平津閣，", "不知捧詔朝天后，誰此登臨看月明。"]'),
('yuding-55','玉女廟','吳融','唐','御定全唐诗','yuding','','[]','九清何日降仙霓，掩映荒祠路欲迷。愁黛不開山淺淺，',40,'御定全唐詩/json/686.json','["九清何日降仙霓，掩映荒祠路欲迷。愁黛不開山淺淺，", "若得洗頭盆置此，靚妝無複碧蓮西。"]'),
('yuding-56','坤維軍前寄江南弟兄','吳融','唐','御定全唐诗','yuding','','[]','二年征戰劍山秋，家在松江白浪頭。關月幾時幹客淚，',40,'御定全唐詩/json/686.json','["二年征戰劍山秋，家在松江白浪頭。關月幾時幹客淚，", "獨羨一聲南去雁，滿天風雨到汀州。"]'),
('yuding-57','滻水席上獻座主侍郎','吳融','唐','御定全唐诗','yuding','','[]','暖泉宮裏告虔回，略避紅塵小宴開。落絮已隨流水去，',40,'御定全唐詩/json/686.json','["暖泉宮裏告虔回，略避紅塵小宴開。落絮已隨流水去，", "莫訝諸生中獨醉，感恩傷別正難裁。"]'),
('yuding-58','送知古上人','吳融','唐','御定全唐诗','yuding','','[]','昔年離別浙河東，多難相逢舊楚宮。振錫才尋三徑草，',40,'御定全唐詩/json/686.json','["昔年離別浙河東，多難相逢舊楚宮。振錫才尋三徑草，", "不似投荒憔悴客，滄浪無際問漁翁。"]'),
('yuding-59','和座主尚書登布善寺樓','吳融','唐','御定全唐诗','yuding','','[]','往事何時不系腸，更堪凝睇白雲鄉。楚王城壘空秋色，',40,'御定全唐詩/json/686.json','["往事何時不系腸，更堪凝睇白雲鄉。楚王城壘空秋色，", "誰知此日憑軒處，一筆工夫勝七襄。"]'),
('yuding-60','金橋感事','吳融','唐','御定全唐诗','yuding','','[]','太行和雪疊晴空，二月春郊尚朔風。飲馬早聞臨渭北，',40,'御定全唐詩/json/686.json','["太行和雪疊晴空，二月春郊尚朔風。飲馬早聞臨渭北，", "日暮長亭正愁絕，哀笳一曲戍煙中。"]'),
('yuding-61','蕭縣道中','吳融','唐','御定全唐诗','yuding','','[]','戍火三籠滯晚程，枯桑系馬上寒城。滿川落照無人過，',40,'御定全唐詩/json/686.json','["戍火三籠滯晚程，枯桑系馬上寒城。滿川落照無人過，", "草堂舊隱終歸去，寄語岩猿莫曉驚。"]'),
('yuding-62','題袞州泗河中石床','吳融','唐','御定全唐诗','yuding','','[]','一片苔床水漱痕，何人清賞動乾坤。謫仙醉後雲為態，',40,'御定全唐詩/json/686.json','["一片苔床水漱痕，何人清賞動乾坤。謫仙醉後雲為態，", "邇來多少登臨客，千載誰將勝事論。"]'),
('yuding-63','禁直偶書','吳融','唐','御定全唐诗','yuding','','[]','玉皇新複五城居，仙館詞臣在碧虛。錦砌漸看翻芍藥，',40,'御定全唐詩/json/686.json','["玉皇新複五城居，仙館詞臣在碧虛。錦砌漸看翻芍藥，", "爭奈滄洲頻入夢，白波無際落紅蕖。"]'),
('yuding-64','送弟東歸','吳融','唐','御定全唐诗','yuding','','[]','偶持麟筆侍金閨，夢想三年在故溪。祖竹定欺簷雪折，',40,'御定全唐詩/json/686.json','["偶持麟筆侍金閨，夢想三年在故溪。祖竹定欺簷雪折，", "此別更無閒事囑，北山高處謝猿啼。"]'),
('yuding-65','和座主尚書春日郊居','吳融','唐','御定全唐诗','yuding','','[]','海燕初歸朔雁回，靜眠深掩百花台。春蔬已為高僧掇，',40,'御定全唐詩/json/686.json','["海燕初歸朔雁回，靜眠深掩百花台。春蔬已為高僧掇，", "謝公難避蒼生意，自古風流必上臺。"]'),
('yuding-66','僧舍白牡丹二首','吳融','唐','御定全唐诗','yuding','','[]','膩若裁雲薄綴霜，春殘獨自殿群芳。梅妝向日霏霏暖，',80,'御定全唐詩/json/686.json','["膩若裁雲薄綴霜，春殘獨自殿群芳。梅妝向日霏霏暖，", "天生潔白宜清淨，何必殷紅映洞房。", "侯家萬朵簇霞丹，若並霜林素豔難。合影只應天際月，", "想得惠林憑此檻，肯將榮落意來看。"]'),
('yuding-67','八月十五夜禁直寄同僚','吳融','唐','御定全唐诗','yuding','','[]','中秋月滿盡相尋，獨入非煙宿禁林。曾恨人間千里隔，',40,'御定全唐詩/json/686.json','["中秋月滿盡相尋，獨入非煙宿禁林。曾恨人間千里隔，", "目斷枚皋何處在，闌幹十二憶登臨。"]'),
('yuding-68','上巳日花下閑看','吳融','唐','御定全唐诗','yuding','','[]','十裏香塵撲馬飛，碧蓮峰下踏青時。雲鬟照水和花重，',40,'御定全唐詩/json/686.json','["十裏香塵撲馬飛，碧蓮峰下踏青時。雲鬟照水和花重，", "如煙如夢爭尋得，溪柳回頭萬萬絲。"]'),
('yuding-69','禪院弈棋偶題','吳融','唐','御定全唐诗','yuding','','[]','裛塵絲雨送微涼，偶出樊籠入道場。半偈已能消萬事，',40,'御定全唐詩/json/686.json','["裛塵絲雨送微涼，偶出樊籠入道場。半偈已能消萬事，", "更約西風搖落後，醉來終日臥禪房。"]'),
('yuding-70','和張舍人','吳融','唐','御定全唐诗','yuding','','[]','玉女盆邊雪未銷，正多春事莫無憀。杏花向日紅勻臉，',40,'御定全唐詩/json/686.json','["玉女盆邊雪未銷，正多春事莫無憀。杏花向日紅勻臉，", "陵遷穀變如須問，控鶴山人字子喬。"]'),
('yuding-71','送友赴闕','吳融','唐','御定全唐诗','yuding','','[]','故人歸去指翔鸞，樂帶離聲可有歡。驛路兩行秋吹急，',40,'御定全唐詩/json/686.json','["故人歸去指翔鸞，樂帶離聲可有歡。驛路兩行秋吹急，", "遙羨從公無一事，探花先醉曲江幹。"]'),
('yuding-72','過鄧城縣作','吳融','唐','御定全唐诗','yuding','','[]','不用登臨足感傷，古來今往盡茫茫。未知堯桀誰臧否，',40,'御定全唐詩/json/686.json','["不用登臨足感傷，古來今往盡茫茫。未知堯桀誰臧否，", "到頭一切皆身外，只覺關身是醉鄉。"]'),
('yuding-73','文德初聞車駕東游','吳融','唐','御定全唐诗','yuding','','[]','龍旆叢叢下劍門，還將瑞氣入中原。鼇頭一蕩山雖沒，',40,'御定全唐詩/json/686.json','["龍旆叢叢下劍門，還將瑞氣入中原。鼇頭一蕩山雖沒，", "自憐閑坐漁磯石，萬級雲台落夢魂。"]'),
('yuding-74','子規','吳融','唐','御定全唐诗','yuding','','[]','舉國繁華委逝川，羽毛飄蕩一年年。他山叫處花成血，',40,'御定全唐詩/json/686.json','["舉國繁華委逝川，羽毛飄蕩一年年。他山叫處花成血，", "湘江日暮聲淒切，愁殺行人歸去船。"]'),
('yuding-75','簡州歸降賀京兆公','吳融','唐','御定全唐诗','yuding','','[]','分棟山前曙色開，三千鐵騎簡州回。雲間墮箭飛書去，',40,'御定全唐詩/json/686.json','["分棟山前曙色開，三千鐵騎簡州回。雲間墮箭飛書去，", "功名一似淮西事，只是元臣不姓裴。"]'),
('yuding-76','登漢州城樓','吳融','唐','御定全唐诗','yuding','','[]','雨餘秋色拂孤城，遠目凝時萬象清。疊翠北來千嶂盡，',40,'御定全唐詩/json/686.json','["雨餘秋色拂孤城，遠目凝時萬象清。疊翠北來千嶂盡，", "欲下闌幹一回首，烏歸帆沒戍煙明。"]'),
('yuding-77','岐下寓居見槐花落因寄從事','吳融','唐','御定全唐诗','yuding','','[]','才開便落不勝黃，覆著庭莎襯夕陽。只共蟬催雙鬢老，',40,'御定全唐詩/json/686.json','["才開便落不勝黃，覆著庭莎襯夕陽。只共蟬催雙鬢老，", "蜀國馬卿看從獵，肯將閒事入淒涼。"]'),
('yuding-78','和人有感','吳融','唐','御定全唐诗','yuding','','[]','莫愁家住石城西，月墜星沈客到迷。一院無人春寂寂，',40,'御定全唐詩/json/686.json','["莫愁家住石城西，月墜星沈客到迷。一院無人春寂寂，", "蘭棹一移風雨急，流鶯千萬莫長啼。"]'),
('yuding-0','春歸次金陵','吳融','唐','御定全唐诗','yuding','','[]','春陰漠漠覆江城，南國歸橈趁晚程。水上驛流初過雨，',40,'御定全唐詩/json/687.json','["春陰漠漠覆江城，南國歸橈趁晚程。水上驛流初過雨，", "便被東風動離思，楊花千里雪中行。"]'),
('yuding-1','途中見杏花','吳融','唐','御定全唐诗','yuding','','[]','一枝紅豔出牆頭，牆外行人正獨愁。長得看來猶有恨，',40,'御定全唐詩/json/687.json','["一枝紅豔出牆頭，牆外行人正獨愁。長得看來猶有恨，", "更憶帝鄉千萬樹，澹煙籠日暗神州。"]'),
('yuding-2','秋日經別墅','吳融','唐','御定全唐诗','yuding','','[]','別墅蕭條海上村，偶期蘭菊與琴尊。簷橫碧嶂秋光近，',40,'御定全唐詩/json/687.json','["別墅蕭條海上村，偶期蘭菊與琴尊。簷橫碧嶂秋光近，", "北山移去前文在，無複教人歎曉猿。"]'),
('yuding-3','紅葉','吳融','唐','御定全唐诗','yuding','','[]','露染霜幹片片輕，斜陽照處轉烘明。和煙飄落九秋色，',40,'御定全唐詩/json/687.json','["露染霜幹片片輕，斜陽照處轉烘明。和煙飄落九秋色，", "一時衰颯無多恨，看著清風彩剪成。"]'),
('yuding-4','離霅溪感事獻鄭員外','吳融','唐','御定全唐诗','yuding','','[]','足恨饒悲不自由，萍無根蒂水長流。庾公明月吟連曙，',40,'御定全唐詩/json/687.json','["足恨饒悲不自由，萍無根蒂水長流。庾公明月吟連曙，", "雲沈鳥去回頭否，平子才多好賦愁。"]'),
('yuding-5','岐州安西門','吳融','唐','御定全唐诗','yuding','','[]','安西門外徹安西，一百年前斷鼓鼙。犬解人歌曾入唱，',40,'御定全唐詩/json/687.json','["安西門外徹安西，一百年前斷鼓鼙。犬解人歌曾入唱，", "今日登臨須下淚，行人無個草萋萋。"]'),
('yuding-6','關西驛亭即事','吳融','唐','御定全唐诗','yuding','','[]','晚霞零落雨初收，關上危闌獨悵留。千里好春聊極目，',40,'御定全唐詩/json/687.json','["晚霞零落雨初收，關上危闌獨悵留。千里好春聊極目，", "直是無情也腸斷，鳥歸帆沒水空流。"]'),
('yuding-7','望嵩山','吳融','唐','御定全唐诗','yuding','','[]','三十六峰危似冠，晴樓百尺獨登看。高淩鳥外青冥窄，',40,'御定全唐詩/json/687.json','["三十六峰危似冠，晴樓百尺獨登看。高淩鳥外青冥窄，", "始知萬歲聲長在，只待東巡動玉鸞。"]'),
('yuding-8','題湖城縣西道中槐樹','吳融','唐','御定全唐诗','yuding','','[]','零落欹斜此路中，盛時曾識太平風。曉迷天仗歸春苑，',40,'御定全唐詩/json/687.json','["零落欹斜此路中，盛時曾識太平風。曉迷天仗歸春苑，", "而今只有孤根在，鳥啄蟲穿沒亂蓬。"]'),
('yuding-9','東歸次瀛上','吳融','唐','御定全唐诗','yuding','','[]','暖煙輕淡草霏霏，一片晴山襯夕暉。水露淺沙無客泛，',40,'御定全唐詩/json/687.json','["暖煙輕淡草霏霏，一片晴山襯夕暉。水露淺沙無客泛，", "回首青門不知處，向人楊柳莫依依。"]'),
('yuding-10','偶書','吳融','唐','御定全唐诗','yuding','','[]','青牛關畔寄孤村，山當屏風石當門。芳樹綠陰連蔽芾，',40,'御定全唐詩/json/687.json','["青牛關畔寄孤村，山當屏風石當門。芳樹綠陰連蔽芾，", "只此無心便無事，避人何必武陵源。"]'),
('yuding-11','得京中親友書，訝久無音耗，以詩代謝','吳融','唐','御定全唐诗','yuding','','[]','退閑何事不忘機，況限溪雲靜掩扉。馬頰浪高魚去少，',40,'御定全唐詩/json/687.json','["退閑何事不忘機，況限溪雲靜掩扉。馬頰浪高魚去少，", "珍重故人知我者，九霄休複寄音徽。"]'),
('yuding-12','即事','吳融','唐','御定全唐诗','yuding','','[]','抵鵲山前雲掩扉，更甘終老脫朝衣。曉窺青鏡千峰入，',40,'御定全唐詩/json/687.json','["抵鵲山前雲掩扉，更甘終老脫朝衣。曉窺青鏡千峰入，", "何須一箸鱸魚膾，始掛孤帆問釣磯。"]'),
('yuding-13','病中宜茯苓寄李諫議','吳融','唐','御定全唐诗','yuding','','[]','千年茯菟帶龍鱗，太華峰頭得最珍。金鼎曉煎雲漾粉，',40,'御定全唐詩/json/687.json','["千年茯菟帶龍鱗，太華峰頭得最珍。金鼎曉煎雲漾粉，", "飛檄愈風知妙手，也須分藥救漳濱。"]'),
('yuding-14','槎','吳融','唐','御定全唐诗','yuding','','[]','浪痕龍跡老欹危，流落何時別故枝。歲月空教苔蘚積，',40,'御定全唐詩/json/687.json','["浪痕龍跡老欹危，流落何時別故枝。歲月空教苔蘚積，", "家近滄浪從泛去，碧天消息不參差。"]'),
('yuding-15','汴上觀','吳融','唐','御定全唐诗','yuding','','[]','九曲河冰半段來，嚴霜結出勁風裁。非時已認蟬飄翼，',40,'御定全唐詩/json/687.json','["九曲河冰半段來，嚴霜結出勁風裁。非時已認蟬飄翼，", "殷勤莫礙星槎路，從看天津弄杼回。"]'),
('yuding-16','閒居有作','吳融','唐','御定全唐诗','yuding','','[]','依依芳樹拂簷平，繞竹清流浸骨清。愛弄綠苔魚自躍，',40,'御定全唐詩/json/687.json','["依依芳樹拂簷平，繞竹清流浸骨清。愛弄綠苔魚自躍，", "只此超然長往是，幾人能遂鑄金成。"]'),
('yuding-17','離岐下題西湖','吳融','唐','御定全唐诗','yuding','','[]','送夏迎秋幾醉來，不堪行色被蟬催。身隨渭水看歸遠，',40,'御定全唐詩/json/687.json','["送夏迎秋幾醉來，不堪行色被蟬催。身隨渭水看歸遠，", "千波萬浪西風急，更為紅蕖把一杯。"]'),
('yuding-18','岐陽蒙相國對宅因抒懷投獻','吳融','唐','御定全唐诗','yuding','','[]','風有危亭月有台，平津閣畔好裴回。雖非宋玉誅茅至，',40,'御定全唐詩/json/687.json','["風有危亭月有台，平津閣畔好裴回。雖非宋玉誅茅至，", "故園蘭菊三千里，旅夢方應校懶回。"]'),
('yuding-19','晚泊松江','吳融','唐','御定全唐诗','yuding','','[]','落日停橈古渡邊，古今蹤跡一蒼然。平沙盡處雲藏樹，',40,'御定全唐詩/json/687.json','["落日停橈古渡邊，古今蹤跡一蒼然。平沙盡處雲藏樹，", "如何不及前賢事，卻謝鱸魚在洛川。"]'),
('yuding-20','過澠池書事','吳融','唐','御定全唐诗','yuding','','[]','澠池城郭半遺基，無限春愁掛落暉。柳渡風輕花浪綠，',40,'御定全唐詩/json/687.json','["澠池城郭半遺基，無限春愁掛落暉。柳渡風輕花浪綠，", "莫道新亭人對泣，異鄉殊代也沾衣。"]'),
('yuding-21','富春','吳融','唐','御定全唐诗','yuding','','[]','水送山迎入富春，一川如畫晚晴新。雲低遠渡帆來重，',40,'御定全唐詩/json/687.json','["水送山迎入富春，一川如畫晚晴新。雲低遠渡帆來重，", "嚴光萬古清風在，不敢停橈更問津。"]'),
('yuding-22','高侍禦話及皮博士池中白蓮因成一章寄博士兼奉呈','吳融','唐','御定全唐诗','yuding','','[]','白玉花開綠錦池，風流禦史報人知。看來應是雲中墮，',41,'御定全唐詩/json/687.json','["白玉花開綠錦池，風流禦史報人知。看來應是雲中墮，", "習家秋色堪圖畫，只欠山公倒接z5。"]'),
('yuding-23','憶猿','吳融','唐','御定全唐诗','yuding','','[]','翠微雲斂日沈空，叫徹青冥怨不窮。連臂影垂溪色裏，',40,'御定全唐詩/json/687.json','["翠微雲斂日沈空，叫徹青冥怨不窮。連臂影垂溪色裏，", "猶有北山歸意在，少驚佳樹近房櫳。"]'),
('yuding-24','紅樹','吳融','唐','御定全唐诗','yuding','','[]','一聲南雁已先紅，神女霜飛葉葉同。自是孤根非暖地，',40,'御定全唐詩/json/687.json','["一聲南雁已先紅，神女霜飛葉葉同。自是孤根非暖地，", "長憶洞庭千萬樹，照山橫浦夕陽中。"]'),
('yuding-25','新雁','吳融','唐','御定全唐诗','yuding','','[]','湘浦波春始北歸，玉關搖落又南飛。數聲飄去和秋色，',40,'御定全唐詩/json/687.json','["湘浦波春始北歸，玉關搖落又南飛。數聲飄去和秋色，", "莫從思婦台邊過，未得征人萬里衣。"]'),
('yuding-26','海上秋懷','吳融','唐','御定全唐诗','yuding','','[]','辭無珪組隱無才，門向潮頭過處開。幾度黃昏逢罔象，',40,'御定全唐詩/json/687.json','["辭無珪組隱無才，門向潮頭過處開。幾度黃昏逢罔象，", "昨夜秋風已搖落，那堪更上望鄉台。"]'),
('yuding-27','憶山泉','吳融','唐','御定全唐诗','yuding','','[]','穿雲落石細湔湔，盡日疑聞弄管弦。千仞灑來寒碎玉，',40,'御定全唐詩/json/687.json','["穿雲落石細湔湔，盡日疑聞弄管弦。千仞灑來寒碎玉，", "春雨正多歸未得，只應流恨更潺湲。"]'),
('yuding-28','東歸望華山','吳融','唐','御定全唐诗','yuding','','[]','碧蓮重疊在青冥，落日垂鞭緩客程。不奈春煙籠暗淡，',40,'御定全唐詩/json/687.json','["碧蓮重疊在青冥，落日垂鞭緩客程。不奈春煙籠暗淡，", "只怕仙人撫高掌，年年相見是空行。"]'),
('yuding-29','游華州飛泉亭','吳融','唐','御定全唐诗','yuding','','[]','走馬街南百畝池，碧蓮花影倒參差。偶同人去紅塵外，',40,'御定全唐詩/json/687.json','["走馬街南百畝池，碧蓮花影倒參差。偶同人去紅塵外，", "殷勤待取前峰月，更倚闌幹弄釣絲。"]'),
('yuding-30','池上雙鳧二首','吳融','唐','御定全唐诗','yuding','','[]','碧池悠漾小鳧雛，兩兩依依只自娛。釣艇忽移還散去，',80,'御定全唐詩/json/687.json','["碧池悠漾小鳧雛，兩兩依依只自娛。釣艇忽移還散去，", "幸是羽毛無取處，一生安穩老菰蒲。", "雙鳧狎得傍池台，戲藻銜蒲遠又回。敢為稻粱淩險去，", "不在籠欄夜仍好，月汀星沼剩裴回。"]'),
('yuding-31','葉落','吳融','唐','御定全唐诗','yuding','','[]','紅影飄來翠影微，一辭林表不知歸。伴愁無色煙猶在，',40,'御定全唐詩/json/687.json','["紅影飄來翠影微，一辭林表不知歸。伴愁無色煙猶在，", "楚郊千樹秋聲急，日暮紛紛惹客衣。"]'),
('yuding-32','和皮博士赴上京觀中修靈齋贈威儀尊師兼見寄','吳融','唐','御定全唐诗','yuding','','[]','霓結雙旌羽綴裙，七星壇上拜元君。精誠有為天應感，',40,'御定全唐詩/json/687.json','["霓結雙旌羽綴裙，七星壇上拜元君。精誠有為天應感，", "白雲鄉路看看到，好駐流年翊聖文。"]'),
('yuding-33','春雨','吳融','唐','御定全唐诗','yuding','','[]','霏霏漠漠暗和春，冪翠凝紅色更新。寒入膩裘濃曉睡，',40,'御定全唐詩/json/687.json','["霏霏漠漠暗和春，冪翠凝紅色更新。寒入膩裘濃曉睡，", "別有空階寂寥事，綠苔狼藉落花頻。"]'),
('yuding-34','秋池','吳融','唐','御定全唐诗','yuding','','[]','冷涵秋水碧溶溶，一片澄明見底空。有日晴來雲襯白，',40,'御定全唐詩/json/687.json','["冷涵秋水碧溶溶，一片澄明見底空。有日晴來雲襯白，", "淩曉無端照衰發，便悲霜雪鏡光中。"]'),
('yuding-35','首陽山','吳融','唐','御定全唐诗','yuding','','[]','首陽山枕黃河水，上有兩人曾餓死。不同天下人為非，',40,'御定全唐詩/json/687.json','["首陽山枕黃河水，上有兩人曾餓死。不同天下人為非，", "精靈長在白雲裏，應笑隨時飽死人。"]'),
('yuding-36','太湖石歌','吳融','唐','御定全唐诗','yuding','','[]','洞庭山下湖波碧，波中萬古生幽石。鐵索千尋取得來，',94,'御定全唐詩/json/687.json','["洞庭山下湖波碧，波中萬古生幽石。鐵索千尋取得來，", "又如防風死後骨，又如于菟活時額。又如成人楓，", "用時應不稱媧皇，將去也堪隨博望。噫嘻爾石好憑依，", "何必豪家甲第裏，玉闌幹畔爭光輝。一朝荊棘忽流落，"]'),
('yuding-37','贈方幹處士歌','吳融','唐','御定全唐诗','yuding','','[]','把筆盡為詩，何人敵夫子？句滿天下口，名聒天下耳。',106,'御定全唐詩/json/687.json','["把筆盡為詩，何人敵夫子？句滿天下口，名聒天下耳。", "不識朝，不識市，曠逍遙，閑徙倚。一杯酒，無萬事；", "一葉舟，無千里。衣裳白雲，坐臥流水。霜落風高忽相憶，", "拂旦舍我亦不辭，攜筇徑去隨所適。隨所適，無處覓。", "雲半片，鶴一隻。"]'),
('yuding-38','李周彈箏歌','吳融','唐','御定全唐诗','yuding','','[]','古人雲，絲不如竹，竹不如肉。乃知此語未必然，',142,'御定全唐詩/json/687.json','["古人雲，絲不如竹，竹不如肉。乃知此語未必然，", "就中十三弦最妙，應宮出入年方少。青驄慣走長楸日，", "始似五更殘月裏，淒淒切切清露蟬。又如石罅堆葉下，", "有時上苑繁花發，有時太液秋波闊。當頭獨坐摐一聲，", "出來無暇更還家，且上青樓醉明月。年將六十藝轉精，", "供奉供奉且聽語，自昔興衰看樂府。只如伊州與梁州，"]'),
('yuding-39','贈z6光上人草書歌','吳融','唐','御定全唐诗','yuding','','[]','篆書樸，隸書俗，草聖貴在無羈束。江南有僧名z6光，',109,'御定全唐詩/json/687.json','["篆書樸，隸書俗，草聖貴在無羈束。江南有僧名z6光，", "摘如鉤，挑如撥，斜如掌，回如斡。又如夏禹鎖淮神，", "有時軟縈盈，一穗秋雲曳空闊。有時瘦巉岩，", "稽山賀老昔所傳，又聞能者惟張顛。上人致功應不下，", "不系知之與不知，須言一字千金值。"]'),
('yuding-40','贈李長史歌','吳融','唐','御定全唐诗','yuding','','[]','危欄壓溪溪澹碧，翠嫋紅飄鶯寂寂。此日長亭愴別離，',144,'御定全唐詩/json/687.json','["危欄壓溪溪澹碧，翠嫋紅飄鶯寂寂。此日長亭愴別離，", "初疑一百尺瀑布，八九月落香爐巔。又似鮫人為客罷，", "鏗訇揭調初驚人，幽咽細聲還感神。紫鳳將雛叫山月，", "可中長似承平基，肯將此為閒人吹。不是東城射雉處，", "賣珠曾被武皇問，熏香不怕賈公知。今來流落一何苦，", "長史長史聽我語，從來藝絕多失所。羅君贈君兩首詩，"]'),
('yuding-41','贈廣利大師歌','吳融','唐','御定全唐诗','yuding','','[]','化人之心固甚難，自化之心更不易。化人可以程限之，',111,'御定全唐詩/json/687.json','["化人之心固甚難，自化之心更不易。化人可以程限之，", "三十年前識師初，正見把筆學草書。崩雲落日千萬狀，", "近來兼解作歌詩，言語明快有氣骨。堅如百煉鋼，", "乃知性是天，習是人。莫輕河邊羖fG，飛作天上麒麟。", "但日新，又日新，李太白，非通神。"]'),
('yuding-42','古離別','吳融','唐','御定全唐诗','yuding','','[]','紫鸞黃鵠雖別離，一舉千里何難追。猶聞啼風與叫月，',48,'御定全唐詩/json/687.json','["紫鸞黃鵠雖別離，一舉千里何難追。猶聞啼風與叫月，", "蟾蜍正向清夜流，蛺蝶須教墮絲罥。莫道斷絲不可續，"]'),
('yuding-43','風雨吟','吳融','唐','御定全唐诗','yuding','','[]','風騷騷，雨涔涔，長洲苑外荒居深。門外流水流澶漫，',172,'御定全唐詩/json/687.json','["風騷騷，雨涔涔，長洲苑外荒居深。門外流水流澶漫，", "尋常倚月複眠花，莫說斜風兼細雨。", "應不知天地造化是何物，亦不知榮辱是何主。", "吾囷長滿是太平，吾樂不極是天生。豈憂天下有大憝，", "又豈複憂朝廷苦弛慢，中官轉縱橫。李膺勾黨即罹患，", "可歎吳城城中人，無人與我交一言。蓬蒿滿徑塵一榻，", "況我長懷丈夫志，今來流落滄溟涘。有時驚事再咨嗟，", "伯牙海上感滄溟，何似今朝風雨思。"]'),
('yuding-44','江行','吳融','唐','御定全唐诗','yuding','','[]','來時風，去時雨，蕭蕭颯颯春江浦。欹欹側側海門帆，',24,'御定全唐詩/json/687.json','["來時風，去時雨，蕭蕭颯颯春江浦。欹欹側側海門帆，"]'),
('yuding-45','壁畫折竹雜言','吳融','唐','御定全唐诗','yuding','','[]','枯纏藤，重欹雪。渭曲逢，湘江別。不是從來無本根，',24,'御定全唐詩/json/687.json','["枯纏藤，重欹雪。渭曲逢，湘江別。不是從來無本根，"]'),
('yuding-46','古錦裾六韻','吳融','唐','御定全唐诗','yuding','','[]','濯水經何日，隨風故有人。綠衣猶偪畫，丹頂尚迷真。',72,'御定全唐詩/json/687.json','["濯水經何日，隨風故有人。綠衣猶偪畫，丹頂尚迷真。", "暗淡雲沈古，青蒼蘚剝新。映襟知惹淚，侵韉想縈塵。", "掣曳無由睹，流傳久自珍。武威應認得，牽挽幾當春。"]'),
('yuding-47','賦得欲曉看妝面','吳融','唐','御定全唐诗','yuding','','[]','朧朧欲曙色，隱隱辨殘妝。月始雲中出，花猶霧裏藏。',72,'御定全唐詩/json/687.json','["朧朧欲曙色，隱隱辨殘妝。月始雲中出，花猶霧裏藏。", "眉邊全失翠，額畔半留黃。轉入金屏影，隈侵角枕光。", "有蟬隳鬢樣，無燕著釵行。十二峰前夢，如何不斷腸。"]'),
('yuding-48','府試雨夜帝裏聞猿聲','吳融','唐','御定全唐诗','yuding','','[]','雨滴秦中夜，猿聞峽外聲。已吟何遜恨，還賦屈平情。',72,'御定全唐詩/json/687.json','["雨滴秦中夜，猿聞峽外聲。已吟何遜恨，還賦屈平情。", "暗逐哀鴻淚，遙含禁漏清。直疑遊萬里，不覺在重城。", "霎霎侵燈亂，啾啾入夢驚。明朝臨曉鏡，別有鬢絲生。"]'),
('yuding-49','題畫柏','吳融','唐','御定全唐诗','yuding','','[]','不得月中桂，轉思陵上柏。閑取畫圖看，煩紆果冰釋。',168,'御定全唐詩/json/687.json','["不得月中桂，轉思陵上柏。閑取畫圖看，煩紆果冰釋。", "桂生在青冥，萬古煙霧隔。下蔭玄兔窟，上映嫦娥魄。", "圓缺且不常，高低圖難測。若非假羽翰，折攀何由得。", "天遠眼虛穿，夜闌頭自白。未知陵上柏，一定不移易。", "有意兼松茂，無情從麝食。不在是非間，與人為憤激。", "他年上縑素，今日懸屋壁。靈怪不可知，風雨疑來逼。", "明朝歸故園，唯此同所適。回首寄團枝，無勞惠消息。"]'),
('yuding-50','平望蚊子二十六韻','吳融','唐','御定全唐诗','yuding','','[]','天下有蚊子，候夜噆人膚。平望有蚊子，白晝來相屠。',312,'御定全唐詩/json/687.json','["天下有蚊子，候夜噆人膚。平望有蚊子，白晝來相屠。", "不避風與雨，群飛出菰蒲。擾擾蔽天黑，雷然隨舳艫。", "利嘴入人肉，微形紅且濡。振蓬亦不懼，至死貪膏腴。", "舟人敢停棹，陸者亦疾趨。南北百餘裏，畏之如虎貙。", "噫嘻天地間，萬物各有殊。陽者陽為伍，陰者陰為徒。", "蚊蚋是陰物，夜從喧牆隅。如何正曦赫，吞噬當通衢。", "人筋為爾斷，人力為爾枯。衣巾穢且甚，盤饌腥有餘。", "豈是陽德衰，不能使消除。豈是有主者，此鄉宜毒荼。", "吾聞蛇能螫，避之則無虞。吾聞蠆有毒，見之可疾驅。", "唯是此蚊子，逢人皆病諸。江南夏景好，水木多蕭疏。", "此中震澤路，風月彌清虛。前後幾來往，襟懷曾未舒。", "朝既蒙襞積，夜仍跧蘧蒢。雖然好吟嘯，其奈難踟躕。", "人生有不便，天意當何如。誰能假羽翼，直上言紅爐。"]'),
('yuding-51','桃花','吳融','唐','御定全唐诗','yuding','','[]','滿樹和嬌爛漫紅，萬枝丹彩灼春融。',32,'御定全唐詩/json/687.json','["滿樹和嬌爛漫紅，萬枝丹彩灼春融。", "何當結作千年實，將示人間造化工。"]'),
('yuding-52','木筆花','吳融','唐','御定全唐诗','yuding','','[]','嫩如新竹管初齊，粉膩紅輕樣可攜。',32,'御定全唐詩/json/687.json','["嫩如新竹管初齊，粉膩紅輕樣可攜。", "誰與詩人偎檻看，好於箋墨並分題。"]'),
('yuding-53','浙東筵上有寄','吳融','唐','御定全唐诗','yuding','','[]','襄王席上一神仙，眼色相當語不傳。見了又休真似夢，',40,'御定全唐詩/json/687.json','["襄王席上一神仙，眼色相當語不傳。見了又休真似夢，", "更被東風勸惆悵，落花時節定翩翩。"]'),
('yuding-54','富水驛東楹有人題詩','吳融','唐','御定全唐诗','yuding','','[]','繡纓霞翼兩鴛鴦，金島銀川是故鄉。只合雙飛便雙死，',40,'御定全唐詩/json/687.json','["繡纓霞翼兩鴛鴦，金島銀川是故鄉。只合雙飛便雙死，", "何事遽驚雲雨別，秦山楚水兩乖張。"]'),
('yuding-55','上巳日','吳融','唐','御定全唐诗','yuding','','[]','本學多情劉武威，尋花傍水看春暉。',32,'御定全唐詩/json/687.json','["本學多情劉武威，尋花傍水看春暉。", "無端遇著傷心事，贏得淒涼索漠歸。"]'),
('yuding-56','隋堤','吳融','唐','御定全唐诗','yuding','','[]','搔首隋堤落日斜，已無餘柳可藏鴉。岸傍昔道牽龍艦，',40,'御定全唐詩/json/687.json','["搔首隋堤落日斜，已無餘柳可藏鴉。岸傍昔道牽龍艦，", "四方正是無虞日，誰信黎陽有古家。"]'),
('yuding-0','寄杜先生詩','孫偓','唐','御定全唐诗','yuding','','[]','蜀國信難遇，楚鄉心更愁。我行同范蠡，師舉效浮丘。',36,'御定全唐詩/json/688.json','["蜀國信難遇，楚鄉心更愁。我行同范蠡，師舉效浮丘。", "他日相逢處，多應在十洲。"]'),
('yuding-1','贈南嶽僧全玭','孫偓','唐','御定全唐诗','yuding','','[]','窠居過後更何人，傳得如來法印真。',32,'御定全唐詩/json/688.json','["窠居過後更何人，傳得如來法印真。", "昨日祝融峰下見，草衣便是雪山□。"]'),
('yuding-2','答門生王渙李德鄰趙光胤王拯長句','孫偓','唐','御定全唐诗','yuding','','[]','謬持文柄得時賢，粉署清華次第遷。昔歲策名皆健筆，',40,'御定全唐詩/json/688.json','["謬持文柄得時賢，粉署清華次第遷。昔歲策名皆健筆，", "何事老夫猶賦詠，欲將酬和永留傳。"]'),
('yuding-3','句','孫偓','唐','御定全唐诗','yuding','','[]','好是步虛明月夜，瑞爐蜚下醮壇前。',16,'御定全唐詩/json/688.json','["好是步虛明月夜，瑞爐蜚下醮壇前。"]'),
('yuding-4','禁林聞曉鶯','陸扆','唐','御定全唐诗','yuding','','[]','曙色分層漢，鶯聲繞上林。報花開瑞錦，催柳綻黃金。',72,'御定全唐詩/json/688.json','["曙色分層漢，鶯聲繞上林。報花開瑞錦，催柳綻黃金。", "斷續隨風遠，間關送月沈。語當溫樹近，飛覺禁園深。", "繡戶驚殘夢，瑤池囀好音。願將棲息意，從此沃天心。"]'),
('yuding-5','句','陸扆','唐','御定全唐诗','yuding','','[]','今秋已約天臺月。',8,'御定全唐詩/json/688.json','["今秋已約天臺月。"]'),
('yuding-6','華州榜寄諸門生','薛昭緯','唐','御定全唐诗','yuding','','[]','時君過聽委平衡，粉署華燈到曉明。開卷固難窺浩汗，',29,'御定全唐詩/json/688.json','["時君過聽委平衡，粉署華燈到曉明。開卷固難窺浩汗，", "自笑觀光輝"]'),
('yuding-7','謝銀工','薛昭緯','唐','御定全唐诗','yuding','','[]','一碟氈根數十皴，盤中猶更有紅鱗。',32,'御定全唐詩/json/688.json','["一碟氈根數十皴，盤中猶更有紅鱗。", "早知文字多辛苦，悔不當初學冶銀。"]'),
('yuding-8','閒居即事','陸翱','唐','御定全唐诗','yuding','','[]','衰柳迷隋苑，衡門啼暮鴉。茅廚煙不動，書牖日空斜。',48,'御定全唐詩/json/688.json','["衰柳迷隋苑，衡門啼暮鴉。茅廚煙不動，書牖日空斜。", "悔下東山石，貧于南阮家。沈憂損神慮，萱草自開花。"]'),
('yuding-9','趙氏北樓','陸翱','唐','御定全唐诗','yuding','','[]','殷勤趙公子，良夜竟相留。朗月生東海，仙娥在北樓。',48,'御定全唐詩/json/688.json','["殷勤趙公子，良夜竟相留。朗月生東海，仙娥在北樓。", "酒闌珠露滴，歌迥石城秋。本為愁人設，愁人到曉愁。"]'),
('yuding-10','題馬嵬驛','狄歸昌','唐','御定全唐诗','yuding','','[]','馬嵬煙柳正依依，重見鑾輿幸蜀歸。',32,'御定全唐詩/json/688.json','["馬嵬煙柳正依依，重見鑾輿幸蜀歸。", "泉下阿蠻應有語，這回休更怨楊妃。"]'),
('yuding-11','蜀中登第答李搏六韻','裴廷裕','唐','御定全唐诗','yuding','','[]','何勞問我成都事，亦報君知便納降。蜀柳籠堤煙矗矗，',48,'御定全唐詩/json/688.json','["何勞問我成都事，亦報君知便納降。蜀柳籠堤煙矗矗，", "高卷絳紗揚氏宅，半垂紅袖薛濤窗。浣花泛鷁詩千首，"]'),
('yuding-12','偶題','裴廷裕','唐','御定全唐诗','yuding','','[]','微雨微風寒食節，半開半合木蘭花。',32,'御定全唐詩/json/688.json','["微雨微風寒食節，半開半合木蘭花。", "看花倚柱終朝立，卻似淒淒不在家。"]'),
('yuding-13','閑宵望月','李沇','唐','御定全唐诗','yuding','','[]','卷箔舒紅茵，當軒玩明月。懿哉深夜中，靜聽歌初發。',72,'御定全唐詩/json/688.json','["卷箔舒紅茵，當軒玩明月。懿哉深夜中，靜聽歌初發。", "苔含殿華濕，竹影蟾光潔。轉扇來清風，援琴飛白雪。", "行愁景候變，坐恐流芳歇。桂影有餘光，蘭燈任將滅。"]'),
('yuding-14','醮詞','李沇','唐','御定全唐诗','yuding','','[]','犬咬天關閉，彩童呼仙吏。一封紅篆書，為奏塵寰事。',108,'御定全唐詩/json/688.json','["犬咬天關閉，彩童呼仙吏。一封紅篆書，為奏塵寰事。", "八極鼇柱傾，四溟龍鬣沸。長庚冷有芒，文曲淡無氣。", "烏輪不再中，黃沙瘞腥鬼。請帝命真官，臨雲啟金匱。", "方與清華宮，重正紫極位。曠古雨露恩，安得惜沾施。", "生人血欲盡，攙搶無飽意。"]'),
('yuding-15','巫山高','李沇','唐','御定全唐诗','yuding','','[]','抉天心，開地脈，浮動淩霄拂藍碧。襄王端眸望不極，',48,'御定全唐詩/json/688.json','["抉天心，開地脈，浮動淩霄拂藍碧。襄王端眸望不極，", "君王妒妾夢荊宮，虛把金泥印仙掌。江濤迅激如相助，"]'),
('yuding-16','夢仙謠','李沇','唐','御定全唐诗','yuding','','[]','海宮蹙浪收殘月，挈壺掌事傳更歇。銀蟾半墜恨流咽，',48,'御定全唐詩/json/688.json','["海宮蹙浪收殘月，挈壺掌事傳更歇。銀蟾半墜恨流咽，", "桂花裛露曙香冷，八窗玉朗驚晨雞。裁紗剪羅貼丹鳳，"]'),
('yuding-17','秋霖歌','李沇','唐','御定全唐诗','yuding','','[]','西方龍兒口猶乳，初解驅雲學行雨。縱恣群陰駕老虯，',40,'御定全唐詩/json/688.json','["西方龍兒口猶乳，初解驅雲學行雨。縱恣群陰駕老虯，", "恨無長劍一千仞，劃斷頑雲看晴碧。"]'),
('yuding-18','方響歌','李沇','唐','御定全唐诗','yuding','','[]','敲金扣石聲相淩，遙空冷靜天正澄。寶瓶下井轆轤急，',72,'御定全唐詩/json/688.json','["敲金扣石聲相淩，遙空冷靜天正澄。寶瓶下井轆轤急，", "季倫怒擊珊瑚摧，靈芸整鬢步搖折。十六葉中侵素光，", "急節寫商商恨促，秦愁越調逡巡足。夢入仙樓戛殘曲，"]'),
('yuding-19','答王渙','裴贄','唐','御定全唐诗','yuding','','[]','謬持文柄得時賢，粉署清華次第遷。昔歲策名皆健筆，',40,'御定全唐詩/json/688.json','["謬持文柄得時賢，粉署清華次第遷。昔歲策名皆健筆，", "何事老夫猶賦詠，欲將酬和永留傳。"]'),
('yuding-20','薄命妾','盧汝弼','唐','御定全唐诗','yuding','','[]','君恩已斷盡成空，追想嬌歡恨莫窮。長為蕣花光曉日，',40,'御定全唐詩/json/688.json','["君恩已斷盡成空，追想嬌歡恨莫窮。長為蕣花光曉日，", "閑憑玉欄思舊事，幾回春暮泣殘紅。"]'),
('yuding-21','秋夕寓居精舍書事','盧汝弼','唐','御定全唐诗','yuding','','[]','葉滿苔階杵滿城，此中多恨恨難平。疏簷看織蠨蛸網，',40,'御定全唐詩/json/688.json','["葉滿苔階杵滿城，此中多恨恨難平。疏簷看織蠨蛸網，", "覺來獨步長廊下，半夜西風吹月明。"]'),
('yuding-22','聞雁','盧汝弼','唐','御定全唐诗','yuding','','[]','秋風蕭瑟靜埃氛，邊雁迎風響咽群。瀚海應嫌霜下早，',40,'御定全唐詩/json/688.json','["秋風蕭瑟靜埃氛，邊雁迎風響咽群。瀚海應嫌霜下早，", "何處最添羈客恨，竹窗殘月酒醒聞。"]'),
('yuding-23','鴛鴦','盧汝弼','唐','御定全唐诗','yuding','','[]','雙浮雙浴傍苔磯，蓼浦蘭皋繡帳幃。長羨鷺鷥能潔白，',40,'御定全唐詩/json/688.json','["雙浮雙浴傍苔磯，蓼浦蘭皋繡帳幃。長羨鷺鷥能潔白，", "應笑隨陽沙漠雁，洞庭煙暖又思歸。"]'),
('yuding-24','和李秀才邊庭四時怨','盧汝弼','唐','御定全唐诗','yuding','','[]','春風昨夜到榆關，故國煙花想已殘。',128,'御定全唐詩/json/688.json','["春風昨夜到榆關，故國煙花想已殘。", "少婦不知歸不得，朝朝應上望夫山。", "盧龍塞外草初肥，雁乳平蕪曉不飛。", "鄉國近來音信斷，至今猶自著寒衣。", "八月霜飛柳半黃，蓬根吹斷雁南翔。", "隴頭流水關山月，泣上龍堆望故鄉。", "朔風吹雪透刀瘢，飲馬長城窟更寒。", "半夜火來知有敵，一時齊保賀蘭山。"]'),
('yuding-0','山居即事二首','陸希聲','唐','御定全唐诗','yuding','','[]','君山蒼翠接青冥，東走洮湖上洞庭。茅屋向陽梳白髮，',80,'御定全唐詩/json/689.json','["君山蒼翠接青冥，東走洮湖上洞庭。茅屋向陽梳白髮，", "為問前時金馬客，此焉還作少微星。", "不是幽棲矯性靈，從來無意在膻腥。滿川風物供高枕，", "君陽遁叟何為樂，一炷清香兩卷經。"]'),
('yuding-1','陽羨雜詠十九首：苦行徑','陸希聲','唐','御定全唐诗','yuding','','[]','山前無數碧琅玕，一徑清森五月寒。',32,'御定全唐詩/json/689.json','["山前無數碧琅玕，一徑清森五月寒。", "世上何人憐苦節，應須細問子猷看。"]'),
('yuding-2','陽羨雜詠十九首：梅花塢','陸希聲','唐','御定全唐诗','yuding','','[]','凍蕊凝香色豔新，小山深塢伴幽人。',32,'御定全唐詩/json/689.json','["凍蕊凝香色豔新，小山深塢伴幽人。", "知君有意淩寒色，羞共千花一樣春。"]'),
('yuding-3','陽羨雜詠十九首：石兕台','陸希聲','唐','御定全唐诗','yuding','','[]','大河波浪激潼關，青兕胡為伏此山。',32,'御定全唐詩/json/689.json','["大河波浪激潼關，青兕胡為伏此山。", "遙想楚王雲夢澤，蜺旌羽蓋定空還。"]'),
('yuding-4','陽羨雜詠十九首：講易台','陸希聲','唐','御定全唐诗','yuding','','[]','年逾知命志尤堅，獨向青山更絕編。',32,'御定全唐詩/json/689.json','["年逾知命志尤堅，獨向青山更絕編。", "天下有山山有水，養蒙肥遁正翛然。"]'),
('yuding-5','陽羨雜詠十九首：觀魚亭','陸希聲','唐','御定全唐诗','yuding','','[]','惠施徒自學多方，謾說觀魚理未長。',32,'御定全唐詩/json/689.json','["惠施徒自學多方，謾說觀魚理未長。", "不得莊生濠上旨，江湖何以見相忘。"]'),
('yuding-6','陽羨雜詠十九首：綠雲亭','陸希聲','唐','御定全唐诗','yuding','','[]','六月清涼綠樹陰，小亭高臥滌煩襟。',32,'御定全唐詩/json/689.json','["六月清涼綠樹陰，小亭高臥滌煩襟。", "羲皇向上何人到，永日時時弄素琴。"]'),
('yuding-7','陽羨雜詠十九首：清輝堂','陸希聲','唐','御定全唐诗','yuding','','[]','野人心地本無機，為愛茅簷倚翠微。',32,'御定全唐詩/json/689.json','["野人心地本無機，為愛茅簷倚翠微。", "盡日尊前誰是客，秋山含水有清輝。"]'),
('yuding-8','陽羨雜詠十九首：觀妙庵','陸希聲','唐','御定全唐诗','yuding','','[]','妙理難觀旨甚深，欲知無欲是無心。',32,'御定全唐詩/json/689.json','["妙理難觀旨甚深，欲知無欲是無心。", "茅庵不異人間世，河上真人自可尋。"]'),
('yuding-9','陽羨雜詠十九首：西陽亭','陸希聲','唐','御定全唐诗','yuding','','[]','隔林殘日照孤亭，玄晏先生酒未醒。',32,'御定全唐詩/json/689.json','["隔林殘日照孤亭，玄晏先生酒未醒。", "入夜莫愁迷下路，昔人猶在逐流螢。"]'),
('yuding-10','陽羨雜詠十九首：弄雲亭','陸希聲','唐','御定全唐诗','yuding','','[]','自知無業致吾君，只向春山弄白雲。',32,'御定全唐詩/json/689.json','["自知無業致吾君，只向春山弄白雲。", "已共此山私斷當，不須轉轍重移文。"]'),
('yuding-11','陽羨雜詠十九首：伏龜堂','陸希聲','唐','御定全唐诗','yuding','','[]','盤崖蹙縮似靈龜，鬼谷先生隱遁時。',32,'御定全唐詩/json/689.json','["盤崖蹙縮似靈龜，鬼谷先生隱遁時。", "不獨卷懷經世志，白雲流水是心期。"]'),
('yuding-12','陽羨雜詠十九首：桃花谷','陸希聲','唐','御定全唐诗','yuding','','[]','君陽山下足春風，滿谷仙桃照水紅。',32,'御定全唐詩/json/689.json','["君陽山下足春風，滿谷仙桃照水紅。", "何必武陵源上去，澗邊好過落花中。"]'),
('yuding-13','陽羨雜詠十九首：含桃圃','陸希聲','唐','御定全唐诗','yuding','','[]','小圃初晴風露光，含桃花發滿山香。',32,'御定全唐詩/json/689.json','["小圃初晴風露光，含桃花發滿山香。", "看花對酒心無事，倍覺春來白日長。"]'),
('yuding-14','陽羨雜詠十九首：茗坡','陸希聲','唐','御定全唐诗','yuding','','[]','二月山家穀雨天，半坡芳茗露華鮮。',32,'御定全唐詩/json/689.json','["二月山家穀雨天，半坡芳茗露華鮮。", "春醒酒病兼消渴，惜取新芽旋摘煎。"]'),
('yuding-15','陽羨雜詠十九首：松嶺','陸希聲','唐','御定全唐诗','yuding','','[]','嶺上青松手自栽，已能蒼翠映莓苔。',32,'御定全唐詩/json/689.json','["嶺上青松手自栽，已能蒼翠映莓苔。", "歲寒本是君家事，好送清風月下來。"]'),
('yuding-16','陽羨雜詠十九首：桃溪','陸希聲','唐','御定全唐诗','yuding','','[]','芳草霏霏遍地齊，桃花脈脈自成溪。',32,'御定全唐詩/json/689.json','["芳草霏霏遍地齊，桃花脈脈自成溪。", "也知百舌多言語，任向春風盡意啼。"]'),
('yuding-17','陽羨雜詠十九首：李徑','陸希聲','唐','御定全唐诗','yuding','','[]','一徑穠芳萬蕊攢，風吹雨打未摧殘。',32,'御定全唐詩/json/689.json','["一徑穠芳萬蕊攢，風吹雨打未摧殘。", "憐君盡向高枝發，應為行人要整冠。"]'),
('yuding-18','陽羨雜詠十九首：鴻盤','陸希聲','唐','御定全唐诗','yuding','','[]','落落飛鴻漸始盤，青雲起處剩須看。',32,'御定全唐詩/json/689.json','["落落飛鴻漸始盤，青雲起處剩須看。", "如今天路多矰繳，縱使銜蘆去也難。"]'),
('yuding-19','陽羨雜詠十九首：偃月嶺','陸希聲','唐','御定全唐诗','yuding','','[]','山嶺依稀偃月形，數層倚石疊空青。',32,'御定全唐詩/json/689.json','["山嶺依稀偃月形，數層倚石疊空青。", "幾回雪夜寒光積，直似金光照戶庭。"]'),
('yuding-20','寄z6光上人','陸希聲','唐','御定全唐诗','yuding','','[]','筆下龍蛇似有神，天池雷雨變逡巡。',32,'御定全唐詩/json/689.json','["筆下龍蛇似有神，天池雷雨變逡巡。", "寄言昔日不龜手，應念江頭洴澼人。"]'),
('yuding-21','喜杜荀鶴及第','李昭象','唐','御定全唐诗','yuding','','[]','深岩貧複病，榜到見君名。貧病渾如失，山川頓覺清。',48,'御定全唐詩/json/689.json','["深岩貧複病，榜到見君名。貧病渾如失，山川頓覺清。", "一春新酒興，四海舊詩聲。日使能吟者，西來步步輕。"]'),
('yuding-22','赴舉出山留寄山居鄭參軍','李昭象','唐','御定全唐诗','yuding','','[]','還如費冠卿，向此振高名。肯羨魚須美，長誇鶴氅輕。',48,'御定全唐詩/json/689.json','["還如費冠卿，向此振高名。肯羨魚須美，長誇鶴氅輕。", "理琴寒指倦，試藥黑髭生。時泰難雲臥，隨看急詔行。"]'),
('yuding-23','題顧正字溪居','李昭象','唐','御定全唐诗','yuding','','[]','高敞吟軒近釣灣，塵中來似出人間。若教明月休生桂，',40,'御定全唐詩/json/689.json','["高敞吟軒近釣灣，塵中來似出人間。若教明月休生桂，", "莫誇恬淡勝榮祿，雁引行高未許閑。"]'),
('yuding-24','寄獻山中顧公員外','李昭象','唐','御定全唐诗','yuding','','[]','抽卻朝簪著釣蓑，近來聲跡轉巍峨。祥麟避網雖山野，',40,'御定全唐詩/json/689.json','["抽卻朝簪著釣蓑，近來聲跡轉巍峨。祥麟避網雖山野，", "深慚未副吹噓力，竟困風埃爭奈何。"]'),
('yuding-25','山中寄崔諫議','李昭象','唐','御定全唐诗','yuding','','[]','半生猿鳥共山居，吟月吟風兩鬢疏。新句未嘗忘教化，',40,'御定全唐詩/json/689.json','["半生猿鳥共山居，吟月吟風兩鬢疏。新句未嘗忘教化，", "從此升騰休說命，只希公道數封書。"]'),
('yuding-26','學仙詞寄顧雲','李昭象','唐','御定全唐诗','yuding','','[]','記得初傳九轉方，碧雲峰下祝虛皇。丹砂未熟心徒切，',40,'御定全唐詩/json/689.json','["記得初傳九轉方，碧雲峰下祝虛皇。丹砂未熟心徒切，", "仙人恩重何由報，焚盡星壇午夜香。"]'),
('yuding-27','寄尉遲侍禦','李昭象','唐','御定全唐诗','yuding','','[]','我眠青嶂弄澄潭，君戴貂蟬白玉篸。應向謝公樓上望，九華山色在西南。',32,'御定全唐詩/json/689.json','["我眠青嶂弄澄潭，君戴貂蟬白玉篸。應向謝公樓上望，九華山色在西南。"]'),
('yuding-28','招西洞道者','李昭象','唐','御定全唐诗','yuding','','[]','危峰抹黛夾晴川，樹簇紅英草碧煙。',32,'御定全唐詩/json/689.json','["危峰抹黛夾晴川，樹簇紅英草碧煙。", "樵客雲僧兩無事，此中堪去覓靈仙。"]'),
('yuding-29','句','李昭象','唐','御定全唐诗','yuding','','[]','投文得仕而今少，佩印還家古所榮。（送周繇之建德。',31,'御定全唐詩/json/689.json','["投文得仕而今少，佩印還家古所榮。（送周繇之建德。", "《唐詩紀事》）"]'),
('yuding-0','夏雨','王駕','唐','御定全唐诗','yuding','','[]','非惟消旱暑，且喜救生民。天地如蒸濕，園林似卻春。',48,'御定全唐詩/json/690.json','["非惟消旱暑，且喜救生民。天地如蒸濕，園林似卻春。", "洗風清枕簟，換夜失埃塵。又作豐年望，田夫笑向人。"]'),
('yuding-1','古意','王駕','唐','御定全唐诗','yuding','','[]','夫戍蕭關妾在吳，西風吹妾妾憂夫。',32,'御定全唐詩/json/690.json','["夫戍蕭關妾在吳，西風吹妾妾憂夫。", "一行書信千行淚，寒到君邊衣到無。"]'),
('yuding-2','社日','王駕','唐','御定全唐诗','yuding','','[]','鵝湖山下稻粱肥，豚柵雞棲半掩扉。',32,'御定全唐詩/json/690.json','["鵝湖山下稻粱肥，豚柵雞棲半掩扉。", "桑柘影斜春社散，家家扶得醉人歸。"]'),
('yuding-3','雨晴','王駕','唐','御定全唐诗','yuding','','[]','雨前初見花間蕊，雨後兼無葉裏花。',32,'御定全唐詩/json/690.json','["雨前初見花間蕊，雨後兼無葉裏花。", "蛺蝶飛來過牆去，卻疑春色在鄰家。"]'),
('yuding-4','亂後曲江','王駕','唐','御定全唐诗','yuding','','[]','憶昔爭遊曲水濱，未春長有探春人。',32,'御定全唐詩/json/690.json','["憶昔爭遊曲水濱，未春長有探春人。", "游春人盡空池在，直至春深不似春。"]'),
('yuding-5','過故友居','王駕','唐','御定全唐诗','yuding','','[]','鄰笛寒吹日落初，舊居今已別人居。',32,'御定全唐詩/json/690.json','["鄰笛寒吹日落初，舊居今已別人居。", "亂來兒侄皆分散，惆悵僧房認得書。"]'),
('yuding-6','上裴侍郎','王渙','唐','御定全唐诗','yuding','','[]','青衿七十榜三年，建禮含香次第遷。珠彩下連星錯落，',40,'御定全唐詩/json/690.json','["青衿七十榜三年，建禮含香次第遷。珠彩下連星錯落，", "應念銜恩最深者，春來為壽拜尊前。"]'),
('yuding-7','悼亡','王渙','唐','御定全唐诗','yuding','','[]','春來得病夏來加，深掩妝窗臥碧紗。為怯暗藏秦女扇，',40,'御定全唐詩/json/690.json','["春來得病夏來加，深掩妝窗臥碧紗。為怯暗藏秦女扇，", "今日青門葬君處，亂蟬衰草夕陽斜。"]'),
('yuding-8','惆悵詩十二首','王渙','唐','御定全唐诗','yuding','','[]','八蠶薄絮鴛鴦綺，半夜佳期並枕眠。',384,'御定全唐詩/json/690.json','["八蠶薄絮鴛鴦綺，半夜佳期並枕眠。", "鐘動紅娘喚歸去，對人勻淚拾金鈿。", "李夫人病已經秋，漢武看來不舉頭。", "得所濃華銷歇盡，楚魂湘血一生休。", "謝家池館花籠月，蕭寺房廊竹颭風。", "夜半酒醒憑檻立，所思多在別離中。", "隋師戰艦欲亡陳，國破應難保此身。", "訣別徐郎淚如雨，鏡鸞分後屬何人。", "七夕瓊筵隨事陳，兼花連蒂共傷神。", "蜀王殿裏三更月，不見驪山私語人。", "夜寒春病不勝懷，玉瘦花啼萬事乖。", "薄幸檀郎斷芳信，驚嗟猶夢合歡鞋。", "嗚咽離聲管吹秋，妾身今日為君休。", "齊奴不說平生事，忍看花枝謝玉樓。", "青絲一綹墮雲鬟，金剪刀鳴不忍看。", "持謝君王寄幽怨，可能從此住人間。", "陳宮興廢事難期，三閣空餘綠草基。", "狎客淪亡麗華死，他年江令獨來時。", "晨肇重來路已迷，碧桃花謝武陵溪。", "仙山目斷無尋處，流水潺湲日漸西。", "少卿降北子卿還，朔野離觴慘別顏。", "卻到茂陵唯一慟，節毛零落鬢毛斑。", "夢裏分明入漢宮，覺來燈背錦屏空。", "紫台月落關山曉，腸斷君恩信畫工。"]'),
('yuding-9','江上雨','戴司顏','唐','御定全唐诗','yuding','','[]','非不欲前去，此情非自由。星辰照何處，風雨送涼秋。',48,'御定全唐詩/json/690.json','["非不欲前去，此情非自由。星辰照何處，風雨送涼秋。", "寒鎖空江夢，聲隨黃葉愁。蕭蕭猶未已，早晚去蘋洲。"]'),
('yuding-10','塞上','戴司顏','唐','御定全唐诗','yuding','','[]','空跡晝蒼茫，沙腥古戰場。逢春多霰雪，生計在牛羊。',48,'御定全唐詩/json/690.json','["空跡晝蒼茫，沙腥古戰場。逢春多霰雪，生計在牛羊。", "冷角吹鄉淚，幹榆落夢床。從來山水客，誰謂到漁陽。"]'),
('yuding-11','句','戴司顏','唐','御定全唐诗','yuding','','[]','遠來朝鳳闕，歸去戀元侯。',12,'御定全唐詩/json/690.json','["遠來朝鳳闕，歸去戀元侯。"]'),
('yuding-12','投謝錢武肅','吳仁璧','唐','御定全唐诗','yuding','','[]','東門上相好知音，數盡台前郭隗金。累重雖然容食椹，',40,'御定全唐詩/json/690.json','["東門上相好知音，數盡台前郭隗金。累重雖然容食椹，", "十裏溪光一山月，可堪從此負歸心。"]'),
('yuding-13','客路','吳仁璧','唐','御定全唐诗','yuding','','[]','人寰急景如波委，客路浮雲似蓋輕。',32,'御定全唐詩/json/690.json','["人寰急景如波委，客路浮雲似蓋輕。", "回首故山天外碧，十年無計卻歸耕。"]'),
('yuding-14','南徐題友人郊居','吳仁璧','唐','御定全唐诗','yuding','','[]','門前樵徑連江寺，岸下漁磯系海槎。',32,'御定全唐詩/json/690.json','["門前樵徑連江寺，岸下漁磯系海槎。", "待到秋深好時節，與君長醉隱侯家。"]'),
('yuding-15','讀度人經寄鄭仁表','吳仁璧','唐','御定全唐诗','yuding','','[]','身雖一旦塵中老，名擬三清會裏題。',32,'御定全唐詩/json/690.json','["身雖一旦塵中老，名擬三清會裏題。", "二午九齋餘日在，請君相伴醉如泥。"]'),
('yuding-16','秋日聽僧彈琴','吳仁璧','唐','御定全唐诗','yuding','','[]','金徽玉軫韻泠然，言下浮生指下泉。',32,'御定全唐詩/json/690.json','["金徽玉軫韻泠然，言下浮生指下泉。", "恰稱秋風西北起，一時吹入碧湘煙。"]'),
('yuding-17','賈誼','吳仁璧','唐','御定全唐诗','yuding','','[]','扶持一疏滿遺編，漢陛前頭正少年。',32,'御定全唐詩/json/690.json','["扶持一疏滿遺編，漢陛前頭正少年。", "誰道恃才輕絳灌，卻將惆悵吊湘川。"]'),
('yuding-18','春雪','吳仁璧','唐','御定全唐诗','yuding','','[]','雪霽凝光入坐寒，天明猶自臥袁安。',32,'御定全唐詩/json/690.json','["雪霽凝光入坐寒，天明猶自臥袁安。", "貂裘穿後鶴氅敝，自此風流不足看。"]'),
('yuding-19','衰柳','吳仁璧','唐','御定全唐诗','yuding','','[]','金風漸利露珠團，廣陌長堤黛色殘。',32,'御定全唐詩/json/690.json','["金風漸利露珠團，廣陌長堤黛色殘。", "水殿狂游隋煬帝，一千餘裏可堪看。"]'),
('yuding-20','鳳仙花','吳仁璧','唐','御定全唐诗','yuding','','[]','香紅嫩綠正開時，冷蝶饑蜂兩不知。',32,'御定全唐詩/json/690.json','["香紅嫩綠正開時，冷蝶饑蜂兩不知。", "此際最宜何處看，朝陽初上碧梧枝。"]'),
('yuding-21','金錢花','吳仁璧','唐','御定全唐诗','yuding','','[]','淺絳濃香幾朵勻，日熔金鑄萬家新。',32,'御定全唐詩/json/690.json','["淺絳濃香幾朵勻，日熔金鑄萬家新。", "堪疑劉寵遺芳在，不許山陰父老貧。"]'),
('yuding-22','錢塘鶴','吳仁璧','唐','御定全唐诗','yuding','','[]','人間路靄青天半，鼇岫雲生碧海涯。',32,'御定全唐詩/json/690.json','["人間路靄青天半，鼇岫雲生碧海涯。", "雖抱雕籠密扃鑰，可能長在叔倫家。"]'),
('yuding-23','句','吳仁璧','唐','御定全唐诗','yuding','','[]','為惜苔錢妨換砌，因憐山色旋開尊。',70,'御定全唐詩/json/690.json','["為惜苔錢妨換砌，因憐山色旋開尊。", "高閣煙霞禪客睡，滿城塵土世人忙。", "五龍金角向星斗，三洞玉音愁鬼神。", "蒲草薄裁連蒂白，胭脂濃染半葩紅。（題鶯粟花，"]'),
('yuding-24','奉試麥壟多秀色','汪極','唐','御定全唐诗','yuding','','[]','南陌生岐穗，農家樂事多。塍畦交茂綠，苗實際清和。',48,'御定全唐詩/json/690.json','["南陌生岐穗，農家樂事多。塍畦交茂綠，苗實際清和。", "日布玲瓏影，風翻浩蕩波。來牟知帝力，含哺有衢歌。"]'),
('yuding-25','下第戲狀元崔昭緯','張曙1','唐','御定全唐诗','yuding','','[]','千里江山陪驥尾，五更風水失龍鱗。',32,'御定全唐詩/json/690.json','["千里江山陪驥尾，五更風水失龍鱗。", "昨夜浣花溪上雨，綠楊芳草為何人。"]'),
('yuding-26','贈天臺王處士','林嵩','唐','御定全唐诗','yuding','','[]','深隱天臺不記秋，琴台長別一何愁。茶煙岩外雲初起，',40,'御定全唐詩/json/690.json','["深隱天臺不記秋，琴台長別一何愁。茶煙岩外雲初起，", "赤城不掩高宗夢，寧久懸冠枕瀑流。"]'),
('yuding-0','春宮怨','杜荀鶴','唐','御定全唐诗','yuding','','[]','早被嬋娟誤，欲妝臨鏡慵。承恩不在貌，教妾若為容。',48,'御定全唐詩/json/691.json','["早被嬋娟誤，欲妝臨鏡慵。承恩不在貌，教妾若為容。", "風暖鳥聲碎，日高花影重。年年越溪女，相憶采芙蓉。"]'),
('yuding-1','訪道者不遇','杜荀鶴','唐','御定全唐诗','yuding','','[]','寂寂白雲門，尋真不遇真。只應松上鶴，便是洞中人。',48,'御定全唐詩/json/691.json','["寂寂白雲門，尋真不遇真。只應松上鶴，便是洞中人。", "藥圃花香異，沙泉鹿跡新。題詩留姓字，他日此相親。"]'),
('yuding-2','送人游吳','杜荀鶴','唐','御定全唐诗','yuding','','[]','君到姑蘇見，人家盡枕河。古宮閑地少，水港小橋多。',48,'御定全唐詩/json/691.json','["君到姑蘇見，人家盡枕河。古宮閑地少，水港小橋多。", "夜市賣菱藕，春船載綺羅。遙知未眠月，鄉思在漁歌。"]'),
('yuding-3','送陳昈歸麻川','杜荀鶴','唐','御定全唐诗','yuding','','[]','麻川清見底，似入武陵溪。兩岸山相向，三春鳥亂啼。',48,'御定全唐詩/json/691.json','["麻川清見底，似入武陵溪。兩岸山相向，三春鳥亂啼。", "酒旗和柳動，僧屋與雲齊。即此吾鄉路，懷君夢不迷。"]'),
('yuding-4','出山','杜荀鶴','唐','御定全唐诗','yuding','','[]','病眼看春榜，文場公道開。朋人登第盡，白髮出山來。',48,'御定全唐詩/json/691.json','["病眼看春榜，文場公道開。朋人登第盡，白髮出山來。", "處世曾無過，惟天合是媒。長安不覺遠，期遂一名回。"]'),
('yuding-5','浙中逢詩友','杜荀鶴','唐','御定全唐诗','yuding','','[]','到處有同人，多為賦與文。詩中難得友，湖畔喜逢君。',48,'御定全唐詩/json/691.json','["到處有同人，多為賦與文。詩中難得友，湖畔喜逢君。", "凍把城根雪，風開嶽面雲。苦吟吟不足，爭忍話離群。"]'),
('yuding-6','送友游吳越','杜荀鶴','唐','御定全唐诗','yuding','','[]','去越從吳過，吳疆與越連。有園多種橘，無水不生蓮。',48,'御定全唐詩/json/691.json','["去越從吳過，吳疆與越連。有園多種橘，無水不生蓮。", "夜市橋邊火，春風寺外船。此中偏重客，君去必經年。"]'),
('yuding-7','出常山界使回有寄','杜荀鶴','唐','御定全唐诗','yuding','','[]','自小即南北，未如今日離。封疆初盡處，人使卻回時。',48,'御定全唐詩/json/691.json','["自小即南北，未如今日離。封疆初盡處，人使卻回時。", "開口有所忌，此心無以為。行行複垂淚，不稱是男兒。"]'),
('yuding-8','經廢宅','杜荀鶴','唐','御定全唐诗','yuding','','[]','人生當貴盛，修德可延之。不慮有今日，爭教無破時。',48,'御定全唐詩/json/691.json','["人生當貴盛，修德可延之。不慮有今日，爭教無破時。", "蘚斑題字壁，花發帶巢枝。何況蒿原上，荒墳與折碑。"]'),
('yuding-9','登天臺寺','杜荀鶴','唐','御定全唐诗','yuding','','[]','一到天臺寺，高低景旋生。共僧岩上坐，見客海邊行。',48,'御定全唐詩/json/691.json','["一到天臺寺，高低景旋生。共僧岩上坐，見客海邊行。", "野色人耕破，山根浪打鳴。忙時向閑處，不覺有閒情。"]'),
('yuding-10','途中春','杜荀鶴','唐','御定全唐诗','yuding','','[]','馬上覽春色，丈夫慚淚垂。一生看卻老，五字未逢知。',48,'御定全唐詩/json/691.json','["馬上覽春色，丈夫慚淚垂。一生看卻老，五字未逢知。", "酒力不能久，愁根無可醫。明年到今日，公道與誰期。"]'),
('yuding-11','入關曆陽道中卻寄舍弟','杜荀鶴','唐','御定全唐诗','yuding','','[]','求名日苦辛，日望日榮親。落葉山中路，秋霖馬上人。',48,'御定全唐詩/json/691.json','["求名日苦辛，日望日榮親。落葉山中路，秋霖馬上人。", "晨昏知汝道，詩酒衛吾身。自笑拋麋鹿，長安擬醉春。"]'),
('yuding-12','贈歐陽明府','杜荀鶴','唐','御定全唐诗','yuding','','[]','賢宰宰斯邑，政聞閭里間。都緣民訟少，長覺吏徒閑。',48,'御定全唐詩/json/691.json','["賢宰宰斯邑，政聞閭里間。都緣民訟少，長覺吏徒閑。", "帆落樽前浦，鐘鳴枕上山。回舟卻惆悵，數宿釣魚灣。"]'),
('yuding-13','贈臨上人','杜荀鶴','唐','御定全唐诗','yuding','','[]','不計禪兼律，終須入悟門。解空非有自，所得是無言。',48,'御定全唐詩/json/691.json','["不計禪兼律，終須入悟門。解空非有自，所得是無言。", "眼豁浮生夢，心澄大道源。今來習師者，多鎖教中猿。"]'),
('yuding-14','題戰島僧居','杜荀鶴','唐','御定全唐诗','yuding','','[]','師愛無塵地，江心島上居。接船求化慣，登陸赴齋疏。',48,'御定全唐詩/json/691.json','["師愛無塵地，江心島上居。接船求化慣，登陸赴齋疏。", "載土春栽樹，拋生日餧魚。入雲蕭帝寺，畢竟欲何如。"]'),
('yuding-15','別衡州牧','杜荀鶴','唐','御定全唐诗','yuding','','[]','朝別使君門，暮投江上村。從來無舊分，臨去望何恩。',48,'御定全唐詩/json/691.json','["朝別使君門，暮投江上村。從來無舊分，臨去望何恩。", "行計自不定，此心誰與論。秋猿叫寒月，只欲斷人魂。"]'),
('yuding-16','送人游江南','杜荀鶴','唐','御定全唐诗','yuding','','[]','滿酌勸君酒，勸君君莫辭。能禁幾度別，即到白頭時。',48,'御定全唐詩/json/691.json','["滿酌勸君酒，勸君君莫辭。能禁幾度別，即到白頭時。", "晚岫無雲蔽，春帆有燕隨。男兒兩行淚，不欲等閒垂。"]'),
('yuding-17','游茅山','杜荀鶴','唐','御定全唐诗','yuding','','[]','步步入山門，仙家鳥徑分。漁樵不到處，麋鹿自成群。',48,'御定全唐詩/json/691.json','["步步入山門，仙家鳥徑分。漁樵不到處，麋鹿自成群。", "石面迸出水，松頭穿破雲。道人星月下，相次禮茅君。"]'),
('yuding-18','讀友人詩卷','杜荀鶴','唐','御定全唐诗','yuding','','[]','冰齒味瑤軸，只應神鬼知。坐當群靜後，吟到月沈時。',48,'御定全唐詩/json/691.json','["冰齒味瑤軸，只應神鬼知。坐當群靜後，吟到月沈時。", "雪峽猿聲健，風檉鶴立危。篇篇一字字，誰複更言詩。"]'),
('yuding-19','寄從叔','杜荀鶴','唐','御定全唐诗','yuding','','[]','三族不當路，長年猶布衣。苦吟天與性，直道世將非。',48,'御定全唐詩/json/691.json','["三族不當路，長年猶布衣。苦吟天與性，直道世將非。", "雁夜愁癡坐，漁鄉老憶歸。為儒皆可立，自是拙時機。"]'),
('yuding-20','寄李溥','杜荀鶴','唐','御定全唐诗','yuding','','[]','如我如君者，不妨身晚成。但從時輩笑，自得古人情。',48,'御定全唐詩/json/691.json','["如我如君者，不妨身晚成。但從時輩笑，自得古人情。", "共莫更初志，俱期立後名。男兒且如此，何用歎平生。"]'),
('yuding-21','郊居即事投李給事','杜荀鶴','唐','御定全唐诗','yuding','','[]','無祿奉晨昏，閒居幾度春。江湖苦吟士，天地最窮人。',48,'御定全唐詩/json/691.json','["無祿奉晨昏，閒居幾度春。江湖苦吟士，天地最窮人。", "書劍同三友，蓬蒿外四鄰。相知不相薦，何以自謀身。"]'),
('yuding-22','寄詩友','杜荀鶴','唐','御定全唐诗','yuding','','[]','別來春又春，相憶喜相親。與我為同志，如君能幾人。',48,'御定全唐詩/json/691.json','["別來春又春，相憶喜相親。與我為同志，如君能幾人。", "何時吟得力，漸老事關身。惟有前溪水，年年濯客塵。"]'),
('yuding-23','題田翁家','杜荀鶴','唐','御定全唐诗','yuding','','[]','田翁真快活，婚嫁不離村。州縣供輸罷，追隨鼓笛喧。',48,'御定全唐詩/json/691.json','["田翁真快活，婚嫁不離村。州縣供輸罷，追隨鼓笛喧。", "盤飧同老少，家計共田園。自說身無事，應官有子孫。"]'),
('yuding-24','長安冬日','杜荀鶴','唐','御定全唐诗','yuding','','[]','近臘饒風雪，閒房凍坐時。書生教到此，天意轉難知。',48,'御定全唐詩/json/691.json','["近臘饒風雪，閒房凍坐時。書生教到此，天意轉難知。", "吟苦猿三叫，形枯柏一枝。還應公道在，未忍與山期。"]'),
('yuding-25','霽後登唐興寺水閣','杜荀鶴','唐','御定全唐诗','yuding','','[]','一雨三秋色，蕭條古寺間。無端登水閣，有處似家山。',48,'御定全唐詩/json/691.json','["一雨三秋色，蕭條古寺間。無端登水閣，有處似家山。", "白日生新事，何時得暫閑。將知老僧意，未必戀松關。"]'),
('yuding-26','山中寄友人','杜荀鶴','唐','御定全唐诗','yuding','','[]','深山多隙地，無力及耕桑。不是營生拙，都緣覓句忙。',48,'御定全唐詩/json/691.json','["深山多隙地，無力及耕桑。不是營生拙，都緣覓句忙。", "破窗風翳燭，穿屋月侵床。吾友應相笑，辛勤道未光。"]'),
('yuding-27','自述','杜荀鶴','唐','御定全唐诗','yuding','','[]','四海欲行遍，不知終遇誰。用心常合道，出語或傷時。',48,'御定全唐詩/json/691.json','["四海欲行遍，不知終遇誰。用心常合道，出語或傷時。", "擬作閒人老，慚無識者嗤。如今已無計，只得苦於詩。"]'),
('yuding-28','題江山寺','杜荀鶴','唐','御定全唐诗','yuding','','[]','江上山頭寺，景留吟客船。遍遊銷一日，重到是何年。',48,'御定全唐詩/json/691.json','["江上山頭寺，景留吟客船。遍遊銷一日，重到是何年。", "沙鳥多翹足，岩僧半露肩。為詩我語澀，喜此得終篇。"]'),
('yuding-29','秋日旅舍臥病呈所知','杜荀鶴','唐','御定全唐诗','yuding','','[]','秋色上庭枝，愁懷切向誰。青雲無勢日，華髮有狂時。',48,'御定全唐詩/json/691.json','["秋色上庭枝，愁懷切向誰。青雲無勢日，華髮有狂時。", "枕上聞風雨，江南系別離。如何吟到此，此道不聞知。"]'),
('yuding-30','秋宿山館','杜荀鶴','唐','御定全唐诗','yuding','','[]','山館坐待曉，夜長吟役神。斜風吹敗葉，寒燭照愁人。',48,'御定全唐詩/json/691.json','["山館坐待曉，夜長吟役神。斜風吹敗葉，寒燭照愁人。", "蘊蓄天然性，澆訛世惡真。男兒出門志，不獨為謀身。"]'),
('yuding-31','贈老僧','杜荀鶴','唐','御定全唐诗','yuding','','[]','眾僧尊夏臘，靈岳遍曾登。度水手中杖，行山溪畔藤。',48,'御定全唐詩/json/691.json','["眾僧尊夏臘，靈岳遍曾登。度水手中杖，行山溪畔藤。", "心空默是印，眉白雪為棱。自得巡方道，棲禪老未能。"]'),
('yuding-32','別舍弟','杜荀鶴','唐','御定全唐诗','yuding','','[]','欲住住不得，出門天氣秋。惟知偷拭淚，不忍更回頭。',48,'御定全唐詩/json/691.json','["欲住住不得，出門天氣秋。惟知偷拭淚，不忍更回頭。", "此日只愁老，況身方遠遊。孤寒將五字，何以動諸侯。"]'),
('yuding-33','雪中別詩友','杜荀鶴','唐','御定全唐诗','yuding','','[]','酒寒無小戶，請滿酌行杯。若待雪消去，自然春到來。',48,'御定全唐詩/json/691.json','["酒寒無小戶，請滿酌行杯。若待雪消去，自然春到來。", "出城人跡少，向暮鳥聲哀。未遇應關命，侯門處處開。"]'),
('yuding-34','題嶽麓寺','杜荀鶴','唐','御定全唐诗','yuding','','[]','一簇楚江山，江山勝此難。覓人來畫取，到處得吟看。',48,'御定全唐詩/json/691.json','["一簇楚江山，江山勝此難。覓人來畫取，到處得吟看。", "鶴隱松聲盡，魚沈檻影寒。自知心未了，閒話亦多端。"]'),
('yuding-35','懷廬岳書齋','杜荀鶴','唐','御定全唐诗','yuding','','[]','長憶在廬嶽，免低塵土顏。煮茶窗底水，采藥屋頭山。',48,'御定全唐詩/json/691.json','["長憶在廬嶽，免低塵土顏。煮茶窗底水，采藥屋頭山。", "是境皆遊遍，誰人不羨閑。無何一名系，引出白雲間。"]'),
('yuding-36','題唐興寺小松','杜荀鶴','唐','御定全唐诗','yuding','','[]','雖小天然別，難將眾木同。侵僧半窗月，向客滿襟風。',48,'御定全唐詩/json/691.json','["雖小天然別，難將眾木同。侵僧半窗月，向客滿襟風。", "枝拂行苔鶴，聲分叫砌蟲。如今未堪看，須是雪霜中。"]'),
('yuding-37','與友人話別','杜荀鶴','唐','御定全唐诗','yuding','','[]','客路行多少，幹人無易顏。未成終老計，難致此身閑。',48,'御定全唐詩/json/691.json','["客路行多少，幹人無易顏。未成終老計，難致此身閑。", "月兔走入海，日烏飛出山。流年留不得，半在別離間。"]'),
('yuding-38','贈廬嶽隱者','杜荀鶴','唐','御定全唐诗','yuding','','[]','自見來如此，未嘗離洞門。結茅遮雨雪，采藥給晨昏。',48,'御定全唐詩/json/691.json','["自見來如此，未嘗離洞門。結茅遮雨雪，采藥給晨昏。", "古樹藤纏殺，春泉鹿過渾。悠悠無一事，不似屬乾坤。"]'),
('yuding-39','懷紫閣隱者','杜荀鶴','唐','御定全唐诗','yuding','','[]','紫閣白雲端，雲中有地仙。未歸蓬島上，猶隱國門前。',48,'御定全唐詩/json/691.json','["紫閣白雲端，雲中有地仙。未歸蓬島上，猶隱國門前。", "洞口人無跡，花陰鹿自眠。焚香賦詩罷，星月冷遙天。"]'),
('yuding-40','題會上人院','杜荀鶴','唐','御定全唐诗','yuding','','[]','鼓角城中寺，師居日得閒。必能行大道，何用在深山。',48,'御定全唐詩/json/691.json','["鼓角城中寺，師居日得閒。必能行大道，何用在深山。", "破衲新添線，空門夜不關。心知與眼見，終取到無間。"]'),
('yuding-41','送黃補闕南遷','杜荀鶴','唐','御定全唐诗','yuding','','[]','得罪非天意，分明謫去身。一心貪諫主，開口不防人。',48,'御定全唐詩/json/691.json','["得罪非天意，分明謫去身。一心貪諫主，開口不防人。", "自古有遷客，何朝無直臣。喧然公論在，難滯楚南春。"]'),
('yuding-42','送賓貢登第後歸海東','杜荀鶴','唐','御定全唐诗','yuding','','[]','歸捷中華第，登船鬢未絲。直應天上桂，別有海東枝。',48,'御定全唐詩/json/691.json','["歸捷中華第，登船鬢未絲。直應天上桂，別有海東枝。", "國界波窮處，鄉心日出時。西風送君去，莫慮到家遲。"]'),
('yuding-43','近試投所知','杜荀鶴','唐','御定全唐诗','yuding','','[]','白髮隨梳落，吟懷說向誰。敢辭成事晚，自是出山遲。',48,'御定全唐詩/json/691.json','["白髮隨梳落，吟懷說向誰。敢辭成事晚，自是出山遲。", "擬動如浮海，凡言似課詩。終身事知己，此外複何為。"]'),
('yuding-44','送友人牧江州','杜荀鶴','唐','御定全唐诗','yuding','','[]','本國兵戈後，難官在此時。遠分天子命，深要使君知。',48,'御定全唐詩/json/691.json','["本國兵戈後，難官在此時。遠分天子命，深要使君知。", "但遂生靈願，當應雨露隨。江山勝他郡，閑賦庾樓詩。"]'),
('yuding-45','辭座主侍郎','杜荀鶴','唐','御定全唐诗','yuding','','[]','一飯尚懷感，況攀高桂枝。此恩無報處，故國遠歸時。',48,'御定全唐詩/json/691.json','["一飯尚懷感，況攀高桂枝。此恩無報處，故國遠歸時。", "只恐兵戈隔，再趨門館遲。茅堂拜親後，特地淚雙垂。"]'),
('yuding-46','別從叔','杜荀鶴','唐','御定全唐诗','yuding','','[]','立馬不忍上，醉醒天氣寒。都緣在門易，直似別家難。',48,'御定全唐詩/json/691.json','["立馬不忍上，醉醒天氣寒。都緣在門易，直似別家難。", "世路既如此，客心須自寬。江村亦饑凍，爭及問長安。"]'),
('yuding-47','送人南游','杜荀鶴','唐','御定全唐诗','yuding','','[]','凡游南國者，未有不蹉跎。到海路難盡，掛帆人更多。',48,'御定全唐詩/json/691.json','["凡游南國者，未有不蹉跎。到海路難盡，掛帆人更多。", "潮沙分象跡，花洞響蠻歌。縱有投文處，於君能幾何。"]'),
('yuding-48','經賈島墓','杜荀鶴','唐','御定全唐诗','yuding','','[]','謫宦自麻衣，銜冤至死時。山根三尺墓，人口數聯詩。',48,'御定全唐詩/json/691.json','["謫宦自麻衣，銜冤至死時。山根三尺墓，人口數聯詩。", "仙桂終無分，皇天似有私。暗松風雨夜，空使老猿悲。"]'),
('yuding-49','秋夜晚泊','杜荀鶴','唐','御定全唐诗','yuding','','[]','一望一蒼然，蕭騷起暮天。遠山橫落日，歸鳥度平川。',48,'御定全唐詩/json/691.json','["一望一蒼然，蕭騷起暮天。遠山橫落日，歸鳥度平川。", "家是去秋別，月當今夕圓。漁翁似相伴，徹曉葦叢邊。"]'),
('yuding-50','送舍弟','杜荀鶴','唐','御定全唐诗','yuding','','[]','我受羈棲慣，客情方細知。好看前路事，不比在家時。',48,'御定全唐詩/json/691.json','["我受羈棲慣，客情方細知。好看前路事，不比在家時。", "勉汝言須記，聞人善即師。旅中無廢業，時作一篇詩。"]'),
('yuding-51','將歸山逢友人','杜荀鶴','唐','御定全唐诗','yuding','','[]','儒為君子儒，儒道不妨孤。白髮多生矣，青山可住乎。',48,'御定全唐詩/json/691.json','["儒為君子儒，儒道不妨孤。白髮多生矣，青山可住乎。", "徉狂寧是事，巧達又非夫。只此平生願，他人肯信無。"]'),
('yuding-52','經九華費征君墓','杜荀鶴','唐','御定全唐诗','yuding','','[]','凡吊先生者，多傷荊棘間。不知三尺墓，高卻九華山。',48,'御定全唐詩/json/691.json','["凡吊先生者，多傷荊棘間。不知三尺墓，高卻九華山。", "天地有何外，子孫無亦閑。當時若征起，未必得身還。"]'),
('yuding-53','溪居叟','杜荀鶴','唐','御定全唐诗','yuding','','[]','溪翁居靜處，溪鳥入門飛。早起釣魚去，夜深乘月歸。',48,'御定全唐詩/json/691.json','["溪翁居靜處，溪鳥入門飛。早起釣魚去，夜深乘月歸。", "見君無事老，覺我有求非。不說風霜苦，三冬一草衣。"]'),
('yuding-54','與友人對酒吟','杜荀鶴','唐','御定全唐诗','yuding','','[]','憑君滿酌酒，聽我醉中吟。客路如天遠，侯門似海深。',48,'御定全唐詩/json/691.json','["憑君滿酌酒，聽我醉中吟。客路如天遠，侯門似海深。", "新墳侵古道，白髮戀黃金。共有人間事，須懷濟物心。"]'),
('yuding-55','送僧','杜荀鶴','唐','御定全唐诗','yuding','','[]','道了亦未了，言閑今且閑。從來無住處，此去向何山。',48,'御定全唐詩/json/691.json','["道了亦未了，言閑今且閑。從來無住處，此去向何山。", "片石樹陰下，斜陽潭影間。請師留偈別，恐不到人寰。"]'),
('yuding-56','送九華道士游茅山','杜荀鶴','唐','御定全唐诗','yuding','','[]','忽起地仙興，飄然出舊山。於身無切事，在世有餘閑。',48,'御定全唐詩/json/691.json','["忽起地仙興，飄然出舊山。於身無切事，在世有餘閑。", "日月浮生外，乾坤大醉間。故園華表上，誰得見君還。"]'),
('yuding-57','寄舍弟','杜荀鶴','唐','御定全唐诗','yuding','','[]','世亂信難通，鄉心日萬重。弟兄皆向善，天地合相容。',48,'御定全唐詩/json/691.json','["世亂信難通，鄉心日萬重。弟兄皆向善，天地合相容。", "大野陰雲重，連城殺氣濃。家山白雲裏，臥得最高峰。"]'),
('yuding-58','下第投所知','杜荀鶴','唐','御定全唐诗','yuding','','[]','若以名場內，誰無一軸詩。縱饒生白髮，豈敢怨明時。',48,'御定全唐詩/json/691.json','["若以名場內，誰無一軸詩。縱饒生白髮，豈敢怨明時。", "知己雖然切，春官未必私。寧教讀書眼，不有看花期。"]'),
('yuding-59','寄顧雲','杜荀鶴','唐','御定全唐诗','yuding','','[]','省得前年別，蘋洲旅館中。亂離身不定，彼此信難通。',48,'御定全唐詩/json/691.json','["省得前年別，蘋洲旅館中。亂離身不定，彼此信難通。", "侯國兵雖斂，吾鄉業已空。秋來憶君夢，夜夜逐征鴻。"]'),
('yuding-60','贈宣城麋明府','杜荀鶴','唐','御定全唐诗','yuding','','[]','天下為官者，無君一軸詩。數聯同我得，當代遇誰知。',48,'御定全唐詩/json/691.json','["天下為官者，無君一軸詩。數聯同我得，當代遇誰知。", "年齒吟將老，生涯說可悲。何當拋手板，鄰隱過危時。"]'),
('yuding-61','望遠','杜荀鶴','唐','御定全唐诗','yuding','','[]','門前通大道，望遠上高臺。落日人行盡，窮邊信不來。',48,'御定全唐詩/json/691.json','["門前通大道，望遠上高臺。落日人行盡，窮邊信不來。", "還聞戰得勝，未見敕招回。卻入機中坐，新愁織不開。"]'),
('yuding-62','冬末投長沙裴侍郎','杜荀鶴','唐','御定全唐诗','yuding','','[]','欲露塵中事，其如不易言。家山一離別，草樹匝春暄。',48,'御定全唐詩/json/691.json','["欲露塵中事，其如不易言。家山一離別，草樹匝春暄。", "吹夢風天角，啼愁雪嶽猿。佇思心覺滿，何以遠門軒。"]'),
('yuding-63','贈秋浦金明府長','杜荀鶴','唐','御定全唐诗','yuding','','[]','倚郭難為宰，非君即有私。惟憑野老口，不立政聲碑。',48,'御定全唐詩/json/691.json','["倚郭難為宰，非君即有私。惟憑野老口，不立政聲碑。", "苦甚求名日，貧于未選時。溪山竟如此，利得且吟詩。"]'),
('yuding-64','和高秘書早春對雪登樓見寄之什','杜荀鶴','唐','御定全唐诗','yuding','','[]','天有惜花意，恐花開染塵。先教微雪下，始放滿城春。',48,'御定全唐詩/json/691.json','["天有惜花意，恐花開染塵。先教微雪下，始放滿城春。", "且醉登樓客，重期出郭人。因酬郢中律，霜鬢數莖新。"]'),
('yuding-65','亂後山中作','杜荀鶴','唐','御定全唐诗','yuding','','[]','自從天下亂，日晚別庭闈。兄弟團圞樂，羈孤遠近歸。',48,'御定全唐詩/json/691.json','["自從天下亂，日晚別庭闈。兄弟團圞樂，羈孤遠近歸。", "文章甘世薄，耕種喜山肥。直待中興後，方應出隱扉。"]'),
('yuding-66','旅寓書事','杜荀鶴','唐','御定全唐诗','yuding','','[]','日日驚身事，淒淒欲斷魂。時清不自立，發白傍誰門。',48,'御定全唐詩/json/691.json','["日日驚身事，淒淒欲斷魂。時清不自立，發白傍誰門。", "中路殘秋雨，空山一夜猿。公卿得見面，懷抱細難言。"]'),
('yuding-67','舟行晚泊江上寺','杜荀鶴','唐','御定全唐诗','yuding','','[]','久勞風水上，禪客喜相依。掛衲雖無分，修心未覺非。',48,'御定全唐詩/json/691.json','["久勞風水上，禪客喜相依。掛衲雖無分，修心未覺非。", "日沈山虎出，鐘動寺禽歸。月上潮平後，談空漸入微。"]'),
('yuding-68','長林山中聞賊退寄孟明府','杜荀鶴','唐','御定全唐诗','yuding','','[]','一縣今如此，殘民數不多。也知賢宰切，爭奈亂兵何。',48,'御定全唐詩/json/691.json','["一縣今如此，殘民數不多。也知賢宰切，爭奈亂兵何。", "皆自干戈達，咸思雨露和。應憐住山者，頭白未登科。"]'),
('yuding-69','泗上客思','杜荀鶴','唐','御定全唐诗','yuding','','[]','痛飲複高歌，愁終不奈何。家山隨日遠，身事逐年多。',48,'御定全唐詩/json/691.json','["痛飲複高歌，愁終不奈何。家山隨日遠，身事逐年多。", "沒雁雲橫楚，兼蟬柳夾河。此心閑未得，到處被詩磨。"]'),
('yuding-70','寄同人','杜荀鶴','唐','御定全唐诗','yuding','','[]','盡與貧為患，唯餘即不然。四方無靜處，百口度荒年。',48,'御定全唐詩/json/691.json','["盡與貧為患，唯餘即不然。四方無靜處，百口度荒年。", "白髮生閒事，新詩出數聯。時情竟如此，不免卻歸田。"]'),
('yuding-71','下第出關投鄭拾遺','杜荀鶴','唐','御定全唐诗','yuding','','[]','丹霄桂有枝，未折未為遲。況是孤寒士，兼行苦澀詩。',48,'御定全唐詩/json/691.json','["丹霄桂有枝，未折未為遲。況是孤寒士，兼行苦澀詩。", "杏園人醉日，關路獨歸時。更蔔深知意，將來擬薦誰。"]'),
('yuding-72','塞上','杜荀鶴','唐','御定全唐诗','yuding','','[]','草白河冰合，蕃戎出掠頻。戍樓三號火，探馬一條塵。',48,'御定全唐詩/json/691.json','["草白河冰合，蕃戎出掠頻。戍樓三號火，探馬一條塵。", "戰士風霜老，將軍雨露新。封侯不由此，何以慰征人。"]'),
('yuding-73','別敬侍郎','杜荀鶴','唐','御定全唐诗','yuding','','[]','交道有寒暑，在人無古今。與君中夜話，盡我一生心。',48,'御定全唐詩/json/691.json','["交道有寒暑，在人無古今。與君中夜話，盡我一生心。", "所向未得志，豈惟空解吟。何當重相見，舊隱白雲深。"]'),
('yuding-74','送青陽李明府','杜荀鶴','唐','御定全唐诗','yuding','','[]','善政無慚色，吟歸似等閒。惟將六幅絹，寫得九華山。',48,'御定全唐詩/json/691.json','["善政無慚色，吟歸似等閒。惟將六幅絹，寫得九華山。", "求理頭空白，離京債未還。仍聞猿與鶴，都在一船間。"]'),
('yuding-75','將遊湘湖有作','杜荀鶴','唐','御定全唐诗','yuding','','[]','一家相別意，不得不潸然。遠作南方客，初登上水船。',48,'御定全唐詩/json/691.json','["一家相別意，不得不潸然。遠作南方客，初登上水船。", "岳鐘思冷夢，湘月少殘篇。便有歸來計，風波亦來年。"]'),
('yuding-76','送姚庭珪','杜荀鶴','唐','御定全唐诗','yuding','','[]','脫衣將換酒，對酌話何之。雨後秋蕭索，天涯晚別離。',48,'御定全唐詩/json/691.json','["脫衣將換酒，對酌話何之。雨後秋蕭索，天涯晚別離。", "人生無此恨，鬢色不成絲。未得重相見，看君馬上詩。"]'),
('yuding-77','投李大夫','杜荀鶴','唐','御定全唐诗','yuding','','[]','自小僻於詩，篇篇恨不奇。苦吟無暇日，華髮有多時。',48,'御定全唐詩/json/691.json','["自小僻於詩，篇篇恨不奇。苦吟無暇日，華髮有多時。", "進取門難見，升沈命未知。秋風夜來急，還恐到京遲。"]'),
('yuding-78','貽裏中同志','杜荀鶴','唐','御定全唐诗','yuding','','[]','鄉里為儒者，唯君見我心。詩書常共讀，雨雪亦相尋。',48,'御定全唐詩/json/691.json','["鄉里為儒者，唯君見我心。詩書常共讀，雨雪亦相尋。", "貧賤志氣在，子孫交契深。古人猶晚達，況未鬢霜侵。"]'),
('yuding-79','江上送韋彖先輩','杜荀鶴','唐','御定全唐诗','yuding','','[]','不易為離抱，江天即見鴻。暮帆何處落，涼月與誰同。',48,'御定全唐詩/json/691.json','["不易為離抱，江天即見鴻。暮帆何處落，涼月與誰同。", "木葉新霜後，漁燈夜浪中。時難慎行止，吾道利於窮。"]'),
('yuding-80','維揚逢詩友張喬','杜荀鶴','唐','御定全唐诗','yuding','','[]','天下方多事，逢君得話詩。直應吾道在，未覺國風衰。',48,'御定全唐詩/json/691.json','["天下方多事，逢君得話詩。直應吾道在，未覺國風衰。", "生計吟消日，人情醉過時。雅篇三百首，留作後來師。"]'),
('yuding-81','秋晨有感','杜荀鶴','唐','御定全唐诗','yuding','','[]','木葉落時節，旅人初夢驚。鐘才枕上盡，事已眼前生。',48,'御定全唐詩/json/691.json','["木葉落時節，旅人初夢驚。鐘才枕上盡，事已眼前生。", "吟發不長黑，世交無久情。且將公道約，未忍便歸耕。"]'),
('yuding-82','秋日山中寄李處士','杜荀鶴','唐','御定全唐诗','yuding','','[]','吾輩道何窮，寒山細雨中。兒童書懶讀，果栗樹將空。',48,'御定全唐詩/json/691.json','["吾輩道何窮，寒山細雨中。兒童書懶讀，果栗樹將空。", "言論關時務，篇章見國風。升平猶可用，應不廢為公。"]'),
('yuding-83','晚泊金陵水亭','杜荀鶴','唐','御定全唐诗','yuding','','[]','江亭當廢國，秋景倍蕭騷。夕照殘荒壘，寒潮漲古濠。',48,'御定全唐詩/json/691.json','["江亭當廢國，秋景倍蕭騷。夕照殘荒壘，寒潮漲古濠。", "就田看鶴劣，隔水見僧高。無限前朝事，醒吟易覺勞。"]'),
('yuding-84','錢塘別羅隱','杜荀鶴','唐','御定全唐诗','yuding','','[]','故國看看遠，前程計在誰。五更聽角後，一葉渡江時。',48,'御定全唐詩/json/691.json','["故國看看遠，前程計在誰。五更聽角後，一葉渡江時。", "吾道天寧喪，人情日可疑。西陵向西望，雙淚為君垂。"]'),
('yuding-85','山中貽同志','杜荀鶴','唐','御定全唐诗','yuding','','[]','君貧我亦貧，為善喜為鄰。到老如今日，無心愧古人。',48,'御定全唐詩/json/691.json','["君貧我亦貧，為善喜為鄰。到老如今日，無心愧古人。", "閉門非傲世，守道是謀身。別有同山者，其如未可親。"]'),
('yuding-86','秋日懷九華舊居','杜荀鶴','唐','御定全唐诗','yuding','','[]','吾道在五字，吾身甯陸沈。涼生中夜雨，病起故山心。',48,'御定全唐詩/json/691.json','["吾道在五字，吾身甯陸沈。涼生中夜雨，病起故山心。", "燭共寒酸影，蛩添苦楚吟。何當遂歸去，一徑入松林。"]'),
('yuding-87','江岸秋思','杜荀鶴','唐','御定全唐诗','yuding','','[]','驅馬傍江行，鄉愁步步生。舉鞭揮柳色，隨手失蟬聲。',48,'御定全唐詩/json/691.json','["驅馬傍江行，鄉愁步步生。舉鞭揮柳色，隨手失蟬聲。", "秋稼緣長道，寒雲約古城。家貧遇豐歲，無地可歸耕。"]'),
('yuding-88','哭劉德仁','杜荀鶴','唐','御定全唐诗','yuding','','[]','賈島還如此，生前不見春。豈能詩苦者，便是命羈人。',48,'御定全唐詩/json/691.json','["賈島還如此，生前不見春。豈能詩苦者，便是命羈人。", "家事因吟失，時情礙國親。多應銜恨骨，千古不為塵。"]'),
('yuding-89','經青山吊李翰林','杜荀鶴','唐','御定全唐诗','yuding','','[]','何為先生死，先生道日新。青山明月夜，千古一詩人。',48,'御定全唐詩/json/691.json','["何為先生死，先生道日新。青山明月夜，千古一詩人。", "天地空銷骨，聲名不傍身。誰移耒陽塚，來此作吟鄰。"]'),
('yuding-90','下第東歸別友人','杜荀鶴','唐','御定全唐诗','yuding','','[]','不得同君住，當春別帝鄉。年華落第老，岐路出關長。',48,'御定全唐詩/json/691.json','["不得同君住，當春別帝鄉。年華落第老，岐路出關長。", "芳草緣流水，殘花向夕陽。懷親暫歸去，非是釣滄浪。"]'),
('yuding-91','秋宿詩僧雲英房因贈','杜荀鶴','唐','御定全唐诗','yuding','','[]','賈島憐無可，都緣數句詩。君雖是後輩，我謂過當時。',48,'御定全唐詩/json/691.json','["賈島憐無可，都緣數句詩。君雖是後輩，我謂過當時。", "溪浪和星動，松陰帶鶴移。同吟到明坐，此道淡誰知。"]'),
('yuding-92','送人宰吳縣','杜荀鶴','唐','御定全唐诗','yuding','','[]','海漲兵荒後，為官合動情。字人無異術，至論不如清。',48,'御定全唐詩/json/691.json','["海漲兵荒後，為官合動情。字人無異術，至論不如清。", "草履隨船賣，綾梭隔水鳴。唯持古人意，千里贈君行。"]'),
('yuding-93','讀友人詩','杜荀鶴','唐','御定全唐诗','yuding','','[]','君詩通大雅，吟覺古風生。外卻浮華景，中含教化情。',48,'御定全唐詩/json/691.json','["君詩通大雅，吟覺古風生。外卻浮華景，中含教化情。", "名應高日月，道可潤公卿。莫以孤寒恥，孤寒達更榮。"]'),
('yuding-94','登山寺','杜荀鶴','唐','御定全唐诗','yuding','','[]','山半一山寺，野人秋日登。就中偏愛石，獨上最高層。',48,'御定全唐詩/json/691.json','["山半一山寺，野人秋日登。就中偏愛石，獨上最高層。", "有果猿攀樹，無齋鴿看僧。儒門自多事，來此複何能。"]'),
('yuding-95','辭九江李郎中入關','杜荀鶴','唐','御定全唐诗','yuding','','[]','帝裏無相識，何門跡可親。願開言重口，薦與分深人。',48,'御定全唐詩/json/691.json','["帝裏無相識，何門跡可親。願開言重口，薦與分深人。", "卷許新詩出，家憐舊業貧。今從九江去，應免更迷津。"]'),
('yuding-96','江南逢李先輩','杜荀鶴','唐','御定全唐诗','yuding','','[]','李杜複李杜，彼時逢此時。干戈侵帝裏，流落向天涯。',48,'御定全唐詩/json/691.json','["李杜複李杜，彼時逢此時。干戈侵帝裏，流落向天涯。", "歲月消于酒，平生斷在詩。懷才不得志，只恐滿頭絲。"]'),
('yuding-97','秋日寄吟友','杜荀鶴','唐','御定全唐诗','yuding','','[]','閑坐細思量，唯吟不可忘。食無三畝地，衣絕一株桑。',48,'御定全唐詩/json/691.json','["閑坐細思量，唯吟不可忘。食無三畝地，衣絕一株桑。", "蟬樹生寒色，漁潭落曉光。青雲舊知己，未許釣滄浪。"]'),
('yuding-98','江上與從弟話別','杜荀鶴','唐','御定全唐诗','yuding','','[]','相逢盡說歸，早晚遂歸期。流水多通處，孤舟少住時。',48,'御定全唐詩/json/691.json','["相逢盡說歸，早晚遂歸期。流水多通處，孤舟少住時。", "幹人不得已，非我欲為之。及此終無愧，其如道在茲。"]'),
('yuding-99','送友人游南海','杜荀鶴','唐','御定全唐诗','yuding','','[]','南海南邊路，君遊只為貧。山川多少地，郡邑幾何人。',48,'御定全唐詩/json/691.json','["南海南邊路，君遊只為貧。山川多少地，郡邑幾何人。", "花鳥名皆別，寒暄氣不均。相期早晚見，莫待瘴侵身。"]'),
('yuding-100','贈聶尊師','杜荀鶴','唐','御定全唐诗','yuding','','[]','詩道將仙分，求之不可求。非關從小學，應是數生修。',48,'御定全唐詩/json/691.json','["詩道將仙分，求之不可求。非關從小學，應是數生修。", "蟾桂雲梯折，鼇山鶴駕遊。他年兩成事，堪喜是鄰州。"]'),
('yuding-101','旅感','杜荀鶴','唐','御定全唐诗','yuding','','[]','白髮根叢出，鑷頻愁不開。自憐空老去，誰信苦吟來。',48,'御定全唐詩/json/691.json','["白髮根叢出，鑷頻愁不開。自憐空老去，誰信苦吟來。", "客路東西闊，家山早晚回。翻思釣魚處，一雨一層苔。"]'),
('yuding-102','寄益陽武灌明府','杜荀鶴','唐','御定全唐诗','yuding','','[]','縣稱詩人理，無嫌日寂寥。溪山入城郭，戶口半漁樵。',48,'御定全唐詩/json/691.json','["縣稱詩人理，無嫌日寂寥。溪山入城郭，戶口半漁樵。", "月滿彈琴夜，花香漉酒朝。相思不相見，煙水路迢迢。"]'),
('yuding-103','湘中秋日呈所知','杜荀鶴','唐','御定全唐诗','yuding','','[]','四海無寸土，一生惟苦吟。虛垂異鄉淚，不滴別人心。',48,'御定全唐詩/json/691.json','["四海無寸土，一生惟苦吟。虛垂異鄉淚，不滴別人心。", "雨色凋湘樹，灘聲下塞禽。求歸歸未得，不是擲光陰。"]'),
('yuding-104','苦吟','杜荀鶴','唐','御定全唐诗','yuding','','[]','世間何事好，最好莫過詩。一句我自得，四方人已知。',48,'御定全唐詩/json/691.json','["世間何事好，最好莫過詩。一句我自得，四方人已知。", "生應無輟日，死是不吟時。始擬歸山去，林泉道在茲。"]'),
('yuding-105','閩中別所知','杜荀鶴','唐','御定全唐诗','yuding','','[]','觸目生歸思，那堪路七千。臘中離此地，馬上見明年。',48,'御定全唐詩/json/691.json','["觸目生歸思，那堪路七千。臘中離此地，馬上見明年。", "郡邑溪山巧，寒暄日月偏。自疑雙鬢雪，不似到南天。"]'),
('yuding-106','塞上傷戰士','杜荀鶴','唐','御定全唐诗','yuding','','[]','戰士說辛勤，書生不忍聞。三邊遠天子，一命信將軍。',48,'御定全唐詩/json/691.json','["戰士說辛勤，書生不忍聞。三邊遠天子，一命信將軍。", "野火燒人骨，陰風卷陣雲。其如禁城裏，何以重要勳。"]'),
('yuding-107','春日訪獨孤處士','杜荀鶴','唐','御定全唐诗','yuding','','[]','地僻春來靜，深宜長者居。好花都待晚，修竹不妨疏。',48,'御定全唐詩/json/691.json','["地僻春來靜，深宜長者居。好花都待晚，修竹不妨疏。", "雁入湘江食，人侵曉色鋤。似君無學處，頭白道如初。"]'),
('yuding-108','哭友人','杜荀鶴','唐','御定全唐诗','yuding','','[]','病向名場得，終為善誤身。無兒承後嗣，有女托何人。',48,'御定全唐詩/json/691.json','["病向名場得，終為善誤身。無兒承後嗣，有女托何人。", "葬禮難求備，交情好者貧。惟餘舊文集，一覽一沾巾。"]'),
('yuding-109','新栽竹','杜荀鶴','唐','御定全唐诗','yuding','','[]','劚破蒼苔色，因栽十數莖。窗風從此冷，詩思當時清。',48,'御定全唐詩/json/691.json','["劚破蒼苔色，因栽十數莖。窗風從此冷，詩思當時清。", "酒入杯中影，棋添局上聲。不同桃與李，瀟灑伴書生。"]'),
('yuding-110','送吳蛻下第入蜀','杜荀鶴','唐','御定全唐诗','yuding','','[]','下第言之蜀，那愁舉別杯。難兄方在幕，上相複憐才。',48,'御定全唐詩/json/691.json','["下第言之蜀，那愁舉別杯。難兄方在幕，上相複憐才。", "鳥徑盤春靄，龍湫發夜雷。臨邛無久戀，高桂待君回。"]'),
('yuding-111','亂後歸山','杜荀鶴','唐','御定全唐诗','yuding','','[]','亂世歸山谷，征鼙喜不聞。詩書猶滿架，弟侄未為軍。',48,'御定全唐詩/json/691.json','["亂世歸山谷，征鼙喜不聞。詩書猶滿架，弟侄未為軍。", "山犬眠紅葉，樵童唱白雲。此心非此志，終擬致明君。"]'),
('yuding-112','題著禪師','杜荀鶴','唐','御定全唐诗','yuding','','[]','大道本無幻，常情自有魔。人皆迷著此，師獨悟如何。',48,'御定全唐詩/json/691.json','["大道本無幻，常情自有魔。人皆迷著此，師獨悟如何。", "為嶽開窗闊，因蟲長草多。說空空說得，空得到維摩。"]'),
('yuding-113','春日閒居即事','杜荀鶴','唐','御定全唐诗','yuding','','[]','未得青雲志，春同秋日情。花開如葉落，鶯語似蟬鳴。',48,'御定全唐詩/json/691.json','["未得青雲志，春同秋日情。花開如葉落，鶯語似蟬鳴。", "道合和貧守，詩堪與命爭。饑寒是吾事，斷定不歸耕。"]'),
('yuding-114','秋宿棲賢寺懷友人','杜荀鶴','唐','御定全唐诗','yuding','','[]','一宿三秋寺，閑忙與曉分。細泉山半落，孤客夜深聞。',48,'御定全唐詩/json/691.json','["一宿三秋寺，閑忙與曉分。細泉山半落，孤客夜深聞。", "鶴去巢盛月，龍潛穴擁雲。苦吟方見景，多恨不同君。"]'),
('yuding-115','亂後再逢汪處士','杜荀鶴','唐','御定全唐诗','yuding','','[]','如君真道者，亂世有閒情。每別不知處，見來長後生。',48,'御定全唐詩/json/691.json','["如君真道者，亂世有閒情。每別不知處，見來長後生。", "藥非因病服，酒不為愁傾。笑我於身苦，吟髭白數莖。"]'),
('yuding-116','山中喜與故交宿話','杜荀鶴','唐','御定全唐诗','yuding','','[]','遠地能相訪，何慚事力微。山中深夜坐，海內故交稀。',48,'御定全唐詩/json/691.json','["遠地能相訪，何慚事力微。山中深夜坐，海內故交稀。", "村酒沽來濁，溪魚釣得肥。貧家只如此，未可便言歸。"]'),
('yuding-117','觀棋','杜荀鶴','唐','御定全唐诗','yuding','','[]','對面不相見，用心同用兵。算人常欲殺，顧己自貪生。',48,'御定全唐詩/json/691.json','["對面不相見，用心同用兵。算人常欲殺，顧己自貪生。", "得勢侵吞遠，乘危打劫贏。有時逢敵手，當局到深更。"]'),
('yuding-118','送人宰德清','杜荀鶴','唐','御定全唐诗','yuding','','[]','亂世人多事，耕桑或失時。不聞寬賦斂，因此轉流離。',48,'御定全唐詩/json/691.json','["亂世人多事，耕桑或失時。不聞寬賦斂，因此轉流離。", "天意未如是，君心無自欺。能依四十字，可立德清碑。"]'),
('yuding-119','寄竇處士','杜荀鶴','唐','御定全唐诗','yuding','','[]','漳水醉中別，今來猶未醒。半生因酒廢，大國幾時寧。',48,'御定全唐詩/json/691.json','["漳水醉中別，今來猶未醒。半生因酒廢，大國幾時寧。", "海畔將軍柳，天邊處士星。遊人不可見，春入亂山青。"]'),
('yuding-120','題曆山舜詞','杜荀鶴','唐','御定全唐诗','yuding','','[]','昔舜曾耕地，遺風日寂寥。世人那肯祭，大聖不興妖。',48,'御定全唐詩/json/691.json','["昔舜曾耕地，遺風日寂寥。世人那肯祭，大聖不興妖。", "殿宇秋霖壞，杉松野火燒。時訛競淫祀，絲竹醉山魈。"]'),
('yuding-121','贈李蒙叟','杜荀鶴','唐','御定全唐诗','yuding','','[]','在我成何事，逢君更勸吟。縱饒不得力，猶勝別勞心。',48,'御定全唐詩/json/691.json','["在我成何事，逢君更勸吟。縱饒不得力，猶勝別勞心。", "凡事有興廢，詩名無古今。百年能幾日，忍不惜光陰。"]'),
('yuding-122','維揚冬末寄幕中二從事','杜荀鶴','唐','御定全唐诗','yuding','','[]','聞道長溪尉，相留一館閑。□□□□□，尚隔幾重山。',48,'御定全唐詩/json/691.json','["聞道長溪尉，相留一館閑。□□□□□，尚隔幾重山。", "為旅春風外，懷人夜雨間。年來疏覽鏡，怕見減朱顏。"]'),
('yuding-123','和吳太守罷郡山村偶題二首','杜荀鶴','唐','御定全唐诗','yuding','','[]','罷郡饒山興，村家不惜過。官情隨日薄，詩思入秋多。',96,'御定全唐詩/json/691.json','["罷郡饒山興，村家不惜過。官情隨日薄，詩思入秋多。", "野獸眠低草，池禽浴動荷。眼前餘政在，不似有干戈。", "快活田翁輩，常言化育時。縱饒稽歲月，猶說向孫兒。", "茅屋梁和節，茶盤果帶枝。相傳終不忘，何必立生祠。"]'),
('yuding-124','亂後送友人歸湘中','杜荀鶴','唐','御定全唐诗','yuding','','[]','家枕三湘岸，門前即釣磯。漁竿壯歲別，鶴發亂時歸。',48,'御定全唐詩/json/691.json','["家枕三湘岸，門前即釣磯。漁竿壯歲別，鶴發亂時歸。", "嶽暖無猿叫，江春有燕飛。平生書劍在，莫便學忘機。"]'),
('yuding-125','送紫陽僧歸廬嶽舊寺','杜荀鶴','唐','御定全唐诗','yuding','','[]','紫衣明主贈，歸寺感先師。受業恩難報，開堂影不知。',48,'御定全唐詩/json/691.json','["紫衣明主贈，歸寺感先師。受業恩難報，開堂影不知。", "松風欹枕夜，山雪下樓時。此際無人會，微吟複斂眉。"]'),
('yuding-126','和劉評事送海禪和歸山','杜荀鶴','唐','御定全唐诗','yuding','','[]','衲外元無象，言尋那路尋。問禪將底說，傳印得何心。',72,'御定全唐詩/json/691.json','["衲外元無象，言尋那路尋。問禪將底說，傳印得何心。", "未了群山淺，難休一室深。伏魔寧是獸，巢頂亦非禽。", "觀色風驅霧，聽聲雪灑林。凡歸是歸處，不必指高岑。"]'),
('yuding-127','禦溝柳','杜荀鶴','唐','御定全唐诗','yuding','','[]','律到禦溝春，溝邊柳色新。細籠穿禁水，輕拂入朝人。',72,'御定全唐詩/json/691.json','["律到禦溝春，溝邊柳色新。細籠穿禁水，輕拂入朝人。", "日近韶光早，天低聖澤勻。谷鶯棲未穩，宮女畫難真。", "楚國空搖浪，隋堤暗惹塵。如何帝城裏，先得覆龍津。"]'),
('yuding-0','冬末同友人泛瀟湘','杜荀鶴','唐','御定全唐诗','yuding','','[]','殘臘泛舟何處好，最多吟興是瀟湘。就船買得魚偏美，',40,'御定全唐詩/json/692.json','["殘臘泛舟何處好，最多吟興是瀟湘。就船買得魚偏美，", "與君剩采江山景，裁取新詩入帝鄉。"]'),
('yuding-1','贈李鐔','杜荀鶴','唐','御定全唐诗','yuding','','[]','君行君文天合知，見君如此我興悲。只殘三口兵戈後，',40,'御定全唐詩/json/692.json','["君行君文天合知，見君如此我興悲。只殘三口兵戈後，", "地爐不暖柴枝濕，猶把蒙求授小兒。"]'),
('yuding-2','旅中臥病','杜荀鶴','唐','御定全唐诗','yuding','','[]','秋來誰料病相縈，枕上心猶算去程。風射破窗燈易滅，',40,'御定全唐詩/json/692.json','["秋來誰料病相縈，枕上心猶算去程。風射破窗燈易滅，", "我自與人無舊分，非幹人與我無情。"]'),
('yuding-3','旅泊遇郡中叛亂示同志','杜荀鶴','唐','御定全唐诗','yuding','','[]','握手相看誰敢言，軍家刀劍在腰邊。遍搜寶貨無藏處，',40,'御定全唐詩/json/692.json','["握手相看誰敢言，軍家刀劍在腰邊。遍搜寶貨無藏處，", "郡侯逐出渾閒事，正是鑾輿幸蜀年。"]'),
('yuding-4','贈秋浦張明府','杜荀鶴','唐','御定全唐诗','yuding','','[]','君為秋浦三年宰，萬慮關心兩鬢知。人事旋生當路縣，',40,'御定全唐詩/json/692.json','["君為秋浦三年宰，萬慮關心兩鬢知。人事旋生當路縣，", "他日親知問官況，但教吟取杜家詩。"]'),
('yuding-5','雪','杜荀鶴','唐','御定全唐诗','yuding','','[]','風攪長空寒骨生，光於曉色報窗明。江湖不見飛禽影，',40,'御定全唐詩/json/692.json','["風攪長空寒骨生，光於曉色報窗明。江湖不見飛禽影，", "擁袍公子休言冷，中有樵夫跣足行。"]'),
('yuding-6','題廬岳劉處士草堂','杜荀鶴','唐','御定全唐诗','yuding','','[]','仙境閑尋采藥翁，草堂留話一宵同。若看山下雲深處，',40,'御定全唐詩/json/692.json','["仙境閑尋采藥翁，草堂留話一宵同。若看山下雲深處，", "求名心在閑難遂，明日馬蹄塵土中。"]'),
('yuding-7','山中寄詩友','杜荀鶴','唐','御定全唐诗','yuding','','[]','山深長恨少同人，覽景無時不憶君。庭果自從霜後熟，',40,'御定全唐詩/json/692.json','["山深長恨少同人，覽景無時不憶君。庭果自從霜後熟，", "仙桂算攀攀合得，平生心力盡于文。"]'),
('yuding-8','秋宿臨江驛','杜荀鶴','唐','御定全唐诗','yuding','','[]','南來北去二三年，年去年來兩鬢斑。舉世盡從愁裏老，',40,'御定全唐詩/json/692.json','["南來北去二三年，年去年來兩鬢斑。舉世盡從愁裏老，", "身事未成歸未得，聽猿鞭馬入長關。"]'),
('yuding-9','題瓦棺寺真上人院矮檜','杜荀鶴','唐','御定全唐诗','yuding','','[]','天生仙檜是長材，栽檜希逢此最低。一自舊山來砌畔，',40,'御定全唐詩/json/692.json','["天生仙檜是長材，栽檜希逢此最低。一自舊山來砌畔，", "今日偶題題似著，不知題後更誰題。"]'),
('yuding-10','江下初秋寓泊','杜荀鶴','唐','御定全唐诗','yuding','','[]','濛濛煙雨蔽江村，江館愁人好斷魂。自別家來生白髮，',40,'御定全唐詩/json/692.json','["濛濛煙雨蔽江村，江館愁人好斷魂。自別家來生白髮，", "兄弟無書雁歸北，一聲聲覺苦於猿。"]'),
('yuding-11','投從叔補闕','杜荀鶴','唐','御定全唐诗','yuding','','[]','吾宗不謁謁詩宗，常仰門風繼國風。空有篇章傳海內，',40,'御定全唐詩/json/692.json','["吾宗不謁謁詩宗，常仰門風繼國風。空有篇章傳海內，", "三十年吟到今日，不妨私薦亦成公。"]'),
('yuding-12','贈張員外兒','杜荀鶴','唐','御定全唐诗','yuding','','[]','張公一子才三歲，聞客吟聲便出來。喚物舌頭猶未穩，',40,'御定全唐詩/json/692.json','["張公一子才三歲，聞客吟聲便出來。喚物舌頭猶未穩，", "月裏桂枝知有分，不勞諸丈作梯媒。"]'),
('yuding-13','重陽日有作','杜荀鶴','唐','御定全唐诗','yuding','','[]','一為重陽上古台，亂時誰見菊花開。偷撏白髮真堪笑，',40,'御定全唐詩/json/692.json','["一為重陽上古台，亂時誰見菊花開。偷撏白髮真堪笑，", "大家拍手高聲唱，日未沈山且莫回。"]'),
('yuding-14','入關寄九華友人','杜荀鶴','唐','御定全唐诗','yuding','','[]','坐床難穩露蟬新，便作東西馬上身。醲酒卻輸耽睡客，',40,'御定全唐詩/json/692.json','["坐床難穩露蟬新，便作東西馬上身。醲酒卻輸耽睡客，", "篋裏篇章頭上雪，未知誰戀杏園春。"]'),
('yuding-15','送李鐔游新安','杜荀鶴','唐','御定全唐诗','yuding','','[]','邯鄲李鐔才崢嶸，酒狂詩逸難幹名。氣直不與兒輩洽，',40,'御定全唐詩/json/692.json','["邯鄲李鐔才崢嶸，酒狂詩逸難幹名。氣直不與兒輩洽，", "一間茅屋住不穩，剛出為人平不平。"]'),
('yuding-16','冬末自長沙游桂嶺留獻所知','杜荀鶴','唐','御定全唐诗','yuding','','[]','家隔重湖歸未期，更堪南去別深知。前程笑到山多處，',40,'御定全唐詩/json/692.json','["家隔重湖歸未期，更堪南去別深知。前程笑到山多處，", "朱門只見朱門事，獨把孤寒問阿誰。"]'),
('yuding-17','送福昌周繇少府歸寧兼謀隱','杜荀鶴','唐','御定全唐诗','yuding','','[]','少見古人無遠慮，如君真得古人情。登科作尉官雖小，',40,'御定全唐詩/json/692.json','["少見古人無遠慮，如君真得古人情。登科作尉官雖小，", "知君未作終焉計，要著文章待太平。"]'),
('yuding-18','賀顧雲侍禦府主與子弟奏官','杜荀鶴','唐','御定全唐诗','yuding','','[]','青桂朱袍不賀兄，賀兄榮是見兒榮。孝經始向堂前徹，',40,'御定全唐詩/json/692.json','["青桂朱袍不賀兄，賀兄榮是見兒榮。孝經始向堂前徹，", "自慚亂世無知己，弟侄鞭牛傍隴耕。"]'),
('yuding-19','舟行即事','杜荀鶴','唐','御定全唐诗','yuding','','[]','年少髭須雪欲侵，別家三日幾般心。朝隨賈客憂風色，',40,'御定全唐詩/json/692.json','["年少髭須雪欲侵，別家三日幾般心。朝隨賈客憂風色，", "重陽酒熟茱萸紫，卻向江頭倚棹吟。"]'),
('yuding-20','亂後山居','杜荀鶴','唐','御定全唐诗','yuding','','[]','從亂移家擬傍山，今來方辦買山錢。九州有路休為客，',40,'御定全唐詩/json/692.json','["從亂移家擬傍山，今來方辦買山錢。九州有路休為客，", "他人似我還應少，如此安貧亦荷天。"]'),
('yuding-21','山居寄同志','杜荀鶴','唐','御定全唐诗','yuding','','[]','茅齋深僻絕輪蹄，門徑緣莎細接溪。垂釣石台依竹壘，',40,'御定全唐詩/json/692.json','["茅齋深僻絕輪蹄，門徑緣莎細接溪。垂釣石台依竹壘，", "不是無端過時日，擬從窗下躡雲梯。"]'),
('yuding-22','將入關安陸遇兵寇','杜荀鶴','唐','御定全唐诗','yuding','','[]','家貧無計早離家，離得家來蹇滯多。已是數程行雨雪，',40,'御定全唐詩/json/692.json','["家貧無計早離家，離得家來蹇滯多。已是數程行雨雪，", "四面煙塵少無處，不知吾土自如何。"]'),
('yuding-23','夏日登友人書齋林亭','杜荀鶴','唐','御定全唐诗','yuding','','[]','暑天長似秋天冷，帶郭林亭畫不如。蟬噪檻前遮日竹，',40,'御定全唐詩/json/692.json','["暑天長似秋天冷，帶郭林亭畫不如。蟬噪檻前遮日竹，", "眾惜君才堪上第，莫因居此與名疏。"]'),
('yuding-24','寄臨海姚中丞','杜荀鶴','唐','御定全唐诗','yuding','','[]','夏辭旌旆已秋深，永夕思量淚滿襟。風月易斑搜句鬢，',40,'御定全唐詩/json/692.json','["夏辭旌旆已秋深，永夕思量淚滿襟。風月易斑搜句鬢，", "雖有夢魂知處所，去來多被角聲侵。"]'),
('yuding-25','秋日閒居寄先達','杜荀鶴','唐','御定全唐诗','yuding','','[]','到頭身事欲何為，窗下工夫鬢上知。乍可百年無稱意，',40,'御定全唐詩/json/692.json','["到頭身事欲何為，窗下工夫鬢上知。乍可百年無稱意，", "自古書生也如此，獨堪惆悵是明時。"]'),
('yuding-26','題覺禪和','杜荀鶴','唐','御定全唐诗','yuding','','[]','少見修行得似師，茅堂佛像亦隨時。禪衣衲後雲藏線，',40,'御定全唐詩/json/692.json','["少見修行得似師，茅堂佛像亦隨時。禪衣衲後雲藏線，", "有時問著經中事，卻道山僧總不知。"]'),
('yuding-27','感秋','杜荀鶴','唐','御定全唐诗','yuding','','[]','年年名路謾辛勤，襟袖空多馬上塵。畫戟門前難作客，',40,'御定全唐詩/json/692.json','["年年名路謾辛勤，襟袖空多馬上塵。畫戟門前難作客，", "自是儂家無住處，不關天地窄於人。"]'),
('yuding-28','題德玄上人院','杜荀鶴','唐','御定全唐诗','yuding','','[]','刳得心來忙處閑，閑中方寸闊於天。浮生自是無空性，',40,'御定全唐詩/json/692.json','["刳得心來忙處閑，閑中方寸闊於天。浮生自是無空性，", "我雖未似師披衲，此理同師悟了然。"]'),
('yuding-29','春日山居寄友人','杜荀鶴','唐','御定全唐诗','yuding','','[]','野吟何處最相宜，春景暄和好入詩。高下麥苗新雨後，',40,'御定全唐詩/json/692.json','["野吟何處最相宜，春景暄和好入詩。高下麥苗新雨後，", "倒載干戈是何日，近來麋鹿欲相隨。"]'),
('yuding-30','懷廬嶽舊隱','杜荀鶴','唐','御定全唐诗','yuding','','[]','一別三年長在夢，夢中時躡石棱層。泉聲入夜方堪聽，',40,'御定全唐詩/json/692.json','["一別三年長在夢，夢中時躡石棱層。泉聲入夜方堪聽，", "人間有許多般事，求要身閑直未能。"]'),
('yuding-31','投長沙裴侍郎','杜荀鶴','唐','御定全唐诗','yuding','','[]','此身雖賤道長存，非謁朱門謁孔門。只望至公將卷讀，',40,'御定全唐詩/json/692.json','["此身雖賤道長存，非謁朱門謁孔門。只望至公將卷讀，", "男子受恩須有地，平生不受等閒恩。"]'),
('yuding-32','和友人見題山居','杜荀鶴','唐','御定全唐诗','yuding','','[]','避時多喜葺居成，七字君題萬象清。開戶曉雲連地白，',40,'御定全唐詩/json/692.json','["避時多喜葺居成，七字君題萬象清。開戶曉雲連地白，", "有景供吟且如此，算來何必躁於名。"]'),
('yuding-33','獻長沙王侍郎','杜荀鶴','唐','御定全唐诗','yuding','','[]','文星漸見射台星，皆仰為霖沃眾情。天澤逼來逢聖主，',40,'御定全唐詩/json/692.json','["文星漸見射台星，皆仰為霖沃眾情。天澤逼來逢聖主，", "美化事多難諷誦，未如耕釣口分明。"]'),
('yuding-34','春日登樓遇雨','杜荀鶴','唐','御定全唐诗','yuding','','[]','忽地晴天作雨天，全無暑氣似秋間。看看水沒來時路，',40,'御定全唐詩/json/692.json','["忽地晴天作雨天，全無暑氣似秋間。看看水沒來時路，", "一心准擬閑登眺，卻被詩情使不閑。"]'),
('yuding-35','春日行次錢塘卻寄台州姚中丞','杜荀鶴','唐','御定全唐诗','yuding','','[]','豈為無心求上第，難安帝裏為家貧。江南江北閑為客，',40,'御定全唐詩/json/692.json','["豈為無心求上第，難安帝裏為家貧。江南江北閑為客，", "花前不獨垂鄉淚，曾是朱門寄食身。"]'),
('yuding-36','投江上崔尚書','杜荀鶴','唐','御定全唐诗','yuding','','[]','此生何路出塵埃，猶把中才謁上才。閉戶十年專筆硯，',40,'御定全唐詩/json/692.json','["此生何路出塵埃，猶把中才謁上才。閉戶十年專筆硯，", "若許登門換鬐鬣，必應辛苦事風雷。"]'),
('yuding-37','書事投所知','杜荀鶴','唐','御定全唐诗','yuding','','[]','古陌寒風來去吹，馬蹄塵旋上麻衣。雖然幹祿無休意，',40,'御定全唐詩/json/692.json','["古陌寒風來去吹，馬蹄塵旋上麻衣。雖然幹祿無休意，", "肯將骨肉輕離別，未遇人知未得歸。"]'),
('yuding-38','秋日湖外書事','杜荀鶴','唐','御定全唐诗','yuding','','[]','十五年來筆硯功，只今猶在苦貧中。三秋客路湖光外，',40,'御定全唐詩/json/692.json','["十五年來筆硯功，只今猶在苦貧中。三秋客路湖光外，", "朱門處處若相似，此命到頭通不通。"]'),
('yuding-39','題宗上人舊院','杜荀鶴','唐','御定全唐诗','yuding','','[]','此院重來事事乖，半欹茅屋草侵階。啄生鴉憶啼松枿。',64,'御定全唐詩/json/692.json','["此院重來事事乖，半欹茅屋草侵階。啄生鴉憶啼松枿。", "接果猿思嘯石崖。壁上塵粘蒲葉扇，床前苔爛筍皮鞋。", "分明記得談空日，不向秋風更愴懷。"]'),
('yuding-40','亂後出山逢高員外','杜荀鶴','唐','御定全唐诗','yuding','','[]','自從亂後別京關，一入煙蘿十五年。重出故山生白髮，',40,'御定全唐詩/json/692.json','["自從亂後別京關，一入煙蘿十五年。重出故山生白髮，", "名姓暗投心暗祝，永期收拾向門前。"]'),
('yuding-41','贈友人罷舉赴交趾辟命','杜荀鶴','唐','御定全唐诗','yuding','','[]','罷卻名場擬入秦，南行無罪似流人。縱經商嶺非馳驛，',40,'御定全唐詩/json/692.json','["罷卻名場擬入秦，南行無罪似流人。縱經商嶺非馳驛，", "如何待取丹霄桂，別赴嘉招作上賓。"]'),
('yuding-42','山中寡婦','杜荀鶴','唐','御定全唐诗','yuding','','[]','夫因兵死守蓬茅，麻苧衣衫鬢髮焦。桑柘廢來猶納稅，',40,'御定全唐詩/json/692.json','["夫因兵死守蓬茅，麻苧衣衫鬢髮焦。桑柘廢來猶納稅，", "任是深山更深處，也應無計避征徭。"]'),
('yuding-43','訪蔡融因題','杜荀鶴','唐','御定全唐诗','yuding','','[]','杖藜時複過荒郊，來到君家不忍拋。每見苦心修好事，',40,'御定全唐詩/json/692.json','["杖藜時複過荒郊，來到君家不忍拋。每見苦心修好事，", "必若天工主人事，肯交吾子委衡茅。"]'),
('yuding-44','閒居書事','杜荀鶴','唐','御定全唐诗','yuding','','[]','竹門茅屋帶村居，數畝生涯自有餘。鬢白只應秋煉句，',40,'御定全唐詩/json/692.json','["竹門茅屋帶村居，數畝生涯自有餘。鬢白只應秋煉句，", "待得功成即西去，時清不問命何如。"]'),
('yuding-45','友人贈舍弟依韻戲和','杜荀鶴','唐','御定全唐诗','yuding','','[]','吾家此弟有何知，多愧君開道業基。不覺裹頭成大漢，',41,'御定全唐詩/json/692.json','["吾家此弟有何知，多愧君開道業基。不覺裹頭成大漢，", "及見和詩詩自好，eh公不到更何時。"]'),
('yuding-46','亂後逢村叟','杜荀鶴','唐','御定全唐诗','yuding','','[]','經亂衰翁居破村，村中何事不傷魂。因供寨木無桑柘，',40,'御定全唐詩/json/692.json','["經亂衰翁居破村，村中何事不傷魂。因供寨木無桑柘，", "至於雞犬皆星散，日落前山獨倚門。"]'),
('yuding-47','贈元上人','杜荀鶴','唐','御定全唐诗','yuding','','[]','多少僧中僧行高，偈成流落遍僧抄。經窗月靜灘聲到，',40,'御定全唐詩/json/692.json','["多少僧中僧行高，偈成流落遍僧抄。經窗月靜灘聲到，", "煮茶童子閑勝我，猶得依時把磬敲。"]'),
('yuding-48','下第東歸道中作','杜荀鶴','唐','御定全唐诗','yuding','','[]','一回落第一寧親，多是途中過卻春。心火不銷雙鬢雪，',40,'御定全唐詩/json/692.json','["一回落第一寧親，多是途中過卻春。心火不銷雙鬢雪，", "馬壯金多有官者，榮歸卻笑讀書人。"]'),
('yuding-49','夏日留題張山人林亭','杜荀鶴','唐','御定全唐诗','yuding','','[]','此中偏稱夏中游，時有風來暑氣收。澗底松搖千尺雨，',40,'御定全唐詩/json/692.json','["此中偏稱夏中游，時有風來暑氣收。澗底松搖千尺雨，", "閑與先生話身事，浮名薄宦總悠悠。"]'),
('yuding-50','傷病馬','杜荀鶴','唐','御定全唐诗','yuding','','[]','此馬堪憐力壯時，細勻行步恐塵知。騎來未省將鞭觸，',40,'御定全唐詩/json/692.json','["此馬堪憐力壯時，細勻行步恐塵知。騎來未省將鞭觸，", "只今筋骨渾全在，春暖莎青放未遲。"]'),
('yuding-51','館舍秋夕','杜荀鶴','唐','御定全唐诗','yuding','','[]','寒雨蕭蕭燈焰青，燈前孤客難為情。兵戈鬧日別鄉國，',40,'御定全唐詩/json/692.json','["寒雨蕭蕭燈焰青，燈前孤客難為情。兵戈鬧日別鄉國，", "出門便作還家計，直至如今計未成。"]'),
('yuding-52','送僧赴黃山沐湯泉兼參禪宗長老','杜荀鶴','唐','御定全唐诗','yuding','','[]','聞有湯泉獨去尋，一瓶一缽一無金。不愁亂世兵相害，',40,'御定全唐詩/json/692.json','["聞有湯泉獨去尋，一瓶一缽一無金。不愁亂世兵相害，", "患身是幻逢禪主，水洗皮膚語洗心。"]'),
('yuding-53','哭山友','杜荀鶴','唐','御定全唐诗','yuding','','[]','十載同棲廬嶽雲，寒燒枯葉夜論文。在生未識公卿面，',40,'御定全唐詩/json/692.json','["十載同棲廬嶽雲，寒燒枯葉夜論文。在生未識公卿面，", "把君詩句高聲讀，想得天高也合聞。"]'),
('yuding-54','獻池州牧','杜荀鶴','唐','御定全唐诗','yuding','','[]','池陽今日似漁陽，大變凶年作小康。江路靜來通客貨，',40,'御定全唐詩/json/692.json','["池陽今日似漁陽，大變凶年作小康。江路靜來通客貨，", "縱有逋民歸未得，遠聞仁政旋還鄉。"]'),
('yuding-55','送韋書記歸京','杜荀鶴','唐','御定全唐诗','yuding','','[]','韋杜相逢眼自明，事連恩地倍牽情。聞歸帝裏愁攀送，',40,'御定全唐詩/json/692.json','["韋杜相逢眼自明，事連恩地倍牽情。聞歸帝裏愁攀送，", "從來有淚非無淚，未似今朝淚滿纓。"]'),
('yuding-56','獻鄭給事','杜荀鶴','唐','御定全唐诗','yuding','','[]','化行邦域二年春，樵唱漁歌日日新。未降詔書酬善政，',40,'御定全唐詩/json/692.json','["化行邦域二年春，樵唱漁歌日日新。未降詔書酬善政，", "他日朱門恐難掃，沙堤新築必無塵。"]'),
('yuding-57','贈休禪和','杜荀鶴','唐','御定全唐诗','yuding','','[]','為僧難得不為僧，僧戒僧儀未是能。弟子自知心了了，',40,'御定全唐詩/json/692.json','["為僧難得不為僧，僧戒僧儀未是能。弟子自知心了了，", "只道詩人無佛性，長將二雅入三乘。"]'),
('yuding-58','送李先輩從知塞上','杜荀鶴','唐','御定全唐诗','yuding','','[]','去草軍書出帝鄉，便從城外學戎裝。好隨漢將收胡土，',40,'御定全唐詩/json/692.json','["去草軍書出帝鄉，便從城外學戎裝。好隨漢將收胡土，", "此行也是男兒事，莫向征人恃桂香。"]'),
('yuding-59','和友人送弟','杜荀鶴','唐','御定全唐诗','yuding','','[]','君說無家只弟兄，此中言別若為情。干戈鬧日分頭去，',40,'御定全唐詩/json/692.json','["君說無家只弟兄，此中言別若為情。干戈鬧日分頭去，", "我今骨肉雖饑凍，幸喜團圓過亂兵。"]'),
('yuding-60','酬張員外見寄','杜荀鶴','唐','御定全唐诗','yuding','','[]','分應天與吟詩老，如此兵戈不廢詩。生在世間人不識，',40,'御定全唐詩/json/692.json','["分應天與吟詩老，如此兵戈不廢詩。生在世間人不識，", "今日逢君惜分手，一枝何校一年遲。"]'),
('yuding-61','獻新安于尚書','杜荀鶴','唐','御定全唐诗','yuding','','[]','九土雄師竟若何，未如良牧與天和。月留清俸資家少，',40,'御定全唐詩/json/692.json','["九土雄師竟若何，未如良牧與天和。月留清俸資家少，", "行人耳滿新安事，儘是無愁父老歌。"]'),
('yuding-62','亂後書事寄同志','杜荀鶴','唐','御定全唐诗','yuding','','[]','九土如今盡用兵，短戈長戟困書生。思量在世頭堪白，',40,'御定全唐詩/json/692.json','["九土如今盡用兵，短戈長戟困書生。思量在世頭堪白，", "到頭詩捲鬚藏卻，各向漁樵混姓名。"]'),
('yuding-63','中山臨上人院觀牡丹寄諸從事','杜荀鶴','唐','御定全唐诗','yuding','','[]','閑來吟繞牡丹叢，花豔人生事略同。半雨半風三月內，',40,'御定全唐詩/json/692.json','["閑來吟繞牡丹叢，花豔人生事略同。半雨半風三月內，", "一境別無唯此有，忍教醒坐對支公。"]'),
('yuding-64','投宣諭張侍郎亂後遇毗陵','杜荀鶴','唐','御定全唐诗','yuding','','[]','此生今日似前生，重著麻衣特地行。經亂後囊新卷軸，',40,'御定全唐詩/json/692.json','["此生今日似前生，重著麻衣特地行。經亂後囊新卷軸，", "聞道中興重人物，不妨西去馬蹄輕。"]'),
('yuding-65','下第投所知','杜荀鶴','唐','御定全唐诗','yuding','','[]','落第愁生曉鼓初，地寒才薄欲何如。不辭更寫公卿卷，',40,'御定全唐詩/json/692.json','["落第愁生曉鼓初，地寒才薄欲何如。不辭更寫公卿卷，", "擬離門館東歸去，又恐重來事轉疏。"]'),
('yuding-66','哭方幹','杜荀鶴','唐','御定全唐诗','yuding','','[]','何言寸祿不沾身，身沒詩名萬古存。況有數篇關教化，',40,'御定全唐詩/json/692.json','["何言寸祿不沾身，身沒詩名萬古存。況有數篇關教化，", "天下未寧吾道喪，更誰將酒酹吟魂。"]'),
('yuding-67','秋日泊浦江','杜荀鶴','唐','御定全唐诗','yuding','','[]','一帆程歇九秋時，漠漠蘆花拂浪飛。寒浦更無船並宿，',40,'御定全唐詩/json/692.json','["一帆程歇九秋時，漠漠蘆花拂浪飛。寒浦更無船並宿，", "江月漸明汀露濕，靜驅吟魄入玄微。"]'),
('yuding-68','白髮吟','杜荀鶴','唐','御定全唐诗','yuding','','[]','一莖兩莖初似絲，不妨驚度少年時。幾人亂世得及此，',40,'御定全唐詩/json/692.json','["一莖兩莖初似絲，不妨驚度少年時。幾人亂世得及此，", "家山蒼翠萬餘尺，藜杖楮冠輸老兒。"]'),
('yuding-69','下第寄池州鄭員外','杜荀鶴','唐','御定全唐诗','yuding','','[]','省出蓬蒿修謁初，蒙知曾不見生疏。侯門數處將書薦，',40,'御定全唐詩/json/692.json','["省出蓬蒿修謁初，蒙知曾不見生疏。侯門數處將書薦，", "如今足得成持取，莫使江湖卻釣魚。"]'),
('yuding-70','塞上','杜荀鶴','唐','御定全唐诗','yuding','','[]','旌旗鬣鬣漢將軍，閑出巡邊帝命新。沙塞旋收饒帳幕，',40,'御定全唐詩/json/692.json','["旌旗鬣鬣漢將軍，閑出巡邊帝命新。沙塞旋收饒帳幕，", "獨作書生疑不穩，軟弓輕劍也隨身。"]'),
('yuding-71','贈題兜率寺閑上人院','杜荀鶴','唐','御定全唐诗','yuding','','[]','人間寺應諸天號，真行僧禪此寺中。百歲有涯頭上雪，',40,'御定全唐詩/json/692.json','["人間寺應諸天號，真行僧禪此寺中。百歲有涯頭上雪，", "畢竟浮生謾勞役，算來何事不成空。"]'),
('yuding-72','別四明鐘尚書','杜荀鶴','唐','御定全唐诗','yuding','','[]','九華天際碧嵯峨，無奈春來入夢何。難與英雄論教化，',40,'御定全唐詩/json/692.json','["九華天際碧嵯峨，無奈春來入夢何。難與英雄論教化，", "都大人生有離別，且將詩句代離歌。"]'),
('yuding-73','題護國大師塔','杜荀鶴','唐','御定全唐诗','yuding','','[]','莫認雙林是佛林，禪棲無地亦無金。塔前盡禮灰來相，',40,'御定全唐詩/json/692.json','["莫認雙林是佛林，禪棲無地亦無金。塔前盡禮灰來相，", "吾師覺路餘知處，大藏經門一夜吟。"]'),
('yuding-74','春日山中對雪有作','杜荀鶴','唐','御定全唐诗','yuding','','[]','竹樹無聲或有聲，霏霏漠漠散還凝。嶺梅謝後重妝蕊，',40,'御定全唐詩/json/692.json','["竹樹無聲或有聲，霏霏漠漠散還凝。嶺梅謝後重妝蕊，", "好將膏雨同功力，松徑莓苔又一層。"]'),
('yuding-75','山中對雪有作','杜荀鶴','唐','御定全唐诗','yuding','','[]','一渾乾坤萬象收，唯應不壅大江流。虎狼遇獵難藏跡，',40,'御定全唐詩/json/692.json','["一渾乾坤萬象收，唯應不壅大江流。虎狼遇獵難藏跡，", "豈堪久蔽蒼蒼色，須放三光照九州。"]'),
('yuding-76','戲題王處士書齋','杜荀鶴','唐','御定全唐诗','yuding','','[]','先生高興似樵漁，水鳥山猿一處居。石徑可行苔色厚，',40,'御定全唐詩/json/692.json','["先生高興似樵漁，水鳥山猿一處居。石徑可行苔色厚，", "莫道無金空有壽，有金無壽欲何如。"]'),
('yuding-77','早發','杜荀鶴','唐','御定全唐诗','yuding','','[]','東窗未明塵夢蘇，呼童結束登征途。落葉鋪霜馬蹄滑，',40,'御定全唐詩/json/692.json','["東窗未明塵夢蘇，呼童結束登征途。落葉鋪霜馬蹄滑，", "青雲快活一未見，爭得安閒釣五湖。"]'),
('yuding-78','題仇處士郊居','杜荀鶴','唐','御定全唐诗','yuding','','[]','江南景簇此林亭，手板藍裾自可輕。洞裏客來無俗話，',40,'御定全唐詩/json/692.json','["江南景簇此林亭，手板藍裾自可輕。洞裏客來無俗話，", "笑我有詩三百首，馬蹄紅日急於名。"]'),
('yuding-79','依韻次同年張曙先輩見寄之什','杜荀鶴','唐','御定全唐诗','yuding','','[]','天上詩名天下傳，引來齊列玉皇前。大仙錄後頭無雪，',40,'御定全唐詩/json/692.json','["天上詩名天下傳，引來齊列玉皇前。大仙錄後頭無雪，", "九華山叟驚凡骨，同到蓬萊豈偶然。"]'),
('yuding-80','亂後逢李昭象敘別','杜荀鶴','唐','御定全唐诗','yuding','','[]','李生李生何所之，家山窣雲胡不歸。兵戈到處弄性命，',40,'御定全唐詩/json/692.json','["李生李生何所之，家山窣雲胡不歸。兵戈到處弄性命，", "也知不是男兒事，爭奈時情賤布衣。"]'),
('yuding-81','晚春寄同年張曙先輩','杜荀鶴','唐','御定全唐诗','yuding','','[]','莫將時態破天真，只合高歌醉過春。易落好花三個月，',40,'御定全唐詩/json/692.json','["莫將時態破天真，只合高歌醉過春。易落好花三個月，", "恩地未酬閑未得，一回醒話一沾巾。"]'),
('yuding-82','長安春感','杜荀鶴','唐','御定全唐诗','yuding','','[]','出京無計住京難，深入東風轉索然。滿眼有花寒食下，',40,'御定全唐詩/json/692.json','["出京無計住京難，深入東風轉索然。滿眼有花寒食下，", "公道算來終達去，更從今日望明年。"]'),
('yuding-83','登靈山水閣貽釣者','杜荀鶴','唐','御定全唐诗','yuding','','[]','江上見僧誰是了，修齋補衲日勞身。未勝漁父閑垂釣，',40,'御定全唐詩/json/692.json','["江上見僧誰是了，修齋補衲日勞身。未勝漁父閑垂釣，", "瓦瓶盛酒瓷甌酌，荻浦蘆灣是要津。"]'),
('yuding-84','贈溧水崔少府','杜荀鶴','唐','御定全唐诗','yuding','','[]','庭戶蕭條燕雀喧，日高窗下枕書眠。只聞留客教沽酒，',40,'御定全唐詩/json/692.json','["庭戶蕭條燕雀喧，日高窗下枕書眠。只聞留客教沽酒，", "九華山叟心相許，不計官卑贈一篇。"]'),
('yuding-85','讀張僕射詩','杜荀鶴','唐','御定全唐诗','yuding','','[]','秋吟一軸見心胸，萬象搜羅詠欲空。才大卻嫌天上桂，',40,'御定全唐詩/json/692.json','["秋吟一軸見心胸，萬象搜羅詠欲空。才大卻嫌天上桂，", "雙美總輸張太守，二南章句六鈞弓。"]'),
('yuding-86','題所居村舍','杜荀鶴','唐','御定全唐诗','yuding','','[]','家隨兵盡屋空存，稅額甯容減一分。衣食旋營猶可過，',40,'御定全唐詩/json/692.json','["家隨兵盡屋空存，稅額甯容減一分。衣食旋營猶可過，", "如此數州誰會得，殺民將盡更邀勳。"]'),
('yuding-87','獻錢塘縣羅著作判官','杜荀鶴','唐','御定全唐诗','yuding','','[]','還鄉夫子遇賢侯，撫字情知不自由。莫把一名專懊惱，',40,'御定全唐詩/json/692.json','["還鄉夫子遇賢侯，撫字情知不自由。莫把一名專懊惱，", "猶有九華知己在，羨君高臥早回頭。"]'),
('yuding-88','遣懷','杜荀鶴','唐','御定全唐诗','yuding','','[]','驅馳岐路共營營，只為人間利與名。紅杏園中終擬醉，',40,'御定全唐詩/json/692.json','["驅馳岐路共營營，只為人間利與名。紅杏園中終擬醉，", "謾道強親堪倚賴，到頭須是有前程。"]'),
('yuding-89','長安道中有作','杜荀鶴','唐','御定全唐诗','yuding','','[]','回頭不忍看羸僮，一路行人我最窮。馬跡蹇於槐影裏，',40,'御定全唐詩/json/692.json','["回頭不忍看羸僮，一路行人我最窮。馬跡蹇於槐影裏，", "子細尋思底模樣，騰騰又過玉關東。"]'),
('yuding-90','題開元寺門閣','杜荀鶴','唐','御定全唐诗','yuding','','[]','一登高閣眺清秋，滿目風光盡勝遊。何處畫橈尋綠水，',40,'御定全唐詩/json/692.json','["一登高閣眺清秋，滿目風光盡勝遊。何處畫橈尋綠水，", "唯有禪居離塵俗，了無榮辱掛心頭。"]'),
('yuding-91','出關投孫侍禦','杜荀鶴','唐','御定全唐诗','yuding','','[]','東歸還著舊麻衣，爭免花前有淚垂。每歲春光九十日，',40,'御定全唐詩/json/692.json','["東歸還著舊麻衣，爭免花前有淚垂。每歲春光九十日，", "不為感恩酬未得，五湖閑作釣魚師。"]'),
('yuding-92','送項山人歸天臺','杜荀鶴','唐','御定全唐诗','yuding','','[]','因話天臺歸思生，布囊藤杖笑離城。不教日月拘身事，',40,'御定全唐詩/json/692.json','["因話天臺歸思生，布囊藤杖笑離城。不教日月拘身事，", "此中是處堪終隱，何要世人知姓名。"]'),
('yuding-93','題衡陽隱士山居','杜荀鶴','唐','御定全唐诗','yuding','','[]','閒居不問世如何，雲起山門日已斜。放鶴去尋三島客，',40,'御定全唐詩/json/692.json','["閒居不問世如何，雲起山門日已斜。放鶴去尋三島客，", "畢竟金多也頭白，算來爭得似君家。"]'),
('yuding-94','題江寺禪和','杜荀鶴','唐','御定全唐诗','yuding','','[]','江寺禪僧似悟禪，壞衣芒履住茅軒。懶求施主修真像，',40,'御定全唐詩/json/692.json','["江寺禪僧似悟禪，壞衣芒履住茅軒。懶求施主修真像，", "行人莫問師宗旨，眼不浮華耳不喧。"]'),
('yuding-95','題弟侄書堂','杜荀鶴','唐','御定全唐诗','yuding','','[]','何事居窮道不窮，亂時還與靜時同。家山雖在干戈地，',40,'御定全唐詩/json/692.json','["何事居窮道不窮，亂時還與靜時同。家山雖在干戈地，", "少年辛苦終身事，莫向光陰惰寸功。"]'),
('yuding-96','和友人寄長林孟明府','杜荀鶴','唐','御定全唐诗','yuding','','[]','為政為人漸見心，長才聊屈宰長林。莫嫌月入無多俸，',40,'御定全唐詩/json/692.json','["為政為人漸見心，長才聊屈宰長林。莫嫌月入無多俸，", "訟庭閑寂公書少，留客看山索酒斟。"]'),
('yuding-97','戲贈漁家','杜荀鶴','唐','御定全唐诗','yuding','','[]','見君生計羨君閑，求食求衣有底難。養一箔蠶供釣線，',40,'御定全唐詩/json/692.json','["見君生計羨君閑，求食求衣有底難。養一箔蠶供釣線，", "卻笑儂家最辛苦，聽蟬鞭馬入長安。"]'),
('yuding-98','登城有作','杜荀鶴','唐','御定全唐诗','yuding','','[]','上得孤城向晚春，眼前何事不傷神。遍看原上累累塚，',40,'御定全唐詩/json/692.json','["上得孤城向晚春，眼前何事不傷神。遍看原上累累塚，", "一名一宦平生事，不放愁侵易過身。"]'),
('yuding-99','秋日山中寄池州李常侍','杜荀鶴','唐','御定全唐诗','yuding','','[]','近來參謁陡生疏，因向雲山僻處居。出為羈孤營糲食，',40,'御定全唐詩/json/692.json','["近來參謁陡生疏，因向雲山僻處居。出為羈孤營糲食，", "但得中興知己在，算應身未老樵漁。"]'),
('yuding-100','辭楊侍郎','杜荀鶴','唐','御定全唐诗','yuding','','[]','春在門闌秋未離，不因人薦只因詩。半年賓館成前事，',40,'御定全唐詩/json/692.json','["春在門闌秋未離，不因人薦只因詩。半年賓館成前事，", "西風萬里東歸去，更把愁心說向誰。"]'),
('yuding-101','題汪氏茅亭','杜荀鶴','唐','御定全唐诗','yuding','','[]','茅亭客到多稱奇，茅亭之上難題詩。出塵景物不可狀，',40,'御定全唐詩/json/692.json','["茅亭客到多稱奇，茅亭之上難題詩。出塵景物不可狀，", "君今酷愛人間事，爭得安閒老在茲。"]'),
('yuding-102','喜從弟雪中遠至有作','杜荀鶴','唐','御定全唐诗','yuding','','[]','深山大雪懶開門，門徑行蹤自爾新。無酒禦寒雖寡況，',40,'御定全唐詩/json/692.json','["深山大雪懶開門，門徑行蹤自爾新。無酒禦寒雖寡況，", "晝短夜長須強學，學成貧亦勝他貧。"]'),
('yuding-103','送僧歸國清寺','杜荀鶴','唐','御定全唐诗','yuding','','[]','吟送越僧歸海涯，僧行渾不覺程賒。路沿山腳潮痕出，',40,'御定全唐詩/json/692.json','["吟送越僧歸海涯，僧行渾不覺程賒。路沿山腳潮痕出，", "到參禪後知無事，看引秋泉灌藕花。"]'),
('yuding-104','題汪明府山居','杜荀鶴','唐','御定全唐诗','yuding','','[]','不似當官只似閑，野情終日不離山。方知薄宦難拘束，',40,'御定全唐詩/json/692.json','["不似當官只似閑，野情終日不離山。方知薄宦難拘束，", "羨君公退歸欹枕，免向他門厚客顏。"]'),
('yuding-105','下第東歸將及故園有作','杜荀鶴','唐','御定全唐诗','yuding','','[]','平生操立有天知，何事謀身與志違。上國獻詩還不遇，',40,'御定全唐詩/json/692.json','["平生操立有天知，何事謀身與志違。上國獻詩還不遇，", "且把風寒作閒事，懶能和淚拜庭闈。"]'),
('yuding-106','宿東林寺題願公院','杜荀鶴','唐','御定全唐诗','yuding','','[]','古寺沉沉僧未眠，支頤將客說閑緣。一溪月色非塵世，',40,'御定全唐詩/json/692.json','["古寺沉沉僧未眠，支頤將客說閑緣。一溪月色非塵世，", "無由住得吟相伴，心系青雲十五年。"]'),
('yuding-107','山居自遣','杜荀鶴','唐','御定全唐诗','yuding','','[]','茅屋周回松竹陰，山翁時挈酒相尋。無人開口不言利，',40,'御定全唐詩/json/692.json','["茅屋周回松竹陰，山翁時挈酒相尋。無人開口不言利，", "此中一日過一日，有底閒愁得到心。"]'),
('yuding-108','贈友人罷舉赴辟命','杜荀鶴','唐','御定全唐诗','yuding','','[]','連天一水浸吳東，十幅帆飛二月風。好景采拋詩句裏，',40,'御定全唐詩/json/692.json','["連天一水浸吳東，十幅帆飛二月風。好景采拋詩句裏，", "不是桂枝終不得，自緣年少好從戎。"]'),
('yuding-109','亂後旅中遇友人','杜荀鶴','唐','御定全唐诗','yuding','','[]','念子為儒道未亨，依依心向十年兄。莫依亂世輕依託，',40,'御定全唐詩/json/692.json','["念子為儒道未亨，依依心向十年兄。莫依亂世輕依託，", "不如自此同歸去，帆掛秋風一信程。"]'),
('yuding-110','贈休糧僧','杜荀鶴','唐','御定全唐诗','yuding','','[]','自言因病學休糧，本意非求不死方。徒有至人傳道術，',40,'御定全唐詩/json/692.json','["自言因病學休糧，本意非求不死方。徒有至人傳道術，", "爭似吾師無一事，穩披雲衲坐藤床。"]'),
('yuding-111','維揚春日再遇孫侍禦','杜荀鶴','唐','御定全唐诗','yuding','','[]','本為榮家不為身，讀書誰料轉家貧。三年行卻千山路，',40,'御定全唐詩/json/692.json','["本為榮家不為身，讀書誰料轉家貧。三年行卻千山路，", "多情禦史應嗟見，未上青雲白髮新。"]'),
('yuding-112','亂後宿南陵廢寺寄沈明府','杜荀鶴','唐','御定全唐诗','yuding','','[]','只共寒燈坐到明，塞鴻沖雪一聲聲。亂時為客無人識，',40,'御定全唐詩/json/692.json','["只共寒燈坐到明，塞鴻沖雪一聲聲。亂時為客無人識，", "男兒仗劍酬恩在，未肯徒然過一生。"]'),
('yuding-113','投鄭先輩','杜荀鶴','唐','御定全唐诗','yuding','','[]','匣中長劍未酬恩，不遇男兒不合論。悶向酒杯吞日月，',40,'御定全唐詩/json/692.json','["匣中長劍未酬恩，不遇男兒不合論。悶向酒杯吞日月，", "兩鬢欲斑三百首，更教裝寫傍誰門。"]'),
('yuding-114','途中有作','杜荀鶴','唐','御定全唐诗','yuding','','[]','無論南北與西東，名利牽人處處同。枕上事仍多馬上，',40,'御定全唐詩/json/692.json','["無論南北與西東，名利牽人處處同。枕上事仍多馬上，", "百歲此身如且健，大家閑作臥雲翁。"]'),
('yuding-115','和舍弟題書堂','杜荀鶴','唐','御定全唐诗','yuding','','[]','兄弟將知大自強，亂時同葺讀書堂。岩泉遇雨多還鬧，',40,'御定全唐詩/json/692.json','["兄弟將知大自強，亂時同葺讀書堂。岩泉遇雨多還鬧，", "團圓便是家肥事，何必盈倉與滿箱。"]'),
('yuding-116','送蜀客遊維揚','杜荀鶴','唐','御定全唐诗','yuding','','[]','見說西川景物繁，維揚景物勝西川。青春花柳樹臨水，',40,'御定全唐詩/json/692.json','["見說西川景物繁，維揚景物勝西川。青春花柳樹臨水，", "送君懶問君回日，才子風流正少年。"]'),
('yuding-117','旅寓','杜荀鶴','唐','御定全唐诗','yuding','','[]','暗算鄉程隔數州，欲歸無計淚空流。已違骨肉來時約，',40,'御定全唐詩/json/692.json','["暗算鄉程隔數州，欲歸無計淚空流。已違骨肉來時約，", "去年今日還如此，似與青春有舊仇。"]'),
('yuding-118','途中春','杜荀鶴','唐','御定全唐诗','yuding','','[]','年光身事旋成空，畢竟何門遇至公。人世鶴歸雙鬢上，',40,'御定全唐詩/json/692.json','["年光身事旋成空，畢竟何門遇至公。人世鶴歸雙鬢上，", "一醉未醒花又落，故鄉回首楚關東。"]'),
('yuding-119','維揚冬末寄幕中二從事','杜荀鶴','唐','御定全唐诗','yuding','','[]','江上數株桑棗樹，自從離亂更荒涼。那堪旅館經殘臘，',40,'御定全唐詩/json/692.json','["江上數株桑棗樹，自從離亂更荒涼。那堪旅館經殘臘，", "故人多在芙蓉幕，應笑孜孜道未光。"]'),
('yuding-120','辭鄭員外入關','杜荀鶴','唐','御定全唐诗','yuding','','[]','男兒三十尚蹉跎，未遂青雲一桂科。在客易為銷歲月，',40,'御定全唐詩/json/692.json','["男兒三十尚蹉跎，未遂青雲一桂科。在客易為銷歲月，", "長把行藏信天道，不知天道竟如何。"]'),
('yuding-121','書齋即事','杜荀鶴','唐','御定全唐诗','yuding','','[]','時清只合力為儒，不可家貧與善疏。賣卻屋邊三畝地，',40,'御定全唐詩/json/692.json','["時清只合力為儒，不可家貧與善疏。賣卻屋邊三畝地，", "鄉里老農多見笑，不知稽古勝耕鋤。"]'),
('yuding-122','雋陽道中','杜荀鶴','唐','御定全唐诗','yuding','','[]','客路客路何悠悠，蟬聲向背槐花愁。爭知百歲不百歲，',40,'御定全唐詩/json/692.json','["客路客路何悠悠，蟬聲向背槐花愁。爭知百歲不百歲，", "輸他江上垂綸者，只在船中老便休。"]'),
('yuding-123','入關因別舍弟','杜荀鶴','唐','御定全唐诗','yuding','','[]','吾今別汝汝聽言，去住人情足可安。百口度荒均食易，',40,'御定全唐詩/json/692.json','["吾今別汝汝聽言，去住人情足可安。百口度荒均食易，", "天道不欺心意是，帝鄉吾土一般般。"]'),
('yuding-124','贈彭蠡釣者','杜荀鶴','唐','御定全唐诗','yuding','','[]','偏坐漁舟出葦林，葦花零落向秋深。只將波上鷗為侶，',40,'御定全唐詩/json/692.json','["偏坐漁舟出葦林，葦花零落向秋深。只將波上鷗為侶，", "若教我似君閑放，贏得湖山到老吟。"]'),
('yuding-125','送友人入關','杜荀鶴','唐','御定全唐诗','yuding','','[]','此去青雲莫更疑，出人才行足人知。況當朝野搜賢日，',40,'御定全唐詩/json/692.json','["此去青雲莫更疑，出人才行足人知。況當朝野搜賢日，", "我今不得同君去，兩鬢霜欺桂一枝。"]'),
('yuding-126','送友人宰潯陽','杜荀鶴','唐','御定全唐诗','yuding','','[]','高興那言去路長，非君不解愛潯陽。有時猿鳥來公署，',40,'御定全唐詩/json/692.json','["高興那言去路長，非君不解愛潯陽。有時猿鳥來公署，", "陶潛舊隱依稀在，好繼高蹤結草堂。"]'),
('yuding-127','秋日臥病','杜荀鶴','唐','御定全唐诗','yuding','','[]','浮世浮名能幾何，致身流落向天涯。少年心壯輕為客，',40,'御定全唐詩/json/692.json','["浮世浮名能幾何，致身流落向天涯。少年心壯輕為客，", "不堪吟罷西風起，黃葉滿庭寒日斜。"]'),
('yuding-128','敘吟','杜荀鶴','唐','御定全唐诗','yuding','','[]','多慚到處有詩名，轉覺吟詩僻性成。度水卻嫌船著岸，',40,'御定全唐詩/json/692.json','["多慚到處有詩名，轉覺吟詩僻性成。度水卻嫌船著岸，", "未合白頭今已白，自知非為別愁生。"]'),
('yuding-129','行次滎陽卻寄諸弟','杜荀鶴','唐','御定全唐诗','yuding','','[]','難把歸書說遠情，奉親多闕拙為兄。早知寸祿榮家晚，',40,'御定全唐詩/json/692.json','["難把歸書說遠情，奉親多闕拙為兄。早知寸祿榮家晚，", "如今已作長安計，只得辛勤取一名。"]'),
('yuding-130','登石壁禪師水閣有作','杜荀鶴','唐','御定全唐诗','yuding','','[]','石壁早聞僧說好，今來偏與我相宜。有山有水堪吟處，',40,'御定全唐詩/json/692.json','["石壁早聞僧說好，今來偏與我相宜。有山有水堪吟處，", "畫人畫得從他畫，六幅應輸八句詩。"]'),
('yuding-131','贈袒肩和尚','杜荀鶴','唐','御定全唐诗','yuding','','[]','山衣草屐染莓苔，雙眼猶慵向俗開。若比吾師居世上，',40,'御定全唐詩/json/692.json','["山衣草屐染莓苔，雙眼猶慵向俗開。若比吾師居世上，", "乘醉吟詩問禪理，為誰須去為誰來。"]'),
('yuding-132','閒居即事','杜荀鶴','唐','御定全唐诗','yuding','','[]','形覺清羸道覺肥，竹門前徑靜相宜。一壺村酒無求處，',40,'御定全唐詩/json/692.json','["形覺清羸道覺肥，竹門前徑靜相宜。一壺村酒無求處，", "一枝仙桂如攀得，只此山前是老期。"]'),
('yuding-133','自敘','杜荀鶴','唐','御定全唐诗','yuding','','[]','酒甕琴書伴病身，熟諳時事樂於貧。寧為宇宙閑吟客，',40,'御定全唐詩/json/692.json','["酒甕琴書伴病身，熟諳時事樂於貧。寧為宇宙閑吟客，", "平生肺腑無言處，白髮吾唐一逸人。"]'),
('yuding-134','空閒二公遞以禪律相鄙因而解之','杜荀鶴','唐','御定全唐诗','yuding','','[]','一教誰雲辟二途，律禪禪律智歸愚。念珠在手隳禪衲，',40,'御定全唐詩/json/692.json','["一教誰雲辟二途，律禪禪律智歸愚。念珠在手隳禪衲，", "有無無有師窮取，山到平來海亦枯。"]'),
('yuding-135','寄溫州朱尚書並呈軍倅崔太博','杜荀鶴','唐','御定全唐诗','yuding','','[]','永嘉名郡昔推名，連屬荀家弟與兄。教化靜師龔渤海，',40,'御定全唐詩/json/692.json','["永嘉名郡昔推名，連屬荀家弟與兄。教化靜師龔渤海，", "今日老輸崔博士，不妨疏逸伴雙旌。"]'),
('yuding-136','恩門致書遠及山居因獻之','杜荀鶴','唐','御定全唐诗','yuding','','[]','時難轉覺保身難，難向師門欲繼顏。若把白衣輕易脫，',40,'御定全唐詩/json/692.json','["時難轉覺保身難，難向師門欲繼顏。若把白衣輕易脫，", "必許酬恩酬未晚，且須容到九華山。"]'),
('yuding-137','寄溫州崔博士','杜荀鶴','唐','御定全唐诗','yuding','','[]','懷君勞我寫詩情，窣窣陰風有鬼聽。縣宰不仁工部餓，',40,'御定全唐詩/json/692.json','["懷君勞我寫詩情，窣窣陰風有鬼聽。縣宰不仁工部餓，", "好向賢侯話吟侶，莫教辜負少微星。"]'),
('yuding-138','李昭象雲與二三同人見訪有寄','杜荀鶴','唐','御定全唐诗','yuding','','[]','得君書後病顏開，雲拉同人訪我來。在路不妨沖雨雪，',40,'御定全唐詩/json/692.json','["得君書後病顏開，雲拉同人訪我來。在路不妨沖雨雪，", "貧舍款賓無別物，止於空戰大尊罍。"]'),
('yuding-139','自江西歸九華','杜荀鶴','唐','御定全唐诗','yuding','','[]','他鄉終日憶吾鄉，及到吾鄉值亂荒。雲外好山看不見，',40,'御定全唐詩/json/692.json','["他鄉終日憶吾鄉，及到吾鄉值亂荒。雲外好山看不見，", "許大乾坤吟未了，揮鞭回首出陵陽。"]'),
('yuding-140','和友人見題山居水閣八韻','杜荀鶴','唐','御定全唐诗','yuding','','[]','池閣初成眼豁開，眼前霽景屬微才。試攀簷果猿先見，',72,'御定全唐詩/json/692.json','["池閣初成眼豁開，眼前霽景屬微才。試攀簷果猿先見，", "南昌一榻延徐孺，楚國千鐘逼老萊。未稱執鞭奔紫陌，", "鑒己每將天作鏡，陶情常以海為杯。和君詩句吟聲大，"]'),
('yuding-0','感寓','杜荀鶴','唐','御定全唐诗','yuding','','[]','大海波濤淺，小人方寸深。海枯終見底，人死不知心。',24,'御定全唐詩/json/693.json','["大海波濤淺，小人方寸深。海枯終見底，人死不知心。"]'),
('yuding-1','春閨怨','杜荀鶴','唐','御定全唐诗','yuding','','[]','朝喜花豔春，暮悲花委塵。不悲花落早，悲妾似花身。',24,'御定全唐詩/json/693.json','["朝喜花豔春，暮悲花委塵。不悲花落早，悲妾似花身。"]'),
('yuding-2','馬上行','杜荀鶴','唐','御定全唐诗','yuding','','[]','五裏複五裏，去時無住時。日將家漸遠，猶恨馬行遲。',24,'御定全唐詩/json/693.json','["五裏複五裏，去時無住時。日將家漸遠，猶恨馬行遲。"]'),
('yuding-3','釣叟','杜荀鶴','唐','御定全唐诗','yuding','','[]','茅屋深灣裏，釣船橫竹門。經營衣食外，猶得弄兒孫。',24,'御定全唐詩/json/693.json','["茅屋深灣裏，釣船橫竹門。經營衣食外，猶得弄兒孫。"]'),
('yuding-4','再經胡城縣','杜荀鶴','唐','御定全唐诗','yuding','','[]','去歲曾經此縣城，縣民無口不冤聲。',32,'御定全唐詩/json/693.json','["去歲曾經此縣城，縣民無口不冤聲。", "今來縣宰加朱紱，便是生靈血染成。"]'),
('yuding-5','讀諸家詩','杜荀鶴','唐','御定全唐诗','yuding','','[]','辭賦文章能者稀，難中難者莫過詩。',32,'御定全唐詩/json/693.json','["辭賦文章能者稀，難中難者莫過詩。", "直應吟骨無生死，只我前身是阿誰。"]'),
('yuding-6','春來燕','杜荀鶴','唐','御定全唐诗','yuding','','[]','我屋汝嫌低不住，雕梁畫閣也知寬。',32,'御定全唐詩/json/693.json','["我屋汝嫌低不住，雕梁畫閣也知寬。", "大須穩擇安巢處，莫道巢成卻不安。"]'),
('yuding-7','清溪來明府出二子請詩因遺一絕','杜荀鶴','唐','御定全唐诗','yuding','','[]','珠明玉潤盡驚人，不稱寒門不稱貧。',32,'御定全唐詩/json/693.json','["珠明玉潤盡驚人，不稱寒門不稱貧。", "若向吾唐作雙瑞，便同祥鳳與祥麟。"]'),
('yuding-8','哭陳陶','杜荀鶴','唐','御定全唐诗','yuding','','[]','耒陽山下傷工部，採石江邊吊翰林。',32,'御定全唐詩/json/693.json','["耒陽山下傷工部，採石江邊吊翰林。", "兩地荒墳各三尺，卻成開解哭君心。"]'),
('yuding-9','哭貝韜','杜荀鶴','唐','御定全唐诗','yuding','','[]','交朋來哭我來歌，喜傍山家葬荔蘿。',32,'御定全唐詩/json/693.json','["交朋來哭我來歌，喜傍山家葬荔蘿。", "四海十年人殺盡，似君埋少不埋多。"]'),
('yuding-10','蠶婦','杜荀鶴','唐','御定全唐诗','yuding','','[]','粉色全無饑色加，豈知人世有榮華。',32,'御定全唐詩/json/693.json','["粉色全無饑色加，豈知人世有榮華。", "年年道我蠶辛苦，底事渾身著苧麻。"]'),
('yuding-11','山寺老僧','杜荀鶴','唐','御定全唐诗','yuding','','[]','草靸無塵心地閑，靜隨猿鳥過寒暄。',32,'御定全唐詩/json/693.json','["草靸無塵心地閑，靜隨猿鳥過寒暄。", "眼昏齒落看經遍，卻向僧中總不言。"]'),
('yuding-12','閩中秋思','杜荀鶴','唐','御定全唐诗','yuding','','[]','雨勻紫菊叢叢色，風弄紅蕉葉葉聲。',32,'御定全唐詩/json/693.json','["雨勻紫菊叢叢色，風弄紅蕉葉葉聲。", "北畔是山南畔海，只堪圖畫不堪行。"]'),
('yuding-13','八駿圖','杜荀鶴','唐','御定全唐诗','yuding','','[]','丹雘傳真未得真，那知筋骨與精神。',32,'御定全唐詩/json/693.json','["丹雘傳真未得真，那知筋骨與精神。", "只今恃駿憑毛色，綠耳驊騮賺殺人。"]'),
('yuding-14','贈僧','杜荀鶴','唐','御定全唐诗','yuding','','[]','利門名路兩何憑，百歲風前短焰燈。',32,'御定全唐詩/json/693.json','["利門名路兩何憑，百歲風前短焰燈。", "只恐為僧僧不了，為僧得了總輸僧。"]'),
('yuding-15','秋夕','杜荀鶴','唐','御定全唐诗','yuding','','[]','世間多少能詩客，誰是無愁得睡人。',32,'御定全唐詩/json/693.json','["世間多少能詩客，誰是無愁得睡人。", "自我夜來霜月下，到頭吟魄始終身。"]'),
('yuding-16','溪興','杜荀鶴','唐','御定全唐诗','yuding','','[]','山雨溪風卷釣絲，瓦甌篷底獨斟時。',32,'御定全唐詩/json/693.json','["山雨溪風卷釣絲，瓦甌篷底獨斟時。", "醉來睡著無人喚，流下前溪也不知。"]'),
('yuding-17','過巢湖','杜荀鶴','唐','御定全唐诗','yuding','','[]','世人貪利複貪榮，來向湖邊始至誠。',32,'御定全唐詩/json/693.json','["世人貪利複貪榮，來向湖邊始至誠。", "男子登舟與登陸，把心何不一般行。"]'),
('yuding-18','傷硤石縣病叟','杜荀鶴','唐','御定全唐诗','yuding','','[]','無子無孫一病翁，將何筋力事耕農。',32,'御定全唐詩/json/693.json','["無子無孫一病翁，將何筋力事耕農。", "官家不管蓬蒿地，須勒王租出此中。"]'),
('yuding-19','贈老僧','杜荀鶴','唐','御定全唐诗','yuding','','[]','童子為僧今白首，暗鋤心地種閒情。',32,'御定全唐詩/json/693.json','["童子為僧今白首，暗鋤心地種閒情。", "時將舊衲添新線，披坐披行過一生。"]'),
('yuding-20','釣叟','杜荀鶴','唐','御定全唐诗','yuding','','[]','田不曾耕地不鋤，誰人閒散得如渠。',32,'御定全唐詩/json/693.json','["田不曾耕地不鋤，誰人閒散得如渠。", "渠將底物為香餌，一度抬竿一個魚。"]'),
('yuding-21','溪岸秋思','杜荀鶴','唐','御定全唐诗','yuding','','[]','桑柘窮頭三四家，掛罾垂釣是生涯。',32,'御定全唐詩/json/693.json','["桑柘窮頭三四家，掛罾垂釣是生涯。", "秋風忽起溪灘白，零落岸邊蘆荻花。"]'),
('yuding-22','春日旅寓','杜荀鶴','唐','御定全唐诗','yuding','','[]','滿城羅綺拖春色，幾處笙歌揭畫樓。',32,'御定全唐詩/json/693.json','["滿城羅綺拖春色，幾處笙歌揭畫樓。", "江上有家歸未得，眼前花是眼前愁。"]'),
('yuding-23','田翁','杜荀鶴','唐','御定全唐诗','yuding','','[]','白髮星星筋力衰，種田猶自伴孫兒。',32,'御定全唐詩/json/693.json','["白髮星星筋力衰，種田猶自伴孫兒。", "官苗若不平平納，任是豐年也受饑。"]'),
('yuding-24','秋江雨夜逢詩友','杜荀鶴','唐','御定全唐诗','yuding','','[]','故友別來三四載，新詩吟得百餘篇。',32,'御定全唐詩/json/693.json','["故友別來三四載，新詩吟得百餘篇。", "夜來江上秋無月，恨不相逢在雪天。"]'),
('yuding-25','感春','杜荀鶴','唐','御定全唐诗','yuding','','[]','無況青雲有恨身，眼前花似夢中春。',32,'御定全唐詩/json/693.json','["無況青雲有恨身，眼前花似夢中春。", "浮生七十今三十，已是人間半世人。"]'),
('yuding-26','題花木障','杜荀鶴','唐','御定全唐诗','yuding','','[]','不假東風次第吹，筆勻春色一枝枝。',32,'御定全唐詩/json/693.json','["不假東風次第吹，筆勻春色一枝枝。", "由來畫看勝栽看，免見朝開暮落時。"]'),
('yuding-27','顧雲侍禦出二子請詩因遺一絕','杜荀鶴','唐','御定全唐诗','yuding','','[]','二雛毛骨秀仍奇，小小能吟大大詩。',32,'御定全唐詩/json/693.json','["二雛毛骨秀仍奇，小小能吟大大詩。", "想得月中仙桂樹，各從生日長新枝。"]'),
('yuding-28','秋夕病中','杜荀鶴','唐','御定全唐诗','yuding','','[]','壞屋不眠風雨夜，故園無信水雲秋。',32,'御定全唐詩/json/693.json','["壞屋不眠風雨夜，故園無信水雲秋。", "病中枕上誰相問，一一蟬聲槐樹頭。"]'),
('yuding-29','宿欒城驛卻寄常山張書記','杜荀鶴','唐','御定全唐诗','yuding','','[]','一更更盡到三更，吟破離心句不成。',32,'御定全唐詩/json/693.json','["一更更盡到三更，吟破離心句不成。", "數樹秋風滿庭月，憶君時複下階行。"]'),
('yuding-30','湘江秋夕','杜荀鶴','唐','御定全唐诗','yuding','','[]','三湘月色三湘水，浸骨寒光似練鋪。',32,'御定全唐詩/json/693.json','["三湘月色三湘水，浸骨寒光似練鋪。", "一夜塞鴻來不住，故鄉書信半年無。"]'),
('yuding-31','旅懷','杜荀鶴','唐','御定全唐诗','yuding','','[]','蒹葭月冷時聞雁，楊柳風和日聽鶯。',32,'御定全唐詩/json/693.json','["蒹葭月冷時聞雁，楊柳風和日聽鶯。", "水涉山行二年客，就中偏怕雨船聲。"]'),
('yuding-32','贈崔道士','杜荀鶴','唐','御定全唐诗','yuding','','[]','四海兵戈無靜處，人家廢業望烽煙。',32,'御定全唐詩/json/693.json','["四海兵戈無靜處，人家廢業望烽煙。", "九華道士渾如夢，猶向尊前笑揭天。"]'),
('yuding-33','題道林寺','杜荀鶴','唐','御定全唐诗','yuding','','[]','身未立間終日苦，身當立後幾年榮。',32,'御定全唐詩/json/693.json','["身未立間終日苦，身當立後幾年榮。", "萬般不及僧無事，共水將山過一生。"]'),
('yuding-34','贈質上人','杜荀鶴','唐','御定全唐诗','yuding','','[]','枿坐雲遊出世塵，兼無瓶缽可隨身。',32,'御定全唐詩/json/693.json','["枿坐雲遊出世塵，兼無瓶缽可隨身。", "逢人不說人間事，便是人間無事人。"]'),
('yuding-35','涇溪','杜荀鶴','唐','御定全唐诗','yuding','','[]','涇溪石險人兢慎，終歲不聞傾覆人。',32,'御定全唐詩/json/693.json','["涇溪石險人兢慎，終歲不聞傾覆人。", "卻是平流無石處，時時聞說有沈淪。"]'),
('yuding-36','夏日題悟空上人院','杜荀鶴','唐','御定全唐诗','yuding','','[]','三伏閉門披一衲，兼無松竹蔭房廊。',32,'御定全唐詩/json/693.json','["三伏閉門披一衲，兼無松竹蔭房廊。", "安禪不必須山水，滅得心中火自涼。"]'),
('yuding-37','經嚴陵釣台','杜荀鶴','唐','御定全唐诗','yuding','','[]','蒼翠雲峰開俗眼，泓澄煙水浸塵心。',32,'御定全唐詩/json/693.json','["蒼翠雲峰開俗眼，泓澄煙水浸塵心。", "唯將道業為芳餌，釣得高名直至今。"]'),
('yuding-38','關試後筵上別同人','杜荀鶴','唐','御定全唐诗','yuding','','[]','日午離筵到夕陽，明朝秦地與吳鄉。',32,'御定全唐詩/json/693.json','["日午離筵到夕陽，明朝秦地與吳鄉。", "同年多是長安客，不信行人欲斷腸。"]'),
('yuding-39','鸕鷀','杜荀鶴','唐','御定全唐诗','yuding','','[]','一般毛羽結群飛，雨岸煙汀好景時。',32,'御定全唐詩/json/693.json','["一般毛羽結群飛，雨岸煙汀好景時。", "深水有魚銜得出，看來卻是鷺鶿饑。"]'),
('yuding-40','宿村舍','杜荀鶴','唐','御定全唐诗','yuding','','[]','野人于我有何情，半掩柴門向月明。',32,'御定全唐詩/json/693.json','["野人于我有何情，半掩柴門向月明。", "深夜欲眠眠未著，一叢寒木一猿聲。"]'),
('yuding-41','題新雁','杜荀鶴','唐','御定全唐诗','yuding','','[]','暮天新雁起汀洲，紅蓼花疏水國秋。',32,'御定全唐詩/json/693.json','["暮天新雁起汀洲，紅蓼花疏水國秋。", "想得故園今夜月，幾人相憶在江樓。"]'),
('yuding-42','離家','杜荀鶴','唐','御定全唐诗','yuding','','[]','丈夫三十身如此，疲馬離鄉懶著鞭。',32,'御定全唐詩/json/693.json','["丈夫三十身如此，疲馬離鄉懶著鞭。", "槐柳路長愁殺我，一枝蟬到一枝蟬。"]'),
('yuding-43','旅舍遇雨','杜荀鶴','唐','御定全唐诗','yuding','','[]','月華星彩坐來收，岳色江聲暗結愁。',32,'御定全唐詩/json/693.json','["月華星彩坐來收，岳色江聲暗結愁。", "半夜燈前十年事，一時和雨到心頭。"]'),
('yuding-44','送人歸淝上','杜荀鶴','唐','御定全唐诗','yuding','','[]','巢湖春漲喻溪深，才過東關見故林。',32,'御定全唐詩/json/693.json','["巢湖春漲喻溪深，才過東關見故林。", "莫道南來總無利，水亭山寺二年吟。"]'),
('yuding-45','自遣','杜荀鶴','唐','御定全唐诗','yuding','','[]','糲食粗衣隨分過，堆金積帛欲如何。',32,'御定全唐詩/json/693.json','["糲食粗衣隨分過，堆金積帛欲如何。", "百年身後一丘土，貧富高低爭幾多。"]'),
('yuding-46','聞子規','杜荀鶴','唐','御定全唐诗','yuding','','[]','楚天空闊月成輪，蜀魄聲聲似告人。',32,'御定全唐詩/json/693.json','["楚天空闊月成輪，蜀魄聲聲似告人。", "啼得血流無用處，不如緘口過殘春。"]'),
('yuding-47','秋夜苦吟','杜荀鶴','唐','御定全唐诗','yuding','','[]','吟盡三更未著題，竹風松雨花淒淒。',32,'御定全唐詩/json/693.json','["吟盡三更未著題，竹風松雨花淒淒。", "此時若有人來聽，始覺巴猿不解啼。"]'),
('yuding-48','秋夜聞砧','杜荀鶴','唐','御定全唐诗','yuding','','[]','荒涼客舍眠秋色，砧杵家家弄月明。',32,'御定全唐詩/json/693.json','["荒涼客舍眠秋色，砧杵家家弄月明。", "不及巴山聽猿夜，三聲中有不愁聲。"]'),
('yuding-49','將過湖南經馬當山廟因書三絕','杜荀鶴','唐','御定全唐诗','yuding','','[]','人說馬當波浪險，我經波浪似通衢。',96,'御定全唐詩/json/693.json','["人說馬當波浪險，我經波浪似通衢。", "大凡君子行藏是，自有龍神衛過湖。", "貪殘官吏虔誠謁，毒害商人瀝膽過。", "只怕馬當山下水，不知平地有風波。", "九江連海一般深，未必船經廟下沈。", "頭上蒼蒼沒瞞處，不如平取一生心。"]'),
('yuding-50','梁王坐上賦無雲雨','杜荀鶴','唐','御定全唐诗','yuding','','[]','同是乾坤事不同，雨絲飛灑日輪中。',32,'御定全唐詩/json/693.json','["同是乾坤事不同，雨絲飛灑日輪中。", "若教陰朗長相似，爭表梁王造化功。"]'),
('yuding-51','小松','杜荀鶴','唐','御定全唐诗','yuding','','[]','自小刺頭深草裏，而今漸覺出蓬蒿。',32,'御定全唐詩/json/693.json','["自小刺頭深草裏，而今漸覺出蓬蒿。", "時人不識淩雲木，直待淩雲始道高。"]'),
('yuding-52','醉書僧壁','杜荀鶴','唐','御定全唐诗','yuding','','[]','九華山色真堪愛，留得高僧爾許年。',32,'御定全唐詩/json/693.json','["九華山色真堪愛，留得高僧爾許年。", "聽我吟詩供我酒，不曾穿得判齋錢。"]'),
('yuding-53','寄李隱居','杜荀鶴','唐','御定全唐诗','yuding','','[]','自小棲玄到老閑，如雲如鶴住應難。',32,'御定全唐詩/json/693.json','["自小棲玄到老閑，如雲如鶴住應難。", "溪山不必將錢買，贏得來來去去看。"]'),
('yuding-54','句','杜荀鶴','唐','御定全唐诗','yuding','','[]','舊衣灰絮絮，新酒竹篘篘。',41,'御定全唐詩/json/693.json','["舊衣灰絮絮，新酒竹篘篘。", "只知斷送豪家酒，不解安排旅客情。（《聞笛》。", "《吟窗雜錄》）"]'),
('yuding-0','上蜀王','張道古','唐','御定全唐诗','yuding','','[]','封章才達冕旒前，黜詔俄離玉座端。二亂豈由明主用，',40,'御定全唐詩/json/694.json','["封章才達冕旒前，黜詔俄離玉座端。二亂豈由明主用，", "諫疏至今如可在，誰能更與讀來看。"]'),
('yuding-1','詠雨','張道古','唐','御定全唐诗','yuding','','[]','亢陽今已久，嘉雨自雲傾。一點不斜去，極多時下成。',24,'御定全唐詩/json/694.json','["亢陽今已久，嘉雨自雲傾。一點不斜去，極多時下成。"]'),
('yuding-2','楊岐山','唐廩','唐','御定全唐诗','yuding','','[]','逗竹穿花越幾村，還從舊路入雲門。翠微不閉樓臺出，',40,'御定全唐詩/json/694.json','["逗竹穿花越幾村，還從舊路入雲門。翠微不閉樓臺出，", "重來白首良堪喜，朝露浮生不足言。"]'),
('yuding-3','吹笙引','王轂','唐','御定全唐诗','yuding','','[]','媧皇遺音寄玉笙，雙成傳得何淒清。丹穴嬌雛七十只，',48,'御定全唐詩/json/694.json','["媧皇遺音寄玉笙，雙成傳得何淒清。丹穴嬌雛七十只，", "旖旎香風繞指生，千聲妙盡神仙曲。曲終滿席悄無語，"]'),
('yuding-4','鴻門宴','王轂','唐','御定全唐诗','yuding','','[]','寰海沸兮爭戰苦，風雲愁兮會龍虎。四百年漢欲開基，',40,'御定全唐詩/json/694.json','["寰海沸兮爭戰苦，風雲愁兮會龍虎。四百年漢欲開基，", "項王足底踏漢土，席上相看渾未悟。"]'),
('yuding-5','玉樹曲','王轂','唐','御定全唐诗','yuding','','[]','陳宮內宴明朝日，玉樹新妝逞嬌逸。三閣霞明天上開，',88,'御定全唐詩/json/694.json','["陳宮內宴明朝日，玉樹新妝逞嬌逸。三閣霞明天上開，", "金管紅弦旖旎隨，霓旌玉佩參差轉。璧月夜滿樓風輕，", "歌舞未終樂未闋，晉王劍上粘腥血。君臣猶在醉鄉中，", "請停此曲歸正聲，願將雅樂調元氣。"]'),
('yuding-6','苦熱行','王轂','唐','御定全唐诗','yuding','','[]','祝融南來鞭火龍，火旗焰焰燒天紅。日輪當午凝不去，',40,'御定全唐詩/json/694.json','["祝融南來鞭火龍，火旗焰焰燒天紅。日輪當午凝不去，", "何當一夕金風發，為我掃卻天下熱。"]'),
('yuding-7','暑日題道邊樹','王轂','唐','御定全唐诗','yuding','','[]','火輪迸焰燒長空，浮埃撲面愁朦朦。羸童走馬喘不進，',40,'御定全唐詩/json/694.json','["火輪迸焰燒長空，浮埃撲面愁朦朦。羸童走馬喘不進，", "卻歎人無及物功，不似團團道邊樹。"]'),
('yuding-8','紅薔薇歌','王轂','唐','御定全唐诗','yuding','','[]','紅霞爛潑猩猩血，阿母瑤池曬仙纈。晚日春風奪眼明，',40,'御定全唐詩/json/694.json','["紅霞爛潑猩猩血，阿母瑤池曬仙纈。晚日春風奪眼明，", "苧羅西子見應妒，風光占斷年年新。"]'),
('yuding-9','刺桐花','王轂','唐','御定全唐诗','yuding','','[]','南國清和煙雨辰，刺桐夾道花開新。林梢簇簇紅霞爛，',40,'御定全唐詩/json/694.json','["南國清和煙雨辰，刺桐夾道花開新。林梢簇簇紅霞爛，", "直疑青帝去匆匆，收拾春風渾不盡。"]'),
('yuding-10','贈蒼溪王明府有文在手曰長生','王轂','唐','御定全唐诗','yuding','','[]','執手長生在，人皆號地仙。水雲真遂性，龜鶴足齊年。',48,'御定全唐詩/json/694.json','["執手長生在，人皆號地仙。水雲真遂性，龜鶴足齊年。", "但以酒養氣，何言命在天。況無婚嫁累，應拍尚平肩。"]'),
('yuding-11','逢道者神和子','王轂','唐','御定全唐诗','yuding','','[]','珍重神和子，聞名五十年。童顏終不改，綠發尚依然。',48,'御定全唐詩/json/694.json','["珍重神和子，聞名五十年。童顏終不改，綠發尚依然。", "酒裏消閒日，人間作散仙。長生如可慕，相逐隱林泉。"]'),
('yuding-12','送友人歸閩','王轂','唐','御定全唐诗','yuding','','[]','東南歸思切，把酒且留連。再會知何處，相看共黯然。',48,'御定全唐詩/json/694.json','["東南歸思切，把酒且留連。再會知何處，相看共黯然。", "猿啼梨嶺路，月白建溪船。莫戀家鄉住，酬身在少年。"]'),
('yuding-13','春草碧色','王轂','唐','御定全唐诗','yuding','','[]','習習東風扇，萋萋草色新。淺深千里碧，高下一時春。',72,'御定全唐詩/json/694.json','["習習東風扇，萋萋草色新。淺深千里碧，高下一時春。", "嫩葉舒煙際，微香動水濱。金塘明夕照，輦路惹芳塵。", "造化功何廣，陽和力自均。今當發生日，瀝懇祝良辰。"]'),
('yuding-14','夢仙謠三首','王轂','唐','御定全唐诗','yuding','','[]','前程漸覺風光好，琪花片片粘瑤草。',96,'御定全唐詩/json/694.json','["前程漸覺風光好，琪花片片粘瑤草。", "有人遺我五色丹，一粒吞之後天老。", "青童遞酒金觴疾，列坐紅霞神氣逸。", "笑說留連數日間，已是人間一千日。", "瑤台絳節遊皆遍，異果奇花香撲面。", "松窗夢覺卻神清，殘月林前三兩片。"]'),
('yuding-15','後魏行','王轂','唐','御定全唐诗','yuding','','[]','力微皇帝謗天嗣，太武兇殘人所畏。',33,'御定全唐詩/json/694.json','["力微皇帝謗天嗣，太武兇殘人所畏。", "一朝羖qj飛上天，子孫盡作河魚餌。"]'),
('yuding-16','秋','王轂','唐','御定全唐诗','yuding','','[]','蟬噪古槐疏葉下，樹銜斜日映孤城。',32,'御定全唐詩/json/694.json','["蟬噪古槐疏葉下，樹銜斜日映孤城。", "欲知潘鬢愁多少，一夜新添白數莖。"]'),
('yuding-17','燕','王轂','唐','御定全唐诗','yuding','','[]','海燕雙飛意若何，曲梁嘔嘎語聲多。',32,'御定全唐詩/json/694.json','["海燕雙飛意若何，曲梁嘔嘎語聲多。", "茅簷不必嫌卑陋，猶勝吳宮爇爾窠。"]'),
('yuding-18','牡丹','王轂','唐','御定全唐诗','yuding','','[]','牡丹妖豔亂人心，一國如狂不惜金。',32,'御定全唐詩/json/694.json','["牡丹妖豔亂人心，一國如狂不惜金。", "曷若東園桃與李，果成無語自垂陰。"]'),
('yuding-19','古意二首','孫合','唐','御定全唐诗','yuding','','[]','屈子生楚國，七雄知其材。介潔世不容，跡合藏蒿萊。',96,'御定全唐詩/json/694.json','["屈子生楚國，七雄知其材。介潔世不容，跡合藏蒿萊。", "道廢固命也，瓢飲亦賢哉。何事葬江水，空使後人哀。", "魏禮段幹木，秦王乃止戈。小國有其人，大國奈之何。", "賢哲信為美，兵甲豈雲多。君子戰必勝，斯言聞孟軻。"]'),
('yuding-20','哭方玄英先生','孫合','唐','御定全唐诗','yuding','','[]','牛鬥文星落，知是先生死。湖上聞哭聲，門前見彈指。',72,'御定全唐詩/json/694.json','["牛鬥文星落，知是先生死。湖上聞哭聲，門前見彈指。", "官無一寸祿，名傳千萬里。死著弊衣裳，生誰顧朱紫。", "我心痛其語，淚落不能已。猶喜韋補闕，揚名薦天子。"]'),
('yuding-21','句','孫合','唐','御定全唐诗','yuding','','[]','仕宦類商賈，終日常東西。',12,'御定全唐詩/json/694.json','["仕宦類商賈，終日常東西。"]'),
('yuding-22','投節度邢公','褚載','唐','御定全唐诗','yuding','','[]','西風昨夜墜紅蘭，一宿郵亭事萬般。無地可耕歸不得，',40,'御定全唐詩/json/694.json','["西風昨夜墜紅蘭，一宿郵亭事萬般。無地可耕歸不得，", "一卷新書滿懷淚，頻來門館訴饑寒。"]'),
('yuding-23','賀趙觀文重試及第','褚載','唐','御定全唐诗','yuding','','[]','一枝仙桂兩回春。始覺文章可致身。已把色絲要上第，',40,'御定全唐詩/json/694.json','["一枝仙桂兩回春。始覺文章可致身。已把色絲要上第，", "今日街頭看禦榜，大能榮耀苦心人。"]'),
('yuding-24','贈道士','褚載','唐','御定全唐诗','yuding','','[]','簪星曳月下蓬壺，曾見東皋種白榆。六甲威靈藏瑞檢，',40,'御定全唐詩/json/694.json','["簪星曳月下蓬壺，曾見東皋種白榆。六甲威靈藏瑞檢，", "聞說葛陂風浪惡，許騎青鹿從行無。"]'),
('yuding-25','曉發','褚載','唐','御定全唐诗','yuding','','[]','貪路貪名須早發，枕前無計暫裴回。才聞雞唱呼童起，',40,'御定全唐詩/json/694.json','["貪路貪名須早發，枕前無計暫裴回。才聞雞唱呼童起，", "朝朝陌上侵星去，待得酬身了便回。"]'),
('yuding-26','曉感','褚載','唐','御定全唐诗','yuding','','[]','曉鼓冬冬星漢微，佩金鳴玉鬥光輝。出門各自爭岐路，',40,'御定全唐詩/json/694.json','["曉鼓冬冬星漢微，佩金鳴玉鬥光輝。出門各自爭岐路，", "故園華表高高在，可得不如丁令威。"]'),
('yuding-27','南徐晚望','褚載','唐','御定全唐诗','yuding','','[]','芳草鋪香晚岸晴，岸頭含醉去來行。僧歸岳外殘鐘寺，',40,'御定全唐詩/json/694.json','["芳草鋪香晚岸晴，岸頭含醉去來行。僧歸岳外殘鐘寺，", "如今未免風塵役，寧敢匆匆便濯纓。"]'),
('yuding-28','移石','褚載','唐','御定全唐诗','yuding','','[]','嶙峋一片溪中石，恰稱幽人彈素琴。浪浸多年苔色在，',40,'御定全唐詩/json/694.json','["嶙峋一片溪中石，恰稱幽人彈素琴。浪浸多年苔色在，", "不是不堪為器用，都緣良匠未留心。"]'),
('yuding-29','瀑布','褚載','唐','御定全唐诗','yuding','','[]','瀉霧傾煙撼撼雷，滿山風雨助喧豗。爭知不是青天闕，撲下銀河一半來。',32,'御定全唐詩/json/694.json','["瀉霧傾煙撼撼雷，滿山風雨助喧豗。爭知不是青天闕，撲下銀河一半來。"]'),
('yuding-30','定鼎門','褚載','唐','御定全唐诗','yuding','','[]','郟鄏城高門倚天，九重蹤跡尚依然。',32,'御定全唐詩/json/694.json','["郟鄏城高門倚天，九重蹤跡尚依然。", "須知道德無關鎖，一閉乾坤一萬年。"]'),
('yuding-31','陳倉驛','褚載','唐','御定全唐诗','yuding','','[]','錦翼花冠安在哉，雄飛雌伏盡塵埃。',32,'御定全唐詩/json/694.json','["錦翼花冠安在哉，雄飛雌伏盡塵埃。", "一雙童子應惆悵，不見真人更獵來。"]'),
('yuding-32','長城','褚載','唐','御定全唐诗','yuding','','[]','秦築長城比鐵牢，蕃戎不敢過臨洮。',32,'御定全唐詩/json/694.json','["秦築長城比鐵牢，蕃戎不敢過臨洮。", "焉知萬里連雲色，不及堯階三尺高。"]'),
('yuding-33','吊秦叟','褚載','唐','御定全唐诗','yuding','','[]','市西樓店金千秤，渭北田園粟萬鐘。',32,'御定全唐詩/json/694.json','["市西樓店金千秤，渭北田園粟萬鐘。", "兒被殺傷妻被虜，一身隨駕到三峰。"]'),
('yuding-34','雲','褚載','唐','御定全唐诗','yuding','','[]','盡日看雲首不回，無心都大似無才。',32,'御定全唐詩/json/694.json','["盡日看雲首不回，無心都大似無才。", "可憐光采一片玉，萬里晴天何處來。"]'),
('yuding-35','鶴','褚載','唐','御定全唐诗','yuding','','[]','欲洗霜翎下澗邊，卻嫌菱刺汙香泉。',32,'御定全唐詩/json/694.json','["欲洗霜翎下澗邊，卻嫌菱刺汙香泉。", "沙鷗浦雁應驚訝，一舉扶搖直上天。"]'),
('yuding-36','句','褚載','唐','御定全唐诗','yuding','','[]','相逢多是醉醺然，應有囊中子母錢。',160,'御定全唐詩/json/694.json','["相逢多是醉醺然，應有囊中子母錢。", "有興欲沽紅麴酒，無人同上翠旌樓。", "星斗離披煙靄收，玉蟾蜍耀海東頭。", "鹿胎冠子水晶簪，長嘯欹眠紫桂陰。", "躞蹀馬搖金絡腦，嬋娟人墜玉搔頭。", "狂歌放飲渾成性，知道逍遙出俗籠。", "除卻洛陽才子後，更誰封恨吊懷沙。", "蓮浦浪澄堪倚釣，柳堤風暖好垂鞭。", "上馬等閒銷白日，出門輕薄倚黃金。", "淨名方丈雖然病，曼倩年涯未有多。"]'),
('yuding-37','代寄邊人','鄭准','唐','御定全唐诗','yuding','','[]','君去不來久，悠悠昏又明。片心因卜解，殘夢過橋驚。',48,'御定全唐詩/json/694.json','["君去不來久，悠悠昏又明。片心因卜解，殘夢過橋驚。", "聖澤如垂餌，沙場會息兵。涼風當為我，一一送砧聲。"]'),
('yuding-38','江南清明','鄭准','唐','御定全唐诗','yuding','','[]','吳山楚驛四年中，一見清明一改容。旅恨共風連夜起，',40,'御定全唐詩/json/694.json','["吳山楚驛四年中，一見清明一改容。旅恨共風連夜起，", "無限歸心何計是，路邊戈甲正重重。"]'),
('yuding-39','題宛陵北樓','鄭准','唐','御定全唐诗','yuding','','[]','雨來風靜綠蕪蘚，憑著朱闌思浩然。人語獨耕燒後嶺，',40,'御定全唐詩/json/694.json','["雨來風靜綠蕪蘚，憑著朱闌思浩然。人語獨耕燒後嶺，", "若遣謝宣城不死，必應吟盡夕陽川。"]'),
('yuding-40','寄進士崔魯范','鄭准','唐','御定全唐诗','yuding','','[]','洛陽才子舊交知，別後干戈積詠思。百戰市朝千里夢，',40,'御定全唐詩/json/694.json','["洛陽才子舊交知，別後干戈積詠思。百戰市朝千里夢，", "會待路寧歸得去，酒樓漁浦重相期。"]'),
('yuding-41','雲','鄭准','唐','御定全唐诗','yuding','','[]','片片飛來靜又閑，樓頭江上複山前。',32,'御定全唐詩/json/694.json','["片片飛來靜又閑，樓頭江上複山前。", "飄零盡日不歸去，點破清光萬里天。"]'),
('yuding-42','句','鄭准','唐','御定全唐诗','yuding','','[]','護犢橫身立，逢人揭尾跳。',12,'御定全唐詩/json/694.json','["護犢橫身立，逢人揭尾跳。"]'),
('yuding-43','遊九鯉湖','陳乘','唐','御定全唐诗','yuding','','[]','汗漫乘春至，林巒霧雨生。洞莓黏屐重，岩雪濺衣輕。',48,'御定全唐詩/json/694.json','["汗漫乘春至，林巒霧雨生。洞莓黏屐重，岩雪濺衣輕。", "窟宅分三島，煙霞接五城。卻憐饒藥物，欲辨不知名。"]'),
('yuding-0','章台夜思','韋莊','唐','御定全唐诗','yuding','','[]','清瑟怨遙夜，繞弦風雨哀。孤燈聞楚角，殘月下章台。',48,'御定全唐詩/json/695.json','["清瑟怨遙夜，繞弦風雨哀。孤燈聞楚角，殘月下章台。", "芳草已雲暮，故人殊未來。鄉書不可寄，秋雁又南回。"]'),
('yuding-1','延興門外作','韋莊','唐','御定全唐诗','yuding','','[]','芳草五陵道，美人金犢車。綠奔穿內水，紅落過牆花。',48,'御定全唐詩/json/695.json','["芳草五陵道，美人金犢車。綠奔穿內水，紅落過牆花。", "馬足倦遊客，鳥聲歡酒家。王孫歸去晚，宮樹欲棲鴉。"]'),
('yuding-2','劉得仁墓','韋莊','唐','御定全唐诗','yuding','','[]','至公遺至藝，終抱至冤沈。名有詩家業，身無戚裏心。',48,'御定全唐詩/json/695.json','["至公遺至藝，終抱至冤沈。名有詩家業，身無戚裏心。", "桂和秋露滴，松帶夜風吟。冥寞知春否，墳蒿日已深。"]'),
('yuding-3','下第題青龍寺僧房','韋莊','唐','御定全唐诗','yuding','','[]','千蹄萬轂一枝芳，要路無媒果自傷。題柱未期歸蜀國，',40,'御定全唐詩/json/695.json','["千蹄萬轂一枝芳，要路無媒果自傷。題柱未期歸蜀國，", "酒薄恨濃消不得，卻將惆悵問支郎。"]'),
('yuding-4','虢州澗東村居作','韋莊','唐','御定全唐诗','yuding','','[]','東南騎馬出郊坰，回首寒煙隔郡城。清澗漲時翹鷺喜，',40,'御定全唐詩/json/695.json','["東南騎馬出郊坰，回首寒煙隔郡城。清澗漲時翹鷺喜，", "試望家田還自適，滿畦秋水稻苗平。"]'),
('yuding-5','送日本國僧敬龍歸','韋莊','唐','御定全唐诗','yuding','','[]','扶桑已在渺茫中，家在扶桑東更東。',32,'御定全唐詩/json/695.json','["扶桑已在渺茫中，家在扶桑東更東。", "此去與師誰共到，一船明月一帆風。"]'),
('yuding-6','對酒','韋莊','唐','御定全唐诗','yuding','','[]','何用岩棲隱姓名，一壺春酎可忘形。',32,'御定全唐詩/json/695.json','["何用岩棲隱姓名，一壺春酎可忘形。", "伯倫若有長生術，直到如今醉未醒。"]'),
('yuding-7','尹喜宅','韋莊','唐','御定全唐诗','yuding','','[]','荒原秋殿柏蕭蕭，何代風煙占寂寥。紫氣已隨仙仗去，',40,'御定全唐詩/json/695.json','["荒原秋殿柏蕭蕭，何代風煙占寂寥。紫氣已隨仙仗去，", "欲問靈蹤無處所，十洲空闊閬山遙。"]'),
('yuding-8','途中望雨懷歸','韋莊','唐','御定全唐诗','yuding','','[]','滿空寒雨漫霏霏，去路雲深鎖翠微。牧豎遠當煙草立，',40,'御定全唐詩/json/695.json','["滿空寒雨漫霏霏，去路雲深鎖翠微。牧豎遠當煙草立，", "對此不堪鄉外思，荷蓑遙羨釣人歸。"]'),
('yuding-9','古離別','韋莊','唐','御定全唐诗','yuding','','[]','晴煙漠漠柳毿毿，不那離情酒半酣。',32,'御定全唐詩/json/695.json','["晴煙漠漠柳毿毿，不那離情酒半酣。", "更把玉鞭雲外指，斷腸春色在江南。"]'),
('yuding-10','柳穀道中作卻寄','韋莊','唐','御定全唐诗','yuding','','[]','馬前紅葉正紛紛，馬上離情斷殺魂。曉發獨辭殘月店，',40,'御定全唐詩/json/695.json','["馬前紅葉正紛紛，馬上離情斷殺魂。曉發獨辭殘月店，", "莫怪苦吟鞭拂地，有誰傾蓋待王孫。"]'),
('yuding-11','灞陵道中作','韋莊','唐','御定全唐诗','yuding','','[]','春橋南望水溶溶，一桁晴山倒碧峰。秦苑落花零露濕，',40,'御定全唐詩/json/695.json','["春橋南望水溶溶，一桁晴山倒碧峰。秦苑落花零露濕，", "萬古行人離別地，不堪吟罷夕陽鐘。"]'),
('yuding-12','秋日早行','韋莊','唐','御定全唐诗','yuding','','[]','上馬蕭蕭襟袖涼，路穿禾黍繞宮牆。半山殘月露華冷，',40,'御定全唐詩/json/695.json','["上馬蕭蕭襟袖涼，路穿禾黍繞宮牆。半山殘月露華冷，", "行人自是心如火，兔走烏飛不覺長。"]'),
('yuding-13','歎落花','韋莊','唐','御定全唐诗','yuding','','[]','一夜霏微露濕煙，曉來和淚喪嬋娟。不隨殘雪埋芳草，',40,'御定全唐詩/json/695.json','["一夜霏微露濕煙，曉來和淚喪嬋娟。不隨殘雪埋芳草，", "飄紅墮白堪惆悵，少別穠華又來年。"]'),
('yuding-14','宮怨','韋莊','唐','御定全唐诗','yuding','','[]','一辭同輦閉昭陽，耿耿寒宵禁漏長。釵上翠禽應不返，',40,'御定全唐詩/json/695.json','["一辭同輦閉昭陽，耿耿寒宵禁漏長。釵上翠禽應不返，", "輾轉令人思蜀賦，解將惆悵感君王。"]'),
('yuding-15','關河道中','韋莊','唐','御定全唐诗','yuding','','[]','槐陌蟬聲柳市風，驛樓高倚夕陽東。往來千里路長在，',40,'御定全唐詩/json/695.json','["槐陌蟬聲柳市風，驛樓高倚夕陽東。往來千里路長在，", "平生志業匡堯舜，又擬滄浪學釣翁。"]'),
('yuding-16','題盤豆驛水館後軒','韋莊','唐','御定全唐诗','yuding','','[]','極目晴川展畫屏，地從桃塞接蒲城。灘頭鷺占清波立，',40,'御定全唐詩/json/695.json','["極目晴川展畫屏，地從桃塞接蒲城。灘頭鷺占清波立，", "馮軒盡日不回首，楚水吳山無限情。"]'),
('yuding-17','梁氏水齋','韋莊','唐','御定全唐诗','yuding','','[]','獨醉任騰騰，琴棋亦自能。捲簾山對客，開戶犬迎僧。',48,'御定全唐詩/json/695.json','["獨醉任騰騰，琴棋亦自能。捲簾山對客，開戶犬迎僧。", "看蟻移苔穴，聞蛙落石層。夜窗風雨急，松外一庵燈。"]'),
('yuding-18','曲池作','韋莊','唐','御定全唐诗','yuding','','[]','細雨曲池濱，青袍草色新。詠詩行信馬，載酒喜逢人。',48,'御定全唐詩/json/695.json','["細雨曲池濱，青袍草色新。詠詩行信馬，載酒喜逢人。", "性為無機率，家因守道貧。若無詩自遣，誰奈寂寥春。"]'),
('yuding-19','嘉會裏閒居','韋莊','唐','御定全唐诗','yuding','','[]','豈知城闕內，有地出紅塵。草占一方綠，樹藏千古春。',48,'御定全唐詩/json/695.json','["豈知城闕內，有地出紅塵。草占一方綠，樹藏千古春。", "馬嘶遊寺客，犬吠探花人。寂寂無鐘鼓，槐行接紫宸。"]'),
('yuding-20','夏夜','韋莊','唐','御定全唐诗','yuding','','[]','傍水遷書榻，開襟納夜涼。星繁愁晝熱，露重覺荷香。',48,'御定全唐詩/json/695.json','["傍水遷書榻，開襟納夜涼。星繁愁晝熱，露重覺荷香。", "蛙吹鳴還息，蛛羅滅又光。正吟秋興賦，桐景下西牆。"]'),
('yuding-21','早發','韋莊','唐','御定全唐诗','yuding','','[]','早霧濃于雨，田深黍稻低。出門雞未唱，過客馬頻嘶。',48,'御定全唐詩/json/695.json','["早霧濃于雨，田深黍稻低。出門雞未唱，過客馬頻嘶。", "樹色遙藏店，泉聲暗傍畦。獨吟三十裏，城月尚如珪。"]'),
('yuding-22','寓言','韋莊','唐','御定全唐诗','yuding','','[]','黃金日日銷還鑄，仙桂年年折又生。',32,'御定全唐詩/json/695.json','["黃金日日銷還鑄，仙桂年年折又生。", "兔走烏飛如未息，路塵終見泰山平。"]'),
('yuding-23','對雪獻薛常侍','韋莊','唐','御定全唐诗','yuding','','[]','瓊林瑤樹忽珊珊，急帶西風下晚天。皓鶴褵褷飛不辨，',40,'御定全唐詩/json/695.json','["瓊林瑤樹忽珊珊，急帶西風下晚天。皓鶴褵褷飛不辨，", "門外寒光利如劍，莫推紅袖訴金船。"]'),
('yuding-24','題裴端公郊居','韋莊','唐','御定全唐诗','yuding','','[]','暫隨紅旆佐藩方，高跡終期臥故鄉。已近水聲開澗戶，',40,'御定全唐詩/json/695.json','["暫隨紅旆佐藩方，高跡終期臥故鄉。已近水聲開澗戶，", "莫奪野人樵牧興，白雲不識繡衣郎。"]'),
('yuding-25','登咸陽縣樓望雨','韋莊','唐','御定全唐诗','yuding','','[]','亂雲如獸出山前，細雨和風滿渭川。',32,'御定全唐詩/json/695.json','["亂雲如獸出山前，細雨和風滿渭川。", "盡日空蒙無所見，雁行斜去字聯聯。"]'),
('yuding-26','貴公子','韋莊','唐','御定全唐诗','yuding','','[]','大道青樓御苑東，玉欄仙杏壓枝紅。金鈴犬吠梧桐月，',40,'御定全唐詩/json/695.json','["大道青樓御苑東，玉欄仙杏壓枝紅。金鈴犬吠梧桐月，", "瑤池宴罷歸來醉，笑說君王在月宮。"]'),
('yuding-27','聽趙秀才彈琴','韋莊','唐','御定全唐诗','yuding','','[]','滿匣冰泉咽又鳴，玉音閑澹入神清。巫山夜雨弦中起，',40,'御定全唐詩/json/695.json','["滿匣冰泉咽又鳴，玉音閑澹入神清。巫山夜雨弦中起，", "不須更奏幽蘭曲，卓氏門前月正明。"]'),
('yuding-28','觀獵','韋莊','唐','御定全唐诗','yuding','','[]','苑牆東畔欲斜暉，傍苑穿花兔正肥。公子喜逢朝罷日，',40,'御定全唐詩/json/695.json','["苑牆東畔欲斜暉，傍苑穿花兔正肥。公子喜逢朝罷日，", "直待四郊高鳥盡，掉鞍齊向國門歸。"]'),
('yuding-29','三堂東湖作','韋莊','唐','御定全唐诗','yuding','','[]','滿塘秋水碧泓澄，十畝菱花晚鏡清。景動新橋橫螮蝀，',40,'御定全唐詩/json/695.json','["滿塘秋水碧泓澄，十畝菱花晚鏡清。景動新橋橫螮蝀，", "何處最添詩客興，黃昏煙雨亂蛙聲。"]'),
('yuding-30','放榜日作','韋莊','唐','御定全唐诗','yuding','','[]','一聲開鼓辟金扉，三十仙材上翠微。葛水霧中龍乍變，',40,'御定全唐詩/json/695.json','["一聲開鼓辟金扉，三十仙材上翠微。葛水霧中龍乍變，", "回首便辭塵土世，彩雲新換六銖衣。"]'),
('yuding-31','寄薛先輩','韋莊','唐','御定全唐诗','yuding','','[]','懸知回日彩衣榮，仙籍高標第一名。瑤樹帶風侵物冷，',40,'御定全唐詩/json/695.json','["懸知回日彩衣榮，仙籍高標第一名。瑤樹帶風侵物冷，", "不說文章及閘地，自然毛骨是公卿。"]'),
('yuding-32','訪含弘山僧不遇留題精舍','韋莊','唐','御定全唐诗','yuding','','[]','滿院桐花鳥雀喧，寂寥芳草茂芊芊。吾師正遇歸山日，',40,'御定全唐詩/json/695.json','["滿院桐花鳥雀喧，寂寥芳草茂芊芊。吾師正遇歸山日，", "人間不自尋行跡，一片孤雲在碧天。"]'),
('yuding-33','寄從兄遵','韋莊','唐','御定全唐诗','yuding','','[]','江上秋風正釣鱸，九重天子夢翹車。不將高臥邀劉主，',40,'御定全唐詩/json/695.json','["江上秋風正釣鱸，九重天子夢翹車。不將高臥邀劉主，", "相逢莫話歸山計，明日東封待直廬。"]'),
('yuding-34','漁塘十六韻','韋莊','唐','御定全唐诗','yuding','','[]','洛水分餘脈，穿岩出石棱。碧經嵐氣重，清帶露華澄。',192,'御定全唐詩/json/695.json','["洛水分餘脈，穿岩出石棱。碧經嵐氣重，清帶露華澄。", "瑩澈通三島，岩梧積萬層。巢由應共到，劉阮想同登。", "壁峻苔如畫，山昏霧似蒸。撼松衣有雪，題石硯生冰。", "路熟雲中客，名留域外僧。饑猿尋落橡，鬥鼠墮高藤。", "嶮樹臨溪亞，殘莎帶岸崩。持竿聊藉草，待月好垂罾。", "對景思任父，開圖想不興。晚風輕浪疊，暮雨濕煙凝。", "似泛靈槎出，如迎羽客升。仙源終不測，勝概自相仍。", "欲別誠堪戀，長歸又未能。他時操史筆，為爾著良稱。"]'),
('yuding-35','冬日長安感志寄獻虢州崔郎中二十韻','韋莊','唐','御定全唐诗','yuding','','[]','帝裏無成久滯淹，別家三度見新蟾。郤詵丹桂無人指，',168,'御定全唐詩/json/695.json','["帝裏無成久滯淹，別家三度見新蟾。郤詵丹桂無人指，", "病如原憲誰能療，蹇似劉楨豈用占。霧雨十年同隱遁，", "客舍正甘愁寂寂，郡樓遙想醉懨懨。已聞鈴閣懸新詔，", "觀星始覺中郎貴，問俗方知太守廉。宅後綠波棲畫鷁，", "積凍慢封寒溜細，暮雲高拔遠峰尖。訟堂無事冰生印，", "未知匣劍何時躍，但恐鉛刀不再銛。雖有遠心長擁篲，", "百口似萍依廣岸，一身如燕戀高簷。如今正困風波力，"]'),
('yuding-36','和薛先輩見寄初秋寓懷即事之作二十韻','韋莊','唐','御定全唐诗','yuding','','[]','玉律初移候，清風乍遠襟。一聲蟬到耳，千炬火然心。',240,'御定全唐詩/json/695.json','["玉律初移候，清風乍遠襟。一聲蟬到耳，千炬火然心。", "嶽靜雲堆翠，樓高日半沉。引愁憎暮角，驚夢怯殘砧。", "露白凝湘簟，風篁韻蜀琴。鳥喧從果爛，階淨任苔侵。", "柿葉添紅景，槐柯減綠陰。采珠逢寶窟，閱石見瑤林。", "魯殿鏗寒玉，苔山激碎金。郤堂流桂景，陳巷集車音。", "名自張華顯，詞因葛亮吟。水深龍易失，天遠鶴難尋。", "鑒貌甯慚樂，論才豈謝任。義心孤劍直，學海怒濤深。", "既睹文兼質，翻疑古在今。慚聞紆綠綬，即候掛朝簪。", "晚樹連秋塢，斜陽映暮岑。夜蟲方唧唧，疲馬正駸駸。", "托跡同吳燕，依仁似越禽。會隨仙羽化，香蟻且同斟。"]'),
('yuding-37','同舊韻','韋莊','唐','御定全唐诗','yuding','','[]','大火收殘暑，清光漸惹襟。謝莊千里思，張翰五湖心。',240,'御定全唐詩/json/695.json','["大火收殘暑，清光漸惹襟。謝莊千里思，張翰五湖心。", "暮角迎風急，孤鐘向暝沈。露滋三徑草，日動四鄰砧。", "簟委班姬扇，蟬悲蔡琰琴。方愁丹桂遠，已怯二毛侵。", "甃石回泉脈，移棋就竹陰。觸絲蛛墮網，避隼鳥投林。", "貌愧潘郎璧，文慚呂相金。但埋酆獄氣，未發爨桐音。", "靜笑劉琨舞，閑思阮籍吟。野花和雨劚，怪石入雲尋。", "跡竟終非切，幽閒且自任。趨時慚藝薄，托質仰恩深。", "美價方稀古，清名已絕今。既聞留縞帶，詎肯擲蓍簪。", "遲客虛高閣，迎僧出亂岑。壯心徒戚戚，逸足自駸駸。", "安羨倉中鼠，危同幕上禽。期君調鼎鼐，他日俟羊斟。"]'),
('yuding-38','三用韻','韋莊','唐','御定全唐诗','yuding','','[]','素律初回馭，商飆暗觸襟。乍傷詩客思，還動旅人心。',240,'御定全唐詩/json/695.json','["素律初回馭，商飆暗觸襟。乍傷詩客思，還動旅人心。", "蟬噪因風斷，鱗游見鷺沈。笛聲隨晚吹，松韻激遙砧。", "地覆青袍草，窗橫綠綺琴。煙霄難自致，歲月易相侵。", "澗柳橫孤彴，岩藤架密陰。瀟湘期釣侶，鄠杜別家林。", "遺愧虞卿璧，言依季布金。錚鏦聞郢唱，次第發巴音。", "螢影沖簾落，蟲聲擁砌吟。樓高思共釣，寺遠想同尋。", "入夜愁難遣，逢秋恨莫任。蝸遊苔徑滑，鶴步翠塘深。", "莫問榮兼辱，甯論古與今。固窮憐甕牖，感舊惜蒿簪。", "晚日舒霞綺，遙天倚黛岑。鴛鸞方翽翽，驊驥整駸駸。", "未化投陂竹，空思出穀禽。感多聊自遣，桑落且閑斟。"]'),
('yuding-39','驚秋','韋莊','唐','御定全唐诗','yuding','','[]','不向煙波狎釣舟，強親文墨事儒丘。',32,'御定全唐詩/json/695.json','["不向煙波狎釣舟，強親文墨事儒丘。", "長安十二槐花陌，曾負秋風多少秋。"]'),
('yuding-40','登漢高廟閑眺','韋莊','唐','御定全唐诗','yuding','','[]','獨尋仙境上高原，雲雨深藏古帝壇。天畔晚峰青簇簇，',40,'御定全唐詩/json/695.json','["獨尋仙境上高原，雲雨深藏古帝壇。天畔晚峰青簇簇，", "一帶遠光何處水，釣舟閑系夕陽灘。"]'),
('yuding-41','耒陽縣浮山神廟','韋莊','唐','御定全唐诗','yuding','','[]','一郡皆傳此廟靈，廟前松桂古今青。山曾堯代浮洪水，',40,'御定全唐詩/json/695.json','["一郡皆傳此廟靈，廟前松桂古今青。山曾堯代浮洪水，", "為霖自可成農歲，何用興師遠伐邢。"]'),
('yuding-42','愁','韋莊','唐','御定全唐诗','yuding','','[]','避愁愁又至，愁至事難忘。夜坐心中火，朝為鬢上霜。',48,'御定全唐詩/json/695.json','["避愁愁又至，愁至事難忘。夜坐心中火，朝為鬢上霜。", "不經公子夢，偏入旅人腸。借問高軒客，何鄉是醉鄉。"]'),
('yuding-43','村居書事','韋莊','唐','御定全唐诗','yuding','','[]','年年耕與釣，鷗鳥已相依。砌長蒼苔厚，藤抽紫蔓肥。',48,'御定全唐詩/json/695.json','["年年耕與釣，鷗鳥已相依。砌長蒼苔厚，藤抽紫蔓肥。", "風鶯移樹囀，雨燕入樓飛。不覺春光暮，繞籬紅杏稀。"]'),
('yuding-44','三堂早春','韋莊','唐','御定全唐诗','yuding','','[]','獨倚危樓四望遙，杏花春陌馬聲驕。池邊冰刃暖初落，',40,'御定全唐詩/json/695.json','["獨倚危樓四望遙，杏花春陌馬聲驕。池邊冰刃暖初落，", "主人年少多情味，笑換金龜解珥貂。"]'),
('yuding-0','雨霽晚眺','韋莊','唐','御定全唐诗','yuding','','[]','入谷路縈紆，岩巔日欲晡。嶺雲寒掃蓋，溪雪凍黏須。',48,'御定全唐詩/json/696.json','["入谷路縈紆，岩巔日欲晡。嶺雲寒掃蓋，溪雪凍黏須。", "臥草跧如兔，聽冰怯似狐。仍聞關外火，昨夜徹皇都。"]'),
('yuding-1','立春日作','韋莊','唐','御定全唐诗','yuding','','[]','九重天子去蒙塵，禦柳無情依舊春。',32,'御定全唐詩/json/696.json','["九重天子去蒙塵，禦柳無情依舊春。", "今日不關妃妾事，始知辜負馬嵬人。"]'),
('yuding-2','贈雲陽裴明府','韋莊','唐','御定全唐诗','yuding','','[]','南北三年一解攜，海為深谷岸為蹊。已聞陳勝心降漢，',40,'御定全唐詩/json/696.json','["南北三年一解攜，海為深谷岸為蹊。已聞陳勝心降漢，", "歸來能作煙波伴，我有魚舟在五溪。"]'),
('yuding-3','賊中與蕭韋二秀才同臥重疾二君尋愈…因有題','韋莊','唐','御定全唐诗','yuding','','[]','與君同臥疾，獨我漸彌留。弟妹不知處，兵戈殊未休。',48,'御定全唐詩/json/696.json','["與君同臥疾，獨我漸彌留。弟妹不知處，兵戈殊未休。", "胸中疑晉豎，耳下鬥殷牛。縱有秦醫在，懷鄉亦淚流。"]'),
('yuding-4','重圍中逢蕭校書','韋莊','唐','御定全唐诗','yuding','','[]','相逢俱此地，此地是何鄉。側目不成語，撫心空自傷。',48,'御定全唐詩/json/696.json','["相逢俱此地，此地是何鄉。側目不成語，撫心空自傷。", "劍高無鳥度，樹暗有兵藏。底事征西將，年年戍洛陽。"]'),
('yuding-5','咸通','韋莊','唐','御定全唐诗','yuding','','[]','咸通時代物情奢，歡殺金張許史家。破產競留天上樂，',40,'御定全唐詩/json/696.json','["咸通時代物情奢，歡殺金張許史家。破產競留天上樂，", "人意似知今日事，急催弦管送年華。"]'),
('yuding-6','白櫻桃','韋莊','唐','御定全唐诗','yuding','','[]','王母階前種幾株，水精簾外看如無。',32,'御定全唐詩/json/696.json','["王母階前種幾株，水精簾外看如無。", "只應漢武金盤上，瀉得珊珊白露珠。"]'),
('yuding-7','夜景','韋莊','唐','御定全唐诗','yuding','','[]','滿庭松桂雨餘天，宋玉秋聲韻蜀弦。烏兔不知多事世，',40,'御定全唐詩/json/696.json','["滿庭松桂雨餘天，宋玉秋聲韻蜀弦。烏兔不知多事世，", "欲把傷心問明月，素娥無語淚娟娟。"]'),
('yuding-8','宿山家','韋莊','唐','御定全唐诗','yuding','','[]','山行侵夜到，雲竇一星燈。草動蛇尋穴，枝搖鼠上藤。',48,'御定全唐詩/json/696.json','["山行侵夜到，雲竇一星燈。草動蛇尋穴，枝搖鼠上藤。", "背風開藥灶，向月展漁罾。明日前溪路，煙蘿更幾層。"]'),
('yuding-9','長年','韋莊','唐','御定全唐诗','yuding','','[]','長年方悟少年非，人道新詩勝舊詩。十畝野塘留客釣，',40,'御定全唐詩/json/696.json','["長年方悟少年非，人道新詩勝舊詩。十畝野塘留客釣，", "大盜不將爐冶去，有心重築太平基。"]'),
('yuding-10','辛醜年','韋莊','唐','御定全唐诗','yuding','','[]','九衢漂杵已成川，塞上黃雲戰馬閑。但有羸兵填渭水，',40,'御定全唐詩/json/696.json','["九衢漂杵已成川，塞上黃雲戰馬閑。但有羸兵填渭水，", "西望翠華殊未返，淚痕空濕劍文斑。"]'),
('yuding-11','思歸','韋莊','唐','御定全唐诗','yuding','','[]','暖絲無力自悠揚，牽引東風斷客腸。外地見花終寂寞，',40,'御定全唐詩/json/696.json','["暖絲無力自悠揚，牽引東風斷客腸。外地見花終寂寞，", "舊裏若為歸去好，子期凋謝呂安亡。"]'),
('yuding-12','憶昔','韋莊','唐','御定全唐诗','yuding','','[]','昔年曾向五陵游，子夜歌清月滿樓。銀燭樹前長似晝，',40,'御定全唐詩/json/696.json','["昔年曾向五陵游，子夜歌清月滿樓。銀燭樹前長似晝，", "今日亂離俱是夢，夕陽唯見水東流。"]'),
('yuding-13','合歡蓮花','韋莊','唐','御定全唐诗','yuding','','[]','虞舜南巡去不歸，二妃相誓死江湄。',32,'御定全唐詩/json/696.json','["虞舜南巡去不歸，二妃相誓死江湄。", "空留萬古香魂在，結作雙葩合一枝。"]'),
('yuding-14','覽蕭必先卷','韋莊','唐','御定全唐诗','yuding','','[]','滿軸編新句，翛然大雅風。名因五字得，命合一言通。',48,'御定全唐詩/json/696.json','["滿軸編新句，翛然大雅風。名因五字得，命合一言通。", "景盡才難盡，吟終意未終。似逢曹與謝，煙雨思何窮。"]'),
('yuding-15','和人歲宴旅舍見寄','韋莊','唐','御定全唐诗','yuding','','[]','積雪滿前除，寒光夜皎如。老憂新歲近，貧覺故交疏。',48,'御定全唐詩/json/696.json','["積雪滿前除，寒光夜皎如。老憂新歲近，貧覺故交疏。", "意合論文後，心降得句初。莫言常鬱鬱，天道有盈虛。"]'),
('yuding-16','宿泊孟津寄三堂友人','韋莊','唐','御定全唐诗','yuding','','[]','解纜西征未有期，槐花又逼桂花時。鴻臚陌上歸耕晚，',40,'御定全唐詩/json/696.json','["解纜西征未有期，槐花又逼桂花時。鴻臚陌上歸耕晚，", "分明昨夜南池夢，還把漁竿詠楚詞。"]'),
('yuding-17','對酒賦友人','韋莊','唐','御定全唐诗','yuding','','[]','多病仍多感，君心自我心。浮生都是夢，浩歎不如吟。',48,'御定全唐詩/json/696.json','["多病仍多感，君心自我心。浮生都是夢，浩歎不如吟。", "白雪篇篇麗，清酤盞盞深。亂離俱老大，強醉莫沾襟。"]'),
('yuding-18','天井關','韋莊','唐','御定全唐诗','yuding','','[]','太行山上雲深處，誰向雲中築女牆。短綆詎能垂玉甃，',40,'御定全唐詩/json/696.json','["太行山上雲深處，誰向雲中築女牆。短綆詎能垂玉甃，", "守吏不教飛鳥過，赤眉何路到吾鄉。"]'),
('yuding-19','贈邊將','韋莊','唐','御定全唐诗','yuding','','[]','昔因征遠向金微，馬出榆關一鳥飛。萬里只攜孤劍去，',40,'御定全唐詩/json/696.json','["昔因征遠向金微，馬出榆關一鳥飛。萬里只攜孤劍去，", "只待煙塵報天子，滿頭霜雪為兵機。"]'),
('yuding-20','春日','韋莊','唐','御定全唐诗','yuding','','[]','忽覺東風景漸遲，野梅山杏暗芳菲。落星樓上吹殘角，',40,'御定全唐詩/json/696.json','["忽覺東風景漸遲，野梅山杏暗芳菲。落星樓上吹殘角，", "紅塵遮斷長安陌，芳草王孫暮不歸。"]'),
('yuding-21','早秋夜作','韋莊','唐','御定全唐诗','yuding','','[]','翠簟初清暑半銷，撇簾松韻送輕飆。莎庭露永琴書潤，',40,'御定全唐詩/json/696.json','["翠簟初清暑半銷，撇簾松韻送輕飆。莎庭露永琴書潤，", "不須更作悲秋賦，王粲辭家鬢已凋。"]'),
('yuding-22','寄江南逐客','韋莊','唐','御定全唐诗','yuding','','[]','二年音信阻湘潭，花下相思酒半酣。',32,'御定全唐詩/json/696.json','["二年音信阻湘潭，花下相思酒半酣。", "記得竹齋風雨夜，對床孤枕話江南。"]'),
('yuding-23','冬夜','韋莊','唐','御定全唐诗','yuding','','[]','睡覺寒爐酒半消，客情鄉夢兩遙遙。',32,'御定全唐詩/json/696.json','["睡覺寒爐酒半消，客情鄉夢兩遙遙。", "無人為我磨心劍，割斷愁腸一寸苗。"]'),
('yuding-24','又聞湖南荊渚相次陷沒','韋莊','唐','御定全唐诗','yuding','','[]','幾時聞唱凱旋歌，處處屯兵未倒戈。天子只憑紅旆壯，',40,'御定全唐詩/json/696.json','["幾時聞唱凱旋歌，處處屯兵未倒戈。天子只憑紅旆壯，", "莫問流離南越事，戰餘空有舊山河。"]'),
('yuding-25','家叔南游卻歸因獻賀','韋莊','唐','御定全唐诗','yuding','','[]','繚繞江南一歲歸，歸來行色滿戎衣。長聞鳳詔徵兵急，',40,'御定全唐詩/json/696.json','["繚繞江南一歲歸，歸來行色滿戎衣。長聞鳳詔徵兵急，", "遙知倚棹思家處，澤國煙深暮雨微。"]'),
('yuding-26','楚行吟','韋莊','唐','御定全唐诗','yuding','','[]','章華台下草如煙，故郢城頭月似弦。',32,'御定全唐詩/json/696.json','["章華台下草如煙，故郢城頭月似弦。", "惆悵楚宮雲雨後，露啼花笑一年年。"]'),
('yuding-27','洛陽吟','韋莊','唐','御定全唐诗','yuding','','[]','萬戶千門夕照邊，開元時節舊風煙。宮官試馬遊三市，',40,'御定全唐詩/json/696.json','["萬戶千門夕照邊，開元時節舊風煙。宮官試馬遊三市，", "如今父老偏垂淚，不見承平四十年。"]'),
('yuding-28','過舊宅','韋莊','唐','御定全唐诗','yuding','','[]','華軒不見馬蕭蕭，廷尉門人久寂寥。朱檻翠樓為蔔肆，',40,'御定全唐詩/json/696.json','["華軒不見馬蕭蕭，廷尉門人久寂寥。朱檻翠樓為蔔肆，", "莫問此中銷歇寺，娟娟紅淚滴芭蕉。"]'),
('yuding-29','喻東軍','韋莊','唐','御定全唐诗','yuding','','[]','四年龍馭守峨嵋，鐵馬西來步步遲。五運未教移漢鼎，',40,'御定全唐詩/json/696.json','["四年龍馭守峨嵋，鐵馬西來步步遲。五運未教移漢鼎，", "獨把一樽和淚酒，隔雲遙奠武侯祠。"]'),
('yuding-30','清河縣樓作','韋莊','唐','御定全唐诗','yuding','','[]','有客微吟獨憑樓，碧雲紅樹不勝愁。盤雕迥印天心沒，',40,'御定全唐詩/json/696.json','["有客微吟獨憑樓，碧雲紅樹不勝愁。盤雕迥印天心沒，", "故人此地揚帆去，何處相思雪滿頭。"]'),
('yuding-31','北原閑眺','韋莊','唐','御定全唐诗','yuding','','[]','春城回首樹重重，立馬平原夕照中。五鳳灰殘金翠滅，',40,'御定全唐詩/json/696.json','["春城回首樹重重，立馬平原夕照中。五鳳灰殘金翠滅，", "欲問向來陵穀事，野桃無語淚花紅。"]'),
('yuding-32','贈戍兵','韋莊','唐','御定全唐诗','yuding','','[]','漢皇無事暫遊汾，底事狐狸嘯作群。夜指碧天占晉分，',40,'御定全唐詩/json/696.json','["漢皇無事暫遊汾，底事狐狸嘯作群。夜指碧天占晉分，", "止竟有征須有戰，洛陽何用久屯軍。"]'),
('yuding-33','睹軍回戈','韋莊','唐','御定全唐诗','yuding','','[]','關中群盜已心離，關外猶聞羽檄飛。御苑綠莎嘶戰馬，',40,'御定全唐詩/json/696.json','["關中群盜已心離，關外猶聞羽檄飛。御苑綠莎嘶戰馬，", "昨日屯軍還夜遁，滿車空載洛神歸。"]'),
('yuding-34','中渡晚眺','韋莊','唐','御定全唐诗','yuding','','[]','魏王堤畔草如煙，有客傷時獨扣舷。妖氣欲昏唐社稷，',40,'御定全唐詩/json/696.json','["魏王堤畔草如煙，有客傷時獨扣舷。妖氣欲昏唐社稷，", "家寄杜陵歸不得，一回回首一潸然。"]'),
('yuding-35','河內別村業閑題','韋莊','唐','御定全唐诗','yuding','','[]','阮氏清風竹巷深，滿溪松竹似山陰。門當谷路多樵客，',40,'御定全唐詩/json/696.json','["阮氏清風竹巷深，滿溪松竹似山陰。門當谷路多樵客，", "鄰翁莫問傷時事，一曲高歌夕照沈。"]'),
('yuding-36','聞官軍繼至未睹凱旋','韋莊','唐','御定全唐诗','yuding','','[]','嫖姚何日破重圍，秋草深來戰馬肥。已有孔明傳將略，',40,'御定全唐詩/json/696.json','["嫖姚何日破重圍，秋草深來戰馬肥。已有孔明傳將略，", "何事小臣偏注目，帝鄉遙羨白雲歸。"]'),
('yuding-37','和集賢侯學士分司丁侍禦秋日雨霽之作','韋莊','唐','御定全唐诗','yuding','','[]','洛岸秋晴夕照長，鳳樓龍闕倚清光。玉泉山淨雲初散，',40,'御定全唐詩/json/696.json','["洛岸秋晴夕照長，鳳樓龍闕倚清光。玉泉山淨雲初散，", "多慚十載游梁士，卻伴賓鴻入帝鄉。"]'),
('yuding-38','題安定張使君','韋莊','唐','御定全唐诗','yuding','','[]','器度風標合出塵，桂宮何負一枝新。成丹始見金無滓，',40,'御定全唐詩/json/696.json','["器度風標合出塵，桂宮何負一枝新。成丹始見金無滓，", "中興若繼開元事，堪向龍池作近臣。"]'),
('yuding-39','潁陽縣','韋莊','唐','御定全唐诗','yuding','','[]','琴堂連少室，故事即仙蹤。樹老風聲壯，山高臘候濃。',48,'御定全唐詩/json/696.json','["琴堂連少室，故事即仙蹤。樹老風聲壯，山高臘候濃。", "雪多庭有鹿，縣僻寺無鐘。何處留詩客，茆簷倚後峰。"]'),
('yuding-40','寄園林主人','韋莊','唐','御定全唐诗','yuding','','[]','主人常不在，春物為誰開。桃豔紅將落，梨華雪又摧。',48,'御定全唐詩/json/696.json','["主人常不在，春物為誰開。桃豔紅將落，梨華雪又摧。", "曉鶯閑自囀，遊客暮空回。尚有餘芳在，猶堪載酒來。"]'),
('yuding-41','洛北村居','韋莊','唐','御定全唐诗','yuding','','[]','十畝松篁百畝田，歸來方屬大兵年。岩邊石室低臨水，',40,'御定全唐詩/json/696.json','["十畝松篁百畝田，歸來方屬大兵年。岩邊石室低臨水，", "無人說得中興事，獨倚斜暉憶仲宣。"]'),
('yuding-42','對梨花贈皇甫秀才','韋莊','唐','御定全唐诗','yuding','','[]','林上梨花雪壓枝，獨攀瓊豔不勝悲。依前此地逢君處，',40,'御定全唐詩/json/696.json','["林上梨花雪壓枝，獨攀瓊豔不勝悲。依前此地逢君處，", "騰騰戰鼓正多事，須信明朝難重持。"]'),
('yuding-43','立春','韋莊','唐','御定全唐诗','yuding','','[]','青帝東來日馭遲，暖煙輕逐曉風吹。罽袍公子樽前覺，',40,'御定全唐詩/json/696.json','["青帝東來日馭遲，暖煙輕逐曉風吹。罽袍公子樽前覺，", "殷勤為作宜春曲，題向花箋帖繡楣。"]'),
('yuding-44','村笛','韋莊','唐','御定全唐诗','yuding','','[]','簫韶九奏韻淒鏘，曲度雖高調不傷。',32,'御定全唐詩/json/696.json','["簫韶九奏韻淒鏘，曲度雖高調不傷。", "卻見孤村明月夜，一聲牛笛斷人腸。"]'),
('yuding-45','題李斯傳','韋莊','唐','御定全唐诗','yuding','','[]','蜀魄湘魂萬古悲，未悲秦相死秦時。',32,'御定全唐詩/json/696.json','["蜀魄湘魂萬古悲，未悲秦相死秦時。", "臨刑莫恨倉中鼠，上蔡東門去自遲。"]'),
('yuding-46','贈薛秀才','韋莊','唐','御定全唐诗','yuding','','[]','相辭因避世，相見尚兵戈。亂後故人少，別來新話多。',48,'御定全唐詩/json/696.json','["相辭因避世，相見尚兵戈。亂後故人少，別來新話多。", "但聞哀痛詔，未睹凱旋歌。欲結岩棲伴，何山好薜蘿。"]'),
('yuding-47','和元秀才別業書事','韋莊','唐','御定全唐诗','yuding','','[]','僻居春事好，水曲亂花陰。浪過河移岸，雛成鳥別林。',48,'御定全唐詩/json/696.json','["僻居春事好，水曲亂花陰。浪過河移岸，雛成鳥別林。", "綠錢榆貫重，紅障杏籬深。莫飲宜城酒，愁多醉易沈。"]'),
('yuding-48','紀村事','韋莊','唐','御定全唐诗','yuding','','[]','綠蔓映雙扉，循牆一徑微。雨多庭果爛，稻熟渚禽肥。',48,'御定全唐詩/json/696.json','["綠蔓映雙扉，循牆一徑微。雨多庭果爛，稻熟渚禽肥。", "釀酒迎新社，遙砧送暮暉。數聲牛上笛，何處餉田歸。"]'),
('yuding-49','題許仙師院','韋莊','唐','御定全唐诗','yuding','','[]','地古多喬木，遊人到且吟。院開金鎖澀，門映綠篁深。',48,'御定全唐詩/json/696.json','["地古多喬木，遊人到且吟。院開金鎖澀，門映綠篁深。", "山色不離眼，鶴聲長在琴。往來誰與熟，乳鹿住前林。"]'),
('yuding-50','離筵訴酒','韋莊','唐','御定全唐诗','yuding','','[]','感君情重惜分離，送我殷勤酒滿卮。',32,'御定全唐詩/json/696.json','["感君情重惜分離，送我殷勤酒滿卮。", "不是不能判酩酊，卻憂前路酒醒時。"]'),
('yuding-51','不寐','韋莊','唐','御定全唐诗','yuding','','[]','不寐天將曉，心勞轉似灰。蚊吟頻到耳，鼠鬥競緣台。',48,'御定全唐詩/json/696.json','["不寐天將曉，心勞轉似灰。蚊吟頻到耳，鼠鬥競緣台。", "戶闇知蟾落，林喧覺雨來。馬嘶朝客過，知是禁門開。"]'),
('yuding-52','贈武處士','韋莊','唐','御定全唐诗','yuding','','[]','一身唯一室，高靜若僧家。掃地留疏影，穿池浸落霞。',48,'御定全唐詩/json/696.json','["一身唯一室，高靜若僧家。掃地留疏影，穿池浸落霞。", "綠蘿臨水合，白道向村斜。賣藥歸來醉，吟詩倚釣查。"]'),
('yuding-53','題吉澗盧拾遺莊','韋莊','唐','御定全唐诗','yuding','','[]','主人西游去不歸，滿溪春雨長春薇。',32,'御定全唐詩/json/696.json','["主人西游去不歸，滿溪春雨長春薇。", "怪來馬上詩情好，印破青山白鷺飛。"]'),
('yuding-54','題潁源廟','韋莊','唐','御定全唐诗','yuding','','[]','曾是巢由棲隱地，百川唯說潁源清。微波乍向雲根吐，',40,'御定全唐詩/json/696.json','["曾是巢由棲隱地，百川唯說潁源清。微波乍向雲根吐，", "臨川試問堯年事，猶被封人勸濯纓。"]'),
('yuding-55','東遊遠歸','韋莊','唐','御定全唐诗','yuding','','[]','扣角幹名計已疏，劍歌休恨食無魚。辭家柳絮三春半，',40,'御定全唐詩/json/696.json','["扣角幹名計已疏，劍歌休恨食無魚。辭家柳絮三春半，", "青雲不識楊生面，天子何由問子虛。"]'),
('yuding-56','新正日商南道中作寄李明府','韋莊','唐','御定全唐诗','yuding','','[]','相看又見歲華新，依舊楊朱拭淚巾。踏雪偶因尋戴客，',40,'御定全唐詩/json/696.json','["相看又見歲華新，依舊楊朱拭淚巾。踏雪偶因尋戴客，", "今日與君同避世，卻憐無事是家貧。"]'),
('yuding-57','春暮','韋莊','唐','御定全唐诗','yuding','','[]','一春春事好，病酒起常遲。流水綠縈砌，落花紅墮枝。',48,'御定全唐詩/json/696.json','["一春春事好，病酒起常遲。流水綠縈砌，落花紅墮枝。", "樓高喧乳燕，樹密鬥雛鸝。不學山公醉，將何自解頤。"]'),
('yuding-58','哭麻處士','韋莊','唐','御定全唐诗','yuding','','[]','卻到歌吟地，閑門草色中。百年流水盡，萬事落花空。',48,'御定全唐詩/json/696.json','["卻到歌吟地，閑門草色中。百年流水盡，萬事落花空。", "繐帳扃秋月，詩樓鎖夜蟲。少微何處墮，留恨白楊風。"]'),
('yuding-59','春早','韋莊','唐','御定全唐诗','yuding','','[]','聞鶯才覺曉，閉戶已知晴。一帶窗間月，斜穿枕上生。',24,'御定全唐詩/json/696.json','["聞鶯才覺曉，閉戶已知晴。一帶窗間月，斜穿枕上生。"]'),
('yuding-60','和友人','韋莊','唐','御定全唐诗','yuding','','[]','閉門同隱士，不出動經時。靜閱王維畫，閑翻褚胤棋。',48,'御定全唐詩/json/696.json','["閉門同隱士，不出動經時。靜閱王維畫，閑翻褚胤棋。", "落泉當戶急，殘月下窗遲。卻想從來意，譙周亦自嗤。"]'),
('yuding-61','春愁','韋莊','唐','御定全唐诗','yuding','','[]','寓思本多傷，逢春恨更長。露沾湘竹淚，花墮越梅妝。',48,'御定全唐詩/json/696.json','["寓思本多傷，逢春恨更長。露沾湘竹淚，花墮越梅妝。", "睡怯交加夢，閑傾瀲灩觴。後庭人不到，斜月上松篁。"]'),
('yuding-62','晚春','韋莊','唐','御定全唐诗','yuding','','[]','花開疑乍富，花落似初貧。萬物不如酒，四時唯愛春。',48,'御定全唐詩/json/696.json','["花開疑乍富，花落似初貧。萬物不如酒，四時唯愛春。", "峨峨秦氏髻，皎皎洛川神。風月應相笑，年年醉病身。"]'),
('yuding-63','題許渾詩卷','韋莊','唐','御定全唐诗','yuding','','[]','江南才子許渾詩，字字清新句句奇。',32,'御定全唐詩/json/696.json','["江南才子許渾詩，字字清新句句奇。", "十斛明珠量不盡，惠休虛作碧雲詞。"]'),
('yuding-64','贈禮佛名者','韋莊','唐','御定全唐诗','yuding','','[]','何用辛勤禮佛名，我從無得到真庭。',32,'御定全唐詩/json/696.json','["何用辛勤禮佛名，我從無得到真庭。", "尋思六祖傳心印，可是從來讀藏經。"]'),
('yuding-65','殘花','韋莊','唐','御定全唐诗','yuding','','[]','和煙和露雪離披，金蕊紅須尚滿枝。',32,'御定全唐詩/json/696.json','["和煙和露雪離披，金蕊紅須尚滿枝。", "十日笙歌一宵夢，苧蘿因雨失西施。"]'),
('yuding-0','上元縣','韋莊','唐','御定全唐诗','yuding','','[]','南朝三十六英雄，角逐興亡盡此中。有國有家皆是夢，',40,'御定全唐詩/json/697.json','["南朝三十六英雄，角逐興亡盡此中。有國有家皆是夢，", "止竟霸圖何物在，石麟無主臥秋風。"]'),
('yuding-1','江上逢史館李學士','韋莊','唐','御定全唐诗','yuding','','[]','前年分袂陝城西，醉憑征軒日欲低。去浪指期魚必變，',40,'御定全唐詩/json/697.json','["前年分袂陝城西，醉憑征軒日欲低。去浪指期魚必變，", "誰謂世途陵是谷，燕來還識舊巢泥。"]'),
('yuding-2','金陵圖','韋莊','唐','御定全唐诗','yuding','','[]','誰謂傷心畫不成，畫人心逐世人情。',32,'御定全唐詩/json/697.json','["誰謂傷心畫不成，畫人心逐世人情。", "君看六幅南朝事，老木寒雲滿故城。"]'),
('yuding-3','謁蔣帝廟','韋莊','唐','御定全唐诗','yuding','','[]','建業城邊蔣帝祠，素髯清骨舊風姿。江聲似激秦軍破，',40,'御定全唐詩/json/697.json','["建業城邊蔣帝祠，素髯清骨舊風姿。江聲似激秦軍破，", "金陵客路方流落，空祝回鑾奠酒卮。"]'),
('yuding-4','聞再幸梁洋','韋莊','唐','御定全唐诗','yuding','','[]','才喜中原息戰鼙，又聞天子幸巴西。延燒魏闕非關燕，',40,'御定全唐詩/json/697.json','["才喜中原息戰鼙，又聞天子幸巴西。延燒魏闕非關燕，", "遙思萬里行宮夢，太白山前月欲低。"]'),
('yuding-5','王道者','韋莊','唐','御定全唐诗','yuding','','[]','五雲遙指海中央，金鼎曾傳肘後方。三島路岐空有月，',40,'御定全唐詩/json/697.json','["五雲遙指海中央，金鼎曾傳肘後方。三島路岐空有月，", "應笑我曹身是夢，白頭猶自學詩狂。"]'),
('yuding-6','陪金陵府相中堂夜宴','韋莊','唐','御定全唐诗','yuding','','[]','滿耳笙歌滿眼花，滿樓珠翠勝吳娃。因知海上神仙窟，',40,'御定全唐詩/json/697.json','["滿耳笙歌滿眼花，滿樓珠翠勝吳娃。因知海上神仙窟，", "卻愁宴罷青蛾散，楊子江頭月半斜。"]'),
('yuding-7','和侯秀才同友生泛舟溪中相招之作','韋莊','唐','御定全唐诗','yuding','','[]','嵇阮相將棹酒船，晚風侵浪水侵舷。輕如控鯉初離岸，',40,'御定全唐詩/json/697.json','["嵇阮相將棹酒船，晚風侵浪水侵舷。輕如控鯉初離岸，", "憑君不用回舟疾，今夜西江月正圓。"]'),
('yuding-8','贈野童','韋莊','唐','御定全唐诗','yuding','','[]','羨爾無知野性真，亂搔蓬發笑看人。',32,'御定全唐詩/json/697.json','["羨爾無知野性真，亂搔蓬發笑看人。", "閑沖暮雨騎牛去，肯問中興社稷臣。"]'),
('yuding-9','代書寄馬','韋莊','唐','御定全唐诗','yuding','','[]','驅馳曾在五侯家，見說初生自渥窪。鬃白似披梁苑雪，',40,'御定全唐詩/json/697.json','["驅馳曾在五侯家，見說初生自渥窪。鬃白似披梁苑雪，", "穩上雲衢千萬里，年年長踏魏堤沙。"]'),
('yuding-10','題淮陰侯廟','韋莊','唐','御定全唐诗','yuding','','[]','滿把椒漿奠楚祠，碧幢黃鉞舊英威。能扶漢代成王業，',40,'御定全唐詩/json/697.json','["滿把椒漿奠楚祠，碧幢黃鉞舊英威。能扶漢代成王業，", "如何不借平齊策，空看長星落賊圍。"]'),
('yuding-11','送崔郎中往使西川行在','韋莊','唐','御定全唐诗','yuding','','[]','拜書辭玉帳，萬里劍關長。新馬杏花色，綠袍春草香。',48,'御定全唐詩/json/697.json','["拜書辭玉帳，萬里劍關長。新馬杏花色，綠袍春草香。", "一身朝玉陛，幾日過銅梁。莫戀爐邊醉，仙宮待侍郎。"]'),
('yuding-12','潤州顯濟閣曉望','韋莊','唐','御定全唐诗','yuding','','[]','清曉水如鏡，隔江人似鷗。遠煙藏海島，初日照揚州。',48,'御定全唐詩/json/697.json','["清曉水如鏡，隔江人似鷗。遠煙藏海島，初日照揚州。", "地壯孫權氣，雲凝庾信愁。一篷何處客，吟憑釣魚舟。"]'),
('yuding-13','觀浙西府相畋游','韋莊','唐','御定全唐诗','yuding','','[]','十裏旌旗十萬兵，等閒遊獵出軍城。紫袍日照金鵝鬥，',40,'御定全唐詩/json/697.json','["十裏旌旗十萬兵，等閒遊獵出軍城。紫袍日照金鵝鬥，", "歸來一路笙歌滿，更有仙娥載酒迎。"]'),
('yuding-14','官莊','韋莊','唐','御定全唐诗','yuding','','[]','誰氏園林一簇煙，路人遙指盡長歎。',32,'御定全唐詩/json/697.json','["誰氏園林一簇煙，路人遙指盡長歎。", "桑田稻澤今無主，新犯香醪沒入官。"]'),
('yuding-15','解維','韋莊','唐','御定全唐诗','yuding','','[]','又解征帆落照中，暮程還過秣陵東。',32,'御定全唐詩/json/697.json','["又解征帆落照中，暮程還過秣陵東。", "二年辛苦煙波裏，贏得風姿似釣翁。"]'),
('yuding-16','雨霽池上作呈侯學士','韋莊','唐','御定全唐诗','yuding','','[]','鹿巾藜杖葛衣輕，雨歇池邊晚吹清。',32,'御定全唐詩/json/697.json','["鹿巾藜杖葛衣輕，雨歇池邊晚吹清。", "正是如今江上好，白鱗紅稻紫蓴羹。"]'),
('yuding-17','寓言','韋莊','唐','御定全唐诗','yuding','','[]','為儒逢世亂，吾道欲何之。學劍已應晚，歸山今又遲。',48,'御定全唐詩/json/697.json','["為儒逢世亂，吾道欲何之。學劍已應晚，歸山今又遲。", "故人三載別，明月兩鄉悲。惆悵滄江上，星星鬢有絲。"]'),
('yuding-18','哭同舍崔員外','韋莊','唐','御定全唐诗','yuding','','[]','卻到同遊地，三年一電光。池塘春草在，風燭故人亡。',48,'御定全唐詩/json/697.json','["卻到同遊地，三年一電光。池塘春草在，風燭故人亡。", "祭罷泉聲急，齋餘磬韻長。碧天應有恨，斜日吊松篁。"]'),
('yuding-19','題姑蘇淩處士莊','韋莊','唐','御定全唐诗','yuding','','[]','一簇林亭返照間，門當官道不曾關。花深遠岸黃鶯鬧，',40,'御定全唐詩/json/697.json','["一簇林亭返照間，門當官道不曾關。花深遠岸黃鶯鬧，", "怪來話得仙中事，新有人從物外還。"]'),
('yuding-20','過當塗縣','韋莊','唐','御定全唐诗','yuding','','[]','客過當塗縣，停車訪舊遊。謝公山有墅，李白酒無樓。',48,'御定全唐詩/json/697.json','["客過當塗縣，停車訪舊遊。謝公山有墅，李白酒無樓。", "採石花空發，烏江水自流。夕陽誰共感，寒鷺立汀洲。"]'),
('yuding-21','江亭酒醒卻寄維揚餞客','韋莊','唐','御定全唐诗','yuding','','[]','別筵人散酒初醒，江步黃昏雨雪零。',32,'御定全唐詩/json/697.json','["別筵人散酒初醒，江步黃昏雨雪零。", "滿坐綺羅皆不見，覺來紅樹背銀屏。"]'),
('yuding-22','台城','韋莊','唐','御定全唐诗','yuding','','[]','江雨霏霏江草齊，六朝如夢鳥空啼。',32,'御定全唐詩/json/697.json','["江雨霏霏江草齊，六朝如夢鳥空啼。", "無情最是台城柳，依舊煙籠十裏堤。"]'),
('yuding-23','贈漁翁','韋莊','唐','御定全唐诗','yuding','','[]','草衣荷笠鬢如霜，自說家編楚水陽。滿岸秋風吹枳橘，',40,'御定全唐詩/json/697.json','["草衣荷笠鬢如霜，自說家編楚水陽。滿岸秋風吹枳橘，", "曾向五湖期範蠡，爾來空闊久相忘。"]'),
('yuding-24','過揚州','韋莊','唐','御定全唐诗','yuding','','[]','當年人未識兵戈，處處青樓夜夜歌。花發洞中春日永，',40,'御定全唐詩/json/697.json','["當年人未識兵戈，處處青樓夜夜歌。花發洞中春日永，", "二十四橋空寂寂，綠楊摧折舊官河。"]'),
('yuding-25','寄右省李起居','韋莊','唐','御定全唐诗','yuding','','[]','已向鴛行接雁行，便應雙拜紫薇郎。才聞闕下征書急，',40,'御定全唐詩/json/697.json','["已向鴛行接雁行，便應雙拜紫薇郎。才聞闕下征書急，", "多慚十載游梁客，未換青襟侍素王。"]'),
('yuding-26','鑷白','韋莊','唐','御定全唐诗','yuding','','[]','白髮太無情，朝朝鑷又生。始因絲一縷，漸至雪千莖。',48,'御定全唐詩/json/697.json','["白髮太無情，朝朝鑷又生。始因絲一縷，漸至雪千莖。", "不避佳人笑，唯慚稚子驚。新年過半百，猶歎未休兵。"]'),
('yuding-27','漳亭驛小櫻桃','韋莊','唐','御定全唐诗','yuding','','[]','當年此樹正花開，五馬仙郎載酒來。',32,'御定全唐詩/json/697.json','["當年此樹正花開，五馬仙郎載酒來。", "李白已亡工部死，何人堪伴玉山頹。"]'),
('yuding-28','酬吳秀才霅川相送','韋莊','唐','御定全唐诗','yuding','','[]','一葉南浮去似飛，楚鄉雲水本無依。離心不忍聞春鳥，',40,'御定全唐詩/json/697.json','["一葉南浮去似飛，楚鄉雲水本無依。離心不忍聞春鳥，", "夫君別我應惆悵，十五年來識素衣。"]'),
('yuding-29','對雨獨酌','韋莊','唐','御定全唐诗','yuding','','[]','榴花新釀綠於苔，對雨閑傾滿滿杯。荷鍤醉翁真達者，',40,'御定全唐詩/json/697.json','["榴花新釀綠於苔，對雨閑傾滿滿杯。荷鍤醉翁真達者，", "門外綠蘿連洞口，馬嘶應是步兵來。"]'),
('yuding-30','夏初與侯補闕江南有約同泛淮汴西赴行朝莊…四韻吊之','韋莊','唐','御定全唐诗','yuding','','[]','本約同來謁帝閽，忽隨川浪去東奔。九重聖主方虛席，',40,'御定全唐詩/json/697.json','["本約同來謁帝閽，忽隨川浪去東奔。九重聖主方虛席，", "遙憐月落清淮上，寂寞何人吊旅魂。"]'),
('yuding-31','汴堤行','韋莊','唐','御定全唐诗','yuding','','[]','欲上隋堤舉步遲，隔雲烽燧叫非時。才聞破虜將休馬，',40,'御定全唐詩/json/697.json','["欲上隋堤舉步遲，隔雲烽燧叫非時。才聞破虜將休馬，", "綠楊千里無飛鳥，日落空投舊店基。"]'),
('yuding-32','旅次甬西見兒童以竹槍紙旗戲為陣列…餘因感之','韋莊','唐','御定全唐诗','yuding','','[]','已聞三世沒軍營，又見兒孫學戰爭。',32,'御定全唐詩/json/697.json','["已聞三世沒軍營，又見兒孫學戰爭。", "見爾此言堪慟哭，遣予何日望時平。"]'),
('yuding-33','自孟津舟西上雨中作','韋莊','唐','御定全唐诗','yuding','','[]','秋煙漠漠雨濛濛，不卷征帆任晚風。百口寄安滄海上，',40,'御定全唐詩/json/697.json','["秋煙漠漠雨濛濛，不卷征帆任晚風。百口寄安滄海上，", "卻到故園翻似客，歸心迢遞秣陵東。"]'),
('yuding-34','含山店夢覺作','韋莊','唐','御定全唐诗','yuding','','[]','曾為流離慣別家，等閒揮袂客天涯。',32,'御定全唐詩/json/697.json','["曾為流離慣別家，等閒揮袂客天涯。", "燈前一覺江南夢，惆悵起來山月斜。"]'),
('yuding-35','題貂黃嶺官軍','韋莊','唐','御定全唐诗','yuding','','[]','散騎蕭蕭下太行，遠從吳會去陳倉。',32,'御定全唐詩/json/697.json','["散騎蕭蕭下太行，遠從吳會去陳倉。", "斜風細雨江亭上，盡日憑欄憶楚鄉。"]'),
('yuding-36','過內黃縣','韋莊','唐','御定全唐诗','yuding','','[]','相州吹角欲斜陽，匹馬搖鞭宿內黃。僻縣不容投刺客，',40,'御定全唐詩/json/697.json','["相州吹角欲斜陽，匹馬搖鞭宿內黃。僻縣不容投刺客，", "猶指去程千萬里，秣陵煙樹在何鄉。"]'),
('yuding-37','雜感','韋莊','唐','御定全唐诗','yuding','','[]','莫悲建業荊榛滿，昔日繁華是帝京。莫愛廣陵台榭好，',40,'御定全唐詩/json/697.json','["莫悲建業荊榛滿，昔日繁華是帝京。莫愛廣陵台榭好，", "行客不勞頻悵望，古來朝市歎衰榮。"]'),
('yuding-38','垣縣山中尋李書記山居不遇，留題河次店','韋莊','唐','御定全唐诗','yuding','','[]','白雲紅樹eryy東，名鳥群飛古畫中。',34,'御定全唐詩/json/697.json','["白雲紅樹eryy東，名鳥群飛古畫中。", "仙吏不知何處隱，山南山北雨濛濛。"]'),
('yuding-39','送人遊並汾','韋莊','唐','御定全唐诗','yuding','','[]','風雨蕭蕭欲暮秋，獨攜孤劍塞垣遊。',32,'御定全唐詩/json/697.json','["風雨蕭蕭欲暮秋，獨攜孤劍塞垣遊。", "如今虜騎方南牧，莫過陰關第一州。"]'),
('yuding-40','李氏小池亭十二韻','韋莊','唐','御定全唐诗','yuding','','[]','積石亂巉巉，庭莎綠不芟。小橋低跨水，危檻半依岩。',144,'御定全唐詩/json/697.json','["積石亂巉巉，庭莎綠不芟。小橋低跨水，危檻半依岩。", "花落魚爭唼，櫻紅鳥競鵮。引泉疏地脈，掃絮積山嵌。", "古柳紅綃織，新篁紫綺緘。養猿秋嘯月，放鶴夜棲杉。", "枕簟溪雲膩，池塘海雨鹹。語窗雞逞辨，舐鼎犬偏饞。", "踏蘚青黏屐，攀蘿綠映衫。訪僧舟北渡，貰酒日西銜。", "遲客登高閣，題詩繞翠岩。家藏何所寶，清韻滿琅函。"]'),
('yuding-41','遣興','韋莊','唐','御定全唐诗','yuding','','[]','如幻如泡世，多愁多病身。亂來知酒聖，貧去覺錢神。',48,'御定全唐詩/json/697.json','["如幻如泡世，多愁多病身。亂來知酒聖，貧去覺錢神。", "異國清明節，空江寂寞春。聲聲林上鳥，喚我北歸秦。"]'),
('yuding-42','婺州和陸諫議將赴闕懷陽羨山居','韋莊','唐','御定全唐诗','yuding','','[]','望闕路仍遠，子牟魂欲飛。道開燒藥鼎，僧寄臥雲衣。',48,'御定全唐詩/json/697.json','["望闕路仍遠，子牟魂欲飛。道開燒藥鼎，僧寄臥雲衣。", "故國饒芳草，他山掛夕暉。東陽雖勝地，王粲奈思歸。"]'),
('yuding-43','江上題所居','韋莊','唐','御定全唐诗','yuding','','[]','故人相別盡朝天，苦竹江頭獨閉關。落日亂蟬蕭帝寺，',40,'御定全唐詩/json/697.json','["故人相別盡朝天，苦竹江頭獨閉關。落日亂蟬蕭帝寺，", "不是對花長酩酊，永嘉時代不如閑。"]'),
('yuding-44','婺州屏居蒙右省王拾遺車枉降訪病中延候不得因成寄謝','韋莊','唐','御定全唐诗','yuding','','[]','三年流落臥漳濱，王粲思家拭淚頻。畫角莫吹殘月夜，',40,'御定全唐詩/json/697.json','["三年流落臥漳濱，王粲思家拭淚頻。畫角莫吹殘月夜，", "怪得白鷗驚去盡，綠蘿門外有朱輪。"]'),
('yuding-45','將卜蘭芷村居留別郡中在仕','韋莊','唐','御定全唐诗','yuding','','[]','蘭芷江頭寄斷蓬，移家空載一帆風。伯倫嗜酒還因亂，',40,'御定全唐詩/json/697.json','["蘭芷江頭寄斷蓬，移家空載一帆風。伯倫嗜酒還因亂，", "從今隱去應難覓，深入蘆花作釣翁。"]'),
('yuding-46','和陸諫議避地寄東陽進退未決見寄','韋莊','唐','御定全唐诗','yuding','','[]','未歸天路紫雲深，暫駐東陽歲月侵。入洛聲華當世重，',40,'御定全唐詩/json/697.json','["未歸天路紫雲深，暫駐東陽歲月侵。入洛聲華當世重，", "讀易草玄人不會，憂君心是致君心。"]'),
('yuding-47','山墅閑題','韋莊','唐','御定全唐诗','yuding','','[]','邐迤前岡厭後岡，一川桑柘好殘陽。主人饋餉炊紅黍，',40,'御定全唐詩/json/697.json','["邐迤前岡厭後岡，一川桑柘好殘陽。主人饋餉炊紅黍，", "有名不那無名客，獨閉衡門避建康。"]'),
('yuding-48','江上逢故人','韋莊','唐','御定全唐诗','yuding','','[]','前年送我曲江西，紅杏園中醉似泥。今日逢君越溪上，',40,'御定全唐詩/json/697.json','["前年送我曲江西，紅杏園中醉似泥。今日逢君越溪上，", "江畔玉樓多美酒，仲宣懷土莫淒淒。"]'),
('yuding-49','旅中感遇寄呈李秘書昆仲','韋莊','唐','御定全唐诗','yuding','','[]','南望愁雲鎖翠微，謝家樓閣雨霏霏。劉楨病後新詩少，',40,'御定全唐詩/json/697.json','["南望愁雲鎖翠微，謝家樓閣雨霏霏。劉楨病後新詩少，", "懷鄉不怕嚴陵笑，只待秋風別釣磯。"]'),
('yuding-50','送範評事入關','韋莊','唐','御定全唐诗','yuding','','[]','寂寥門戶寡相親，日日頻來只有君。正喜琴尊長作伴，',40,'御定全唐詩/json/697.json','["寂寥門戶寡相親，日日頻來只有君。正喜琴尊長作伴，", "為報明年杏園客，與留絕豔待終軍。"]'),
('yuding-51','東陽酒家贈別二絕句','韋莊','唐','御定全唐诗','yuding','','[]','送君同上酒家樓，酩酊翻成一笑休。',64,'御定全唐詩/json/697.json','["送君同上酒家樓，酩酊翻成一笑休。", "正是落花饒悵望，醉鄉前路莫回頭。", "天涯方歎異鄉身，又向天涯別故人。", "明日五更孤店月，醉醒何處淚沾巾。"]'),
('yuding-52','江上村居','韋莊','唐','御定全唐诗','yuding','','[]','本無蹤跡戀柴扃，世亂須教識道情。顛倒夢魂愁裏得，',40,'御定全唐詩/json/697.json','["本無蹤跡戀柴扃，世亂須教識道情。顛倒夢魂愁裏得，", "聞道漢軍新破虜，使來仍說近離京。"]'),
('yuding-53','江外思鄉','韋莊','唐','御定全唐诗','yuding','','[]','年年春日異鄉悲，杜曲黃鶯可得知。',32,'御定全唐詩/json/697.json','["年年春日異鄉悲，杜曲黃鶯可得知。", "更被夕陽江岸上，斷腸煙柳一絲絲。"]'),
('yuding-54','和鄭拾遺秋日感事一百韻','韋莊','唐','御定全唐诗','yuding','','[]','禍亂天心厭，流離客思傷。有家拋上國，無罪謫遐方。',577,'御定全唐詩/json/697.json','["禍亂天心厭，流離客思傷。有家拋上國，無罪謫遐方。", "負笈將辭越，揚帆欲泛湘。避時難駐足，感事易回腸。", "雅道何銷德，妖星忽耀芒。中原初縱燎，下國竟探湯。", "盜據三秦地，兵纏八水鄉。戰塵輕犯闕，羽旆遠巡梁。", "自此修文代，俄成講武場。熊羆驅涿鹿，犀象走昆陽。", "禦馬迷新棧，宮娥改舊妝。五丁功再睹，八難事難忘。", "鳳引金根疾，兵環玉弩強。建牙雖可恃，摩壘詎能防。", "霍廟神遐遠，圯橋路杳茫。出師威似虎，禦敵狠如羊。", "眉畫猶思赤，巾裁未厭黃。晨趨鳴鐵騎，夜舞挹瓊觴。", "僭侈彤襜亂，喧呼繡cK攘。但聞爭曳組，詎見學垂韁。", "鵲印提新篆，龍泉奪曉霜。軍威徒逗撓，我武自維揚。", "負扆勞天眷，凝旒念國章。繡旗張畫獸，寶馬躍紅鴦。", "但欲除妖氣，甯思蔽耿光。曉煙生帝裏，夜火入春坊。", "鳥怪巢宮樹，狐驕上苑牆。設危終在德，視履豈無祥。", "氣激雷霆怒，神驅嶽瀆忙。功高分虎節，位下恥龍驤。", "遍命登壇將，巡封異姓王。志求扶墜典，力未振頹綱。", "漢路閑雕鶚，雲衢駐驌驦。寶裝軍器麗，麝裛戰袍香。", "日睹兵書捷，時聞虜騎亡。人心驚獬豸，雀意伺螳螂。", "上略咸推妙，前鋒詎可當。紆金光照耀，執玉意藏昂。", "覆餗非無謂，奢華事每詳。四民皆組綬，九土墮耕桑。", "飛騎黃金勒，香車翠鈿裝。八珍羅膳府，五采鬥筐床。", "宴集喧華第，歌鐘簇畫梁。永期傳子姓，寧誤犯天狼。", "未睹君除側，徒思玉在傍。竄身奚可保，易地喜相將。", "國運方夷險，天心詎測量。九流雖暫蔽，三柄豈相妨。"]'),
('yuding-55','夢入關','韋莊','唐','御定全唐诗','yuding','','[]','夢中乘傳過關亭，南望蓮峰簇簇青。',32,'御定全唐詩/json/697.json','["夢中乘傳過關亭，南望蓮峰簇簇青。", "馬上正吟歸去好，覺來江月滿前庭。"]'),
('yuding-56','送人歸上國','韋莊','唐','御定全唐诗','yuding','','[]','送君江上日西斜，泣向江邊滿樹花。',32,'御定全唐詩/json/697.json','["送君江上日西斜，泣向江邊滿樹花。", "若見青雲舊相識，為言流落在天涯。"]'),
('yuding-57','聞春鳥','韋莊','唐','御定全唐诗','yuding','','[]','雲晴春鳥滿江村，還似長安舊日聞。',32,'御定全唐詩/json/697.json','["雲晴春鳥滿江村，還似長安舊日聞。", "紅杏花前應笑我，我今憔悴亦羞君。"]'),
('yuding-58','櫻桃樹','韋莊','唐','御定全唐诗','yuding','','[]','記得初生雪滿枝，和蜂和蝶帶花移。',32,'御定全唐詩/json/697.json','["記得初生雪滿枝，和蜂和蝶帶花移。", "而今花落遊蜂去，空作主人惆悵詩。"]'),
('yuding-59','獨鶴','韋莊','唐','御定全唐诗','yuding','','[]','夕陽灘上立裴回，紅蓼風前雪翅開。',32,'御定全唐詩/json/697.json','["夕陽灘上立裴回，紅蓼風前雪翅開。", "應為不知棲宿處，幾回飛去又飛來。"]'),
('yuding-60','新栽竹','韋莊','唐','御定全唐诗','yuding','','[]','寂寞階前見此君，繞欄吟罷卻沾巾。',32,'御定全唐詩/json/697.json','["寂寞階前見此君，繞欄吟罷卻沾巾。", "異鄉流落誰相識，唯有叢篁似主人。"]'),
('yuding-61','稻田','韋莊','唐','御定全唐诗','yuding','','[]','綠波春浪滿前陂，極目連雲罷亞肥。',32,'御定全唐詩/json/697.json','["綠波春浪滿前陂，極目連雲罷亞肥。", "更被鷺鶿千點雪，破煙來入畫屏飛。"]'),
('yuding-62','庭前菊','韋莊','唐','御定全唐诗','yuding','','[]','為憶長安爛熳開，我今移爾滿庭栽。',32,'御定全唐詩/json/697.json','["為憶長安爛熳開，我今移爾滿庭栽。", "紅蘭莫笑青青色，曾向龍山泛酒來。"]'),
('yuding-63','燕來','韋莊','唐','御定全唐诗','yuding','','[]','去歲辭巢別近鄰，今來空訝草堂新。',32,'御定全唐詩/json/697.json','["去歲辭巢別近鄰，今來空訝草堂新。", "花開對語應相問，不是村中舊主人。"]'),
('yuding-64','倚柴關','韋莊','唐','御定全唐诗','yuding','','[]','杖策無言獨倚關，如癡如醉又如閑。',32,'御定全唐詩/json/697.json','["杖策無言獨倚關，如癡如醉又如閑。", "孤吟盡日何人會，依約前山似故山。"]'),
('yuding-65','題七步廊','韋莊','唐','御定全唐诗','yuding','','[]','席門無計那殘陽，更接簷前七步廊。',32,'御定全唐詩/json/697.json','["席門無計那殘陽，更接簷前七步廊。", "不羨東都丞相宅，每行吟得好篇章。"]'),
('yuding-66','語松竹','韋莊','唐','御定全唐诗','yuding','','[]','庭前芳草綠於袍，堂上詩人欲二毛。',32,'御定全唐詩/json/697.json','["庭前芳草綠於袍，堂上詩人欲二毛。", "多病不禁秋寂寞，雨松風竹莫騷騷。"]'),
('yuding-0','不出院楚公','韋莊','唐','御定全唐诗','yuding','','[]','一自禪關閉，心猿日漸馴。不知城郭路，稀識市朝人。',48,'御定全唐詩/json/698.json','["一自禪關閉，心猿日漸馴。不知城郭路，稀識市朝人。", "履帶階前雪，衣無寺外塵。卻嫌山翠好，詩客往來頻。"]'),
('yuding-1','江邊吟','韋莊','唐','御定全唐诗','yuding','','[]','江邊烽燧幾時休，江上行人雪滿頭。誰信亂離花不見，',40,'御定全唐詩/json/698.json','["江邊烽燧幾時休，江上行人雪滿頭。誰信亂離花不見，", "若有片帆歸去好，可堪重倚仲宣樓。"]'),
('yuding-2','江南送李明府入關','韋莊','唐','御定全唐诗','yuding','','[]','雨花煙柳傍江村，流落天涯酒一樽。分首不辭多下淚，',40,'御定全唐詩/json/698.json','["雨花煙柳傍江村，流落天涯酒一樽。分首不辭多下淚，", "正是中興磐石重，莫將憔悴入都門。"]'),
('yuding-3','送福州王先輩南歸','韋莊','唐','御定全唐诗','yuding','','[]','豫章城下偶相逢，自說今方遇至公。八韻賦吟梁苑雪，',40,'御定全唐詩/json/698.json','["豫章城下偶相逢，自說今方遇至公。八韻賦吟梁苑雪，", "明日一杯何處別，綠楊煙岸雨濛濛。"]'),
('yuding-4','夜雪泛舟游南溪','韋莊','唐','御定全唐诗','yuding','','[]','大江西面小溪斜，入竹穿松似若耶。兩岸嚴風吹玉樹，',40,'御定全唐詩/json/698.json','["大江西面小溪斜，入竹穿松似若耶。兩岸嚴風吹玉樹，", "去去不知歸路遠，棹聲煙裏獨嘔啞。"]'),
('yuding-5','江行西望','韋莊','唐','御定全唐诗','yuding','','[]','西望長安白日遙，半年無事駐蘭橈。',32,'御定全唐詩/json/698.json','["西望長安白日遙，半年無事駐蘭橈。", "欲將張翰秋江雨，畫作屏風寄鮑昭。"]'),
('yuding-6','銅儀','韋莊','唐','御定全唐诗','yuding','','[]','銅儀一夜變葭灰，暖律還吹嶺上梅。已喜漢官今再睹，',40,'御定全唐詩/json/698.json','["銅儀一夜變葭灰，暖律還吹嶺上梅。已喜漢官今再睹，", "誰念閉關張仲蔚，滿庭春雨長蒿萊。"]'),
('yuding-7','含香','韋莊','唐','御定全唐诗','yuding','','[]','含香高步已難陪，鶴到清霄勢未回。遇物旋添芳草句，',40,'御定全唐詩/json/698.json','["含香高步已難陪，鶴到清霄勢未回。遇物旋添芳草句，", "卻去金鑾為近侍，便辭鷗鳥不歸來。"]'),
('yuding-8','春雲','韋莊','唐','御定全唐诗','yuding','','[]','春雲春水兩溶溶，倚郭樓臺晚翠濃。山好只因人化石，',40,'御定全唐詩/json/698.json','["春雲春水兩溶溶，倚郭樓臺晚翠濃。山好只因人化石，", "王粲不知多少恨，夕陽吟斷一聲鐘。"]'),
('yuding-9','雲散','韋莊','唐','御定全唐诗','yuding','','[]','雲散天邊落照和，關關春樹鳥聲多。劉伶避世唯沈醉，',40,'御定全唐詩/json/698.json','["雲散天邊落照和，關關春樹鳥聲多。劉伶避世唯沈醉，", "青雲自有鵷鴻待，莫說他山好薜蘿。"]'),
('yuding-10','袁州作','韋莊','唐','御定全唐诗','yuding','','[]','家家生計只琴書，一郡清風似魯儒。山色東南連紫府，',40,'御定全唐詩/json/698.json','["家家生計只琴書，一郡清風似魯儒。山色東南連紫府，", "正是江村春酒熟，更聞春鳥勸提壺。"]'),
('yuding-11','題袁州謝秀才所居','韋莊','唐','御定全唐诗','yuding','','[]','主人年少已能詩，更有松軒掛夕暉。芳草似袍連徑合，',40,'御定全唐詩/json/698.json','["主人年少已能詩，更有松軒掛夕暉。芳草似袍連徑合，", "若有前山好煙雨，與君吟到暝鐘歸。"]'),
('yuding-12','謁巫山廟','韋莊','唐','御定全唐诗','yuding','','[]','亂猿啼處訪高唐，路入煙霞草木香。山色未能忘宋玉，',40,'御定全唐詩/json/698.json','["亂猿啼處訪高唐，路入煙霞草木香。山色未能忘宋玉，", "惆悵廟前無限柳，春來空鬥畫眉長。"]'),
('yuding-13','鷓鴣','韋莊','唐','御定全唐诗','yuding','','[]','南禽無侶似相依，錦翅雙雙傍馬飛。孤竹廟前啼暮雨，',40,'御定全唐詩/json/698.json','["南禽無侶似相依，錦翅雙雙傍馬飛。孤竹廟前啼暮雨，", "懊惱澤家非有恨，年年長憶鳳城歸。"]'),
('yuding-14','宿蓬船','韋莊','唐','御定全唐诗','yuding','','[]','夜來江雨宿蓬船，臥聽淋鈴不忍眠。',32,'御定全唐詩/json/698.json','["夜來江雨宿蓬船，臥聽淋鈴不忍眠。", "卻憶紫微情調逸，阻風中酒過年年。"]'),
('yuding-15','送李秀才歸荊溪','韋莊','唐','御定全唐诗','yuding','','[]','八月中秋月正圓，送君吟上木蘭船。人言格調勝玄度，',40,'御定全唐詩/json/698.json','["八月中秋月正圓，送君吟上木蘭船。人言格調勝玄度，", "楚王宮去陽臺近，莫倚風流滯少年。"]'),
('yuding-16','洪州送西明寺省上人游福建','韋莊','唐','御定全唐诗','yuding','','[]','記得初騎竹馬年，送師來往禦溝邊。荊榛已失當時路，',40,'御定全唐詩/json/698.json','["記得初騎竹馬年，送師來往禦溝邊。荊榛已失當時路，", "新春闕下應相見，紅杏花中覓酒仙。"]'),
('yuding-17','建昌渡暝吟','韋莊','唐','御定全唐诗','yuding','','[]','月照臨官渡，鄉情獨浩然。鳥棲彭蠡樹，月上建昌船。',48,'御定全唐詩/json/698.json','["月照臨官渡，鄉情獨浩然。鳥棲彭蠡樹，月上建昌船。", "市散漁翁醉，樓深賈客眠。隔江何處笛，吹斷綠楊煙。"]'),
('yuding-18','歲除對王秀才作','韋莊','唐','御定全唐诗','yuding','','[]','我惜今宵促，君愁玉漏頻。豈知新歲酒，猶作異鄉身。',48,'御定全唐詩/json/698.json','["我惜今宵促，君愁玉漏頻。豈知新歲酒，猶作異鄉身。", "雪向寅前凍，花從子後春。到明追此會，俱是來年人。"]'),
('yuding-19','酒渴愛江清','韋莊','唐','御定全唐诗','yuding','','[]','酒渴何方療，江波一掬清。瀉甌如練色，漱齒作泉聲。',48,'御定全唐詩/json/698.json','["酒渴何方療，江波一掬清。瀉甌如練色，漱齒作泉聲。", "味帶他山雪，光含白露精。只應千古後，長稱伯倫情。"]'),
('yuding-20','和李秀才郊墅早春吟興十韻','韋莊','唐','御定全唐诗','yuding','','[]','暖律變寒光，東君景漸長。我悲遊海嶠，君說住柴桑。',120,'御定全唐詩/json/698.json','["暖律變寒光，東君景漸長。我悲遊海嶠，君說住柴桑。", "雪色隨高嶽，冰聲陷古塘。草根微吐翠，梅朵半含霜。", "酒市多逋客，漁家足夜航。匡廬雲傍屋，彭蠡浪衝床。", "綠擺楊枝嫩，紅挑菜甲香。鳳凰城已盡，鸚鵡賦應狂。", "佇見龍辭沼，寧憂雁失行。不應雙劍氣，長在鬥牛傍。"]'),
('yuding-21','泛鄱陽湖','韋莊','唐','御定全唐诗','yuding','','[]','四顧無邊鳥不飛，大波驚隔楚山微。紛紛雨外靈均過，',40,'御定全唐詩/json/698.json','["四顧無邊鳥不飛，大波驚隔楚山微。紛紛雨外靈均過，", "鴟夷去後何人到，愛者雖多見者稀。"]'),
('yuding-22','黃藤山下聞猿','韋莊','唐','御定全唐诗','yuding','','[]','黃藤山下駐歸程，一夜號猿吊旅情。入耳便能生百恨，',40,'御定全唐詩/json/698.json','["黃藤山下駐歸程，一夜號猿吊旅情。入耳便能生百恨，", "好笑五陵年少客，壯心無事也沾纓。"]'),
('yuding-23','章江作','韋莊','唐','御定全唐诗','yuding','','[]','杜陵歸客正裴回，玉笛誰家叫落梅。之子棹從天外去，',40,'御定全唐詩/json/698.json','["杜陵歸客正裴回，玉笛誰家叫落梅。之子棹從天外去，", "欲問維揚舊風月，一江紅樹亂猿哀。"]'),
('yuding-24','南游富陽江中作','韋莊','唐','御定全唐诗','yuding','','[]','南去又南去，此行非自期。一帆雲作伴，千里月相隨。',48,'御定全唐詩/json/698.json','["南去又南去，此行非自期。一帆雲作伴，千里月相隨。", "浪跡花應笑，衰容鏡每知。鄉園不可問，禾黍正離離。"]');
